export type TipoMensagem = "versiculo" | "salmo" | "reflexao";

export interface Mensagem {
  id: string;
  texto: string;
  referencia: string;
  tipo: TipoMensagem;
  fraseMotivacional?: string;
  resumo?: string;
}

export const CATEGORIAS = [
  "Motivação",
  "Feliz",
  "Ansioso",
  "Triste",
  "Sozinho",
  "Agradecido",
  "Nervoso",
  "Preciso de esperança",
  "Preciso de paz",
  "Preciso de força",
] as const;

export type Categoria = typeof CATEGORIAS[number];

export const MENSAGENS: Record<Categoria, Mensagem[]> = {
  "Feliz": [
    { id: "fel1", tipo: "versiculo", texto: "Alegrem-se sempre no Senhor. Novamente direi: alegrem-se!", referencia: "Filipenses 4:4", resumo: "Paulo escreve da prisão romana e mesmo assim ordena alegria — duas vezes. A alegria cristã não depende de circunstâncias, é uma decisão ancorada na fidelidade de Deus. Ela coexiste com a dor, oferecendo força interior que o mundo não consegue explicar." },
    { id: "fel2", tipo: "salmo", texto: "Este é o dia que o Senhor fez; regozijemo-nos e alegremo-nos nele.", referencia: "Salmos 118:24", resumo: "Cada amanhecer é obra das mãos de Deus, não acaso. Declarar isso é afirmar que Ele governa o tempo e que cada 24 horas vem com propósito. A gratidão pela manhã abre a porta para a alegria genuína do dia." },
    { id: "fel3", tipo: "versiculo", texto: "O coração alegre aformoseia o rosto.", referencia: "Provérbios 15:13", resumo: "A verdadeira beleza não vem de cosméticos, mas de uma alma que encontrou descanso em Deus. Um coração alegre irradia leveza, brilho nos olhos e expressão acolhedora. Cultivar alegria espiritual não é vaidade — é mordomia da luz que recebemos." },
    { id: "fel4", tipo: "salmo", texto: "Tu me farás conhecer a vereda da vida, a alegria plena da tua presença.", referencia: "Salmos 16:11", resumo: "Davi descobre que a satisfação real não está em prazeres terrenos, mas em conhecer Deus pessoalmente. 'Alegria plena' é uma felicidade que preenche cada canto da existência — sólida, crescente e definitiva." },
    { id: "fel5", tipo: "versiculo", texto: "A alegria do Senhor é a vossa força.", referencia: "Neemias 8:10", resumo: "Após o exílio, o povo chorava ao ouvir a Lei. Neemias os interrompe com uma verdade libertadora: a alegria de Deus é combustível espiritual. Focar em quem Ele é, não nas nossas falhas, traz vigor para reconstruir." },
    { id: "fel6", tipo: "salmo", texto: "Pois tu, Senhor, me alegraste pelos teus feitos; exultarei nas obras das tuas mãos.", referencia: "Salmos 92:4", resumo: "Quanto mais observamos o que Deus fez, mais motivos encontramos para celebrar. Esse exercício combate a ansiedade, que se alimenta de focar no que falta. Adoração baseada em fatos permanece firme até em dias difíceis." },
    { id: "fel7", tipo: "versiculo", texto: "Alegrai-vos na esperança, sede pacientes na tribulação, perseverai na oração.", referencia: "Romanos 12:12", resumo: "Paulo oferece um tripé para a vida cristã: alegria ancorada na esperança futura, paciência na dor presente, perseverança na oração que sustenta tudo. Juntos, esses três pilares resistem ao desânimo." },
    { id: "fel8", tipo: "salmo", texto: "Servi ao Senhor com alegria; apresentai-vos a ele com cântico.", referencia: "Salmos 100:2", resumo: "O serviço a Deus não deve ser pesado ou movido por medo, mas marcado pela alegria de quem entende a quem serve. Quando servimos por amor e gratidão, a tarefa se torna privilégio." },
    { id: "fel9", tipo: "versiculo", texto: "Até agora nada pedistes em meu nome; pedi, e recebereis, para que a vossa alegria seja completa.", referencia: "João 16:24", resumo: "Jesus revela que Deus deseja se relacionar de forma íntima com Seus filhos, recebendo pedidos e respondendo de maneira que a alegria transborde. Uma vida de oração ativa cultiva essa plenitude inabalável." },
    { id: "fel10", tipo: "reflexao", texto: "A alegria do justo é como a luz da aurora, que vai brilhando mais e mais até o dia perfeito.", referencia: "Provérbios 4:18", resumo: "A alegria genuína começa discreta e amadurece com o tempo de comunhão. Não é euforia momentânea, mas claridade interior que se expande à medida que caminhamos com Deus." },
    { id: "fel11", tipo: "versiculo", texto: "Os redimidos do Senhor voltarão; cantando, virão a Sião com alegria eterna sobre a cabeça.", referencia: "Isaías 35:10", resumo: "A alegria eterna é uma marca visível, como uma coroa que repousa sobre quem caminha com o Senhor. Ela transforma a jornada de volta em festa, mostrando que o cuidado divino sempre tem o último ato." },
    { id: "fel12", tipo: "salmo", texto: "Em ti se alegrarão todos os que confiam em ti; exultarão para sempre, porque tu os defendes.", referencia: "Salmos 5:11", resumo: "A defesa divina dá segurança suficiente para o coração celebrar mesmo em meio a ameaças reais. Não é ignorância dos problemas, é certeza do Defensor." },
    { id: "fel13", tipo: "versiculo", texto: "Estas coisas vos tenho dito para que a minha alegria esteja em vós, e a vossa alegria seja completa.", referencia: "João 15:11", resumo: "Jesus quer transferir Sua própria alegria ao discípulo. Quanto mais permanecemos Nele como ramo na videira, mais essa alegria preenche os espaços vazios da alma." },
    { id: "fel14", tipo: "salmo", texto: "Alegrai-vos no Senhor, ó justos; aos retos fica bem o louvor.", referencia: "Salmos 33:1", resumo: "O louvor é a resposta natural de quem reconhece a justiça e bondade de Deus. Cantar fortalece a alma e nos lembra que a alegria é um traje que cai bem em quem caminha com integridade." },
    { id: "fel15", tipo: "salmo", texto: "Os justos se alegrem, exultem na presença de Deus e folguem de alegria.", referencia: "Salmos 68:3", resumo: "A presença de Deus é um lugar de festa para quem vive em comunhão com Ele. A alegria espiritual não exige motivos externos — basta lembrar onde estamos espiritualmente." },
    { id: "fel16", tipo: "versiculo", texto: "Alegrai-vos nesse dia e exultai, porque o vosso galardão é grande nos céus.", referencia: "Lucas 6:23", resumo: "Jesus ensina a sustentar alegria mesmo sob perseguição, porque o foco está na recompensa eterna. Essa perspectiva muda a forma como recebemos cada dia." },
    { id: "fel17", tipo: "salmo", texto: "Render-te-ei graças, Senhor, de todo o meu coração; alegrar-me-ei e exultarei em ti.", referencia: "Salmos 9:1-2", resumo: "Davi escolhe agradecer com tudo o que há nele. A alegria cresce quando a gratidão se torna prática diária, não exceção. Lembrar dos atos de Deus alimenta a celebração." },
    { id: "fel18", tipo: "salmo", texto: "Bem-aventurado o povo que conhece os sons festivos; andará, ó Senhor, na luz da tua face.", referencia: "Salmos 89:15-16", resumo: "Conhecer os 'sons festivos' é viver familiarizado com a presença de Deus. Quem caminha nessa luz se alegra no nome dEle o dia inteiro, sem precisar de motivos externos." },
    { id: "fel19", tipo: "salmo", texto: "Semeia-se a luz para o justo, e a alegria, para o reto de coração.", referencia: "Salmos 97:11-12", resumo: "A alegria é semeada na vida do justo — nem sempre brota no dia, mas cresce com fidelidade. Andar reto é cuidar do solo onde Deus planta luz." },
    { id: "fel20", tipo: "versiculo", texto: "Tende por motivo de toda alegria o passardes por várias provações.", referencia: "Tiago 1:2", resumo: "Tiago propõe uma alegria contraintuitiva: enxergar provações como oportunidade de amadurecimento. Não é alegrar-se pela dor, mas pelo que Deus formará através dela." },
    { id: "fel21", tipo: "reflexao", texto: "O coração alegre é bom remédio, mas o espírito abatido faz secar os ossos.", referencia: "Provérbios 17:22", resumo: "A Bíblia reconhece a conexão entre alma e corpo. Cuidar do coração com alegria espiritual é também cuidar da saúde. Buscar a fonte certa de alegria é prevenção." },
    { id: "fel22", tipo: "salmo", texto: "Alegrai-vos no Senhor e regozijai-vos, ó justos; exultai, vós todos que sois retos de coração.", referencia: "Salmos 32:11", resumo: "Após confessar o pecado e receber perdão, Davi convida a uma alegria explosiva. O perdão é fonte permanente de júbilo — quem foi perdoado tem motivo diário para celebrar." },
    { id: "fel23", tipo: "versiculo", texto: "Vós, com alegria, tirareis água das fontes da salvação.", referencia: "Isaías 12:3", resumo: "A salvação é uma fonte de onde se tira água com alegria. Cada vez que lembramos quem nos salvou e do que fomos livres, a alegria volta a jorrar." },
    { id: "fel24", tipo: "salmo", texto: "Os preceitos do Senhor são retos e alegram o coração.", referencia: "Salmos 19:8", resumo: "Obedecer à Palavra não é peso, é alegria. Os mandamentos de Deus protegem e direcionam, e essa proteção produz leveza interior em vez de opressão." },
    { id: "fel25", tipo: "salmo", texto: "Bem-aventurado o povo que assim lhe sucede! Bem-aventurado o povo cujo Deus é o Senhor!", referencia: "Salmos 144:15", resumo: "A maior felicidade é pertencer a Deus. Antes de qualquer bênção material, a bem-aventurança vem do relacionamento. Saber a quem pertencemos resolve a busca por sentido." },
    { id: "fel26", tipo: "versiculo", texto: "Sem o terdes visto, o amais; e, sem agora o verdes, mas crendo, exultais com alegria indizível.", referencia: "1 Pedro 1:8", resumo: "Pedro descreve uma alegria que não depende de ver. É uma alegria de fé, indizível e cheia de glória, que surge no encontro espiritual com Cristo, mesmo invisível aos olhos." },
    { id: "fel27", tipo: "salmo", texto: "Pois lhe dás contínuas bênçãos; alegra-lo com o gozo da tua presença.", referencia: "Salmos 21:6", resumo: "A presença de Deus é fonte contínua de gozo. Buscar essa presença diariamente alimenta uma alegria que não depende de circunstâncias." },
    { id: "fel28", tipo: "salmo", texto: "Grandes coisas fez o Senhor por nós, e por isso estamos alegres.", referencia: "Salmos 126:3", resumo: "A alegria nasce da memória ativa do que Deus já fez. Listar conscientemente os atos da fidelidade divina renova a celebração no presente." },
    { id: "fel29", tipo: "versiculo", texto: "Eu, porém, me alegro no Senhor, exulto no Deus da minha salvação.", referencia: "Habacuque 3:18", resumo: "Habacuque declara essa alegria mesmo prevendo escassez total. A alegria que sobrevive à perda não está nos bens, está no Senhor. É o tipo mais profundo de júbilo." },
    { id: "fel30", tipo: "salmo", texto: "Puseste no meu coração mais alegria do que a alegria deles quando lhes há fartura de pão e de vinho.", referencia: "Salmos 4:7", resumo: "A alegria de Deus supera qualquer abundância material. Quem prova esse gozo interior descobre que nenhuma colheita terrena chega perto. É um descanso da alma que nenhuma posse oferece." },
    { id: "fel31", tipo: "versiculo", texto: "Alegrai-vos sempre.", referencia: "1 Tessalonicenses 5:16", resumo: "Ordem simples e revolucionária: alegria constante como estilo de vida cristão, independente do humor do dia." },
    { id: "fel32", tipo: "salmo", texto: "O Senhor é a minha porção; feliz é o povo cuja vida assim transcorre.", referencia: "Salmos 144:15", resumo: "Ter Deus como herança é a maior riqueza. Felicidade profunda vem de pertencer a Ele." },
    { id: "fel33", tipo: "versiculo", texto: "Alegre-se o coração dos que buscam o Senhor.", referencia: "1 Crônicas 16:10", resumo: "Buscar a Deus produz alegria no processo, não só no resultado. O caminho já é celebração." },
    { id: "fel34", tipo: "salmo", texto: "Feliz é o homem que teme ao Senhor e se compraz nos seus mandamentos.", referencia: "Salmos 112:1", resumo: "Reverência e obediência não roubam alegria — são o solo onde ela cresce sem medo." },
    { id: "fel35", tipo: "reflexao", texto: "O justo se alegra no Senhor e nele confia; e todos os retos de coração se gloriam.", referencia: "Salmos 64:10", resumo: "Confiar em Deus produz alegria que não depende de circunstâncias externas." },
    { id: "fel36", tipo: "versiculo", texto: "Regozijai-vos na esperança.", referencia: "Romanos 12:12", resumo: "A alegria cristã olha para frente. Esperança futura ilumina o presente por mais duro que seja." },
    { id: "fel37", tipo: "salmo", texto: "A luz do teu rosto, Senhor, faz brilhar sobre nós.", referencia: "Salmos 4:6", resumo: "Quando Deus vira o rosto para nós, tudo muda. A luz Dele reacende a alma cansada." },
    { id: "fel38", tipo: "versiculo", texto: "Deus é o nosso refúgio e fortaleza, socorro bem presente na angústia. Por isso não temeremos.", referencia: "Salmos 46:1-2", resumo: "A alegria coexiste com dificuldade porque descansa em quem não muda: Deus." },
    { id: "fel39", tipo: "salmo", texto: "Bendize, ó minha alma, ao Senhor, e não te esqueças de nenhum dos seus benefícios.", referencia: "Salmos 103:2", resumo: "Lembrar ativamente do que Deus fez desperta alegria genuína no coração." },
    { id: "fel40", tipo: "versiculo", texto: "O reino de Deus é justiça, paz e alegria no Espírito Santo.", referencia: "Romanos 14:17", resumo: "Alegria não é acessório — é essência do reino. Onde Deus reina, alegria brota." },
    { id: "fel41", tipo: "salmo", texto: "Louvai ao Senhor, porque é bom cantar louvores ao nosso Deus.", referencia: "Salmos 147:1", resumo: "Louvor é resposta natural de quem viu bondade divina. E louvor reacende a alegria." },
    { id: "fel42", tipo: "versiculo", texto: "Todo bom dom e todo dom perfeito vem do alto.", referencia: "Tiago 1:17", resumo: "Cada motivo de alegria vem de Deus. Reconhecer isso multiplica a gratidão e o júbilo." },
    { id: "fel43", tipo: "salmo", texto: "Os que semeiam em lágrimas com júbilo ceifarão.", referencia: "Salmos 126:5", resumo: "A alegria vem depois da fidelidade no choro. Deus honra quem persevera no vale." },
    { id: "fel44", tipo: "reflexao", texto: "Bem-aventurados os limpos de coração, porque verão a Deus.", referencia: "Mateus 5:8", resumo: "Pureza interior abre a visão espiritual — e ver a Deus é a alegria maior possível." },
    { id: "fel45", tipo: "versiculo", texto: "O Senhor, teu Deus, está no meio de ti, poderoso para te salvar; ele se deleitará em ti com alegria.", referencia: "Sofonias 3:17", resumo: "Deus se alegra COM você. Essa verdade dá dignidade e leveza à existência." },
    { id: "fel46", tipo: "salmo", texto: "Trocaste o meu pranto em folguedo; tiraste-me o cilício e me cingiste de alegria.", referencia: "Salmos 30:11", resumo: "Deus especialista em transformar luto em festa. Nada é permanente demais para Ele mudar." },
    { id: "fel47", tipo: "versiculo", texto: "Mas o fruto do Espírito é: amor, alegria, paz.", referencia: "Gálatas 5:22", resumo: "Alegria é fruto — resultado do Espírito trabalhando dentro. Não se fabrica, se cultiva." },
    { id: "fel48", tipo: "salmo", texto: "Feliz aquele que tem por seu auxílio o Deus de Jacó.", referencia: "Salmos 146:5", resumo: "O socorro divino é a base da felicidade real. Quem tem Deus por aliado tem tudo." },
    { id: "fel49", tipo: "versiculo", texto: "Alegrem-se com os que se alegram; chorem com os que choram.", referencia: "Romanos 12:15", resumo: "Alegria compartilhada dobra; empatia gera comunhão que floresce em júbilo mútuo." },
    { id: "fel50", tipo: "salmo", texto: "Alegra a alma do teu servo, pois a ti, Senhor, elevo a minha alma.", referencia: "Salmos 86:4", resumo: "Alegria brota da entrega. Levar a alma a Deus é receber alegria em troca." },
    { id: "fel51", tipo: "versiculo", texto: "Considerai motivo de toda alegria o passardes por várias provações.", referencia: "Tiago 1:2", resumo: "Reformular a prova como oportunidade de crescimento libera alegria que a dor não rouba." },
    { id: "fel52", tipo: "salmo", texto: "Meu coração e a minha carne exultam pelo Deus vivo.", referencia: "Salmos 84:2", resumo: "Deus não é ideia distante — é vivo, e Sua realidade faz corpo e alma cantarem." },
    { id: "fel53", tipo: "versiculo", texto: "Estas coisas vos digo para que a minha alegria esteja em vós.", referencia: "João 15:11", resumo: "Jesus deseja transferir Sua própria alegria — não uma cópia, a original." },
    { id: "fel54", tipo: "salmo", texto: "Como é grande a tua bondade, que guardaste para os que te temem!", referencia: "Salmos 31:19", resumo: "Deus guarda tesouros de bondade. Descobrir isso a cada dia é fonte inesgotável de júbilo." },
    { id: "fel55", tipo: "versiculo", texto: "Regozijai-vos no Senhor sempre; outra vez digo: regozijai-vos.", referencia: "Filipenses 4:4", resumo: "A repetição é intencional. Alegria é escolha consciente, não humor passageiro." },
    { id: "fel56", tipo: "salmo", texto: "Aclamai a Deus com voz de júbilo.", referencia: "Salmos 47:1", resumo: "O louvor alto é remédio da alma. Elevar a voz eleva também o espírito." },
    { id: "fel57", tipo: "versiculo", texto: "O Deus da esperança vos encha de todo gozo e paz.", referencia: "Romanos 15:13", resumo: "Deus é fonte, não apenas doador. Ele mesmo é a alegria que preenche por dentro." },
    { id: "fel58", tipo: "salmo", texto: "O Senhor é a minha porção e o meu cálice; tu és o meu bem.", referencia: "Salmos 16:5", resumo: "Quando Deus é a porção, nada falta para a alma se alegrar." },
    { id: "fel59", tipo: "versiculo", texto: "Tenho-vos dito isto para que em mim tenhais paz. No mundo tereis aflições; mas tende bom ânimo, eu venci o mundo.", referencia: "João 16:33", resumo: "Alegria que resiste à aflição vem de saber que Cristo já venceu." },
    { id: "fel60", tipo: "salmo", texto: "Cantai ao Senhor um cântico novo, porque ele tem feito maravilhas.", referencia: "Salmos 98:1", resumo: "Cada maravilha nova pede cântico novo. A alegria se renova conforme observamos Deus agir." },
    { id: "fel61", tipo: "versiculo", texto: "A alegria do coração faz o rosto sereno.", referencia: "Provérbios 15:13", resumo: "A alegria interior transborda no rosto. Cuidar do coração é cuidar da expressão." },
    { id: "fel62", tipo: "salmo", texto: "Feliz aquele cuja iniquidade é perdoada, cujo pecado é coberto.", referencia: "Salmos 32:1", resumo: "Ser perdoado é a raiz de toda felicidade duradoura. Nada pesa mais que culpa retirada." },
    { id: "fel63", tipo: "versiculo", texto: "Ainda que a figueira não floresça, eu me alegrarei no Senhor.", referencia: "Habacuque 3:17-18", resumo: "Alegria que resiste à escassez total prova que sua fonte é Deus, não a colheita." },
    { id: "fel64", tipo: "salmo", texto: "Os que confiam no Senhor são como o monte Sião, que não se abala.", referencia: "Salmos 125:1", resumo: "Alegria firme se apoia em confiança firme. Quem confia em Deus permanece." },
    { id: "fel65", tipo: "versiculo", texto: "Grande é a paz dos que amam a tua lei.", referencia: "Salmos 119:165", resumo: "Amar a Palavra de Deus produz paz — e paz é solo fértil para alegria." },
    { id: "fel66", tipo: "salmo", texto: "Feliz aquele que não anda no conselho dos ímpios.", referencia: "Salmos 1:1", resumo: "Escolhas dão fruto. Andar longe do mal preserva a alegria que a companhia errada rouba." },
    { id: "fel67", tipo: "versiculo", texto: "Rejubilo-me na tua palavra, como quem acha grande despojo.", referencia: "Salmos 119:162", resumo: "Descobrir tesouros na Palavra é alegria genuína — como achar riqueza escondida." },
    { id: "fel68", tipo: "salmo", texto: "Servi ao Senhor com alegria; entrai na sua presença com canto.", referencia: "Salmos 100:2", resumo: "Serviço leve e cantado é sinal de coração alinhado. Alegria transforma o dever em dom." },
    { id: "fel69", tipo: "versiculo", texto: "Alegrai-vos e exultai, porque é grande nos céus a vossa recompensa.", referencia: "Mateus 5:12", resumo: "A recompensa eterna é motivo suficiente para alegria hoje, mesmo em perseguição." },
    { id: "fel70", tipo: "salmo", texto: "O justo florescerá como a palmeira.", referencia: "Salmos 92:12", resumo: "Vida com Deus é vida que floresce. Alegria é fruto natural desse florescer." },
    { id: "fel71", tipo: "versiculo", texto: "Sabemos que todas as coisas cooperam para o bem daqueles que amam a Deus.", referencia: "Romanos 8:28", resumo: "Se tudo coopera para o bem, há sempre motivo para alegria mesmo no que hoje dói." },
    { id: "fel72", tipo: "salmo", texto: "Ele resgata a tua vida da cova; ele te coroa de bondade e misericórdia.", referencia: "Salmos 103:4", resumo: "Deus coroa — não pune. Reconhecer as coroas invisíveis alimenta o júbilo diário." },
    { id: "fel73", tipo: "versiculo", texto: "Nele nos alegramos com alegria indizível e cheia de glória.", referencia: "1 Pedro 1:8", resumo: "Existe alegria que não tem palavras. Só quem prova entende — vem do encontro com Cristo." },
    { id: "fel74", tipo: "salmo", texto: "Bendirei ao Senhor em todo o tempo; o seu louvor estará continuamente na minha boca.", referencia: "Salmos 34:1", resumo: "Bendição contínua produz alegria contínua. É circuito virtuoso da alma." },
    { id: "fel75", tipo: "versiculo", texto: "A vossa tristeza se converterá em alegria.", referencia: "João 16:20", resumo: "Promessa de Jesus: a tristeza é temporária, a alegria é permanente para os Seus." },
    { id: "fel76", tipo: "salmo", texto: "Louvai o Senhor, todas as nações; louvai-o, todos os povos.", referencia: "Salmos 117:1", resumo: "Alegria de louvar Deus é universal — feita para toda tribo, língua e nação." },
    { id: "fel77", tipo: "versiculo", texto: "Buscai as coisas lá do alto, onde Cristo vive.", referencia: "Colossenses 3:1", resumo: "Focar no alto é escapar do baixo. Perspectiva celeste sustenta alegria terrena." },
    { id: "fel78", tipo: "salmo", texto: "Bendize, ó minha alma, ao Senhor, e tudo o que há em mim.", referencia: "Salmos 103:1", resumo: "Alegria integral — corpo, alma e espírito unidos em louvor. Nada de dentro fica de fora." },
    { id: "fel79", tipo: "versiculo", texto: "O Senhor é bom para com todos, e as suas misericórdias permeiam todas as suas obras.", referencia: "Salmos 145:9", resumo: "Bondade divina está por toda parte. Enxergá-la em detalhes multiplica a alegria." },
    { id: "fel80", tipo: "salmo", texto: "Os que buscam o Senhor de nenhum bem terão falta.", referencia: "Salmos 34:10", resumo: "Confiar nessa promessa liberta a alegria de depender de bens acumulados." },
    { id: "fel81", tipo: "versiculo", texto: "Muitas vezes vos deixei escritas estas coisas… para que a minha alegria seja plena em vós.", referencia: "João 17:13", resumo: "Jesus reza pela nossa alegria. É desejo Dele, não luxo nosso." },
    { id: "fel82", tipo: "salmo", texto: "Tomarei o cálice da salvação e invocarei o nome do Senhor.", referencia: "Salmos 116:13", resumo: "Celebrar a salvação como cálice — bebida a cada dia. Fonte permanente de alegria." },
    { id: "fel83", tipo: "versiculo", texto: "Deus é fiel; por meio dele fostes chamados à comunhão.", referencia: "1 Coríntios 1:9", resumo: "Fidelidade de Deus é rocha da alegria. Ele não muda, então nossa alegria pode ser firme." },
    { id: "fel84", tipo: "salmo", texto: "Tu és o meu Deus, graças te darei; tu és o meu Deus, exaltar-te-ei.", referencia: "Salmos 118:28", resumo: "Repetição é ancoragem. Declarar duas vezes 'meu Deus' fixa alegria como resposta padrão." },
    { id: "fel85", tipo: "versiculo", texto: "Quem ama a sua vida perde-a; quem a odeia neste mundo a preservará para a vida eterna.", referencia: "João 12:25", resumo: "Alegria eterna nasce quando soltamos o que agarrávamos com medo." },
    { id: "fel86", tipo: "salmo", texto: "O meu coração exulta no Senhor; a minha força está exaltada no Senhor.", referencia: "1 Samuel 2:1", resumo: "Ana canta após esterilidade prolongada. Alegria que vem depois da espera é a mais profunda." },
    { id: "fel87", tipo: "versiculo", texto: "Bem-aventurados os que ouvem a palavra de Deus e a guardam.", referencia: "Lucas 11:28", resumo: "Guardar a Palavra é preservar felicidade. Obediência protege alegria." },
    { id: "fel88", tipo: "salmo", texto: "O Senhor é o meu pastor; nada me faltará.", referencia: "Salmos 23:1", resumo: "Ter pastor perfeito é ter tudo. Alegria surge da certeza do cuidado." },
    { id: "fel89", tipo: "versiculo", texto: "Pelo que temos boa confiança e dizemos: O Senhor é o meu ajudador.", referencia: "Hebreus 13:6", resumo: "Confiança em Deus produz coragem — e coragem é irmã da alegria." },
    { id: "fel90", tipo: "salmo", texto: "Este é o dia em que agiu o Senhor; regozijemo-nos e alegremo-nos nele.", referencia: "Salmos 118:24", resumo: "Cada dia é oportunidade nova de celebrar. Hoje é presente que se abre." },
    { id: "fel91", tipo: "versiculo", texto: "Naquele dia direis: Graças dou ao Senhor, porque me abençoou.", referencia: "Isaías 12:1", resumo: "Chegará o dia em que só resta agradecer. Antecipar essa alegria acelera sua chegada." },
    { id: "fel92", tipo: "salmo", texto: "Louvai ao Senhor, invocai o seu nome, fazei conhecidos os seus feitos.", referencia: "Salmos 105:1", resumo: "Contar o que Deus fez espalha alegria — para quem conta e para quem ouve." },
    { id: "fel93", tipo: "versiculo", texto: "Todo aquele que crê que Jesus é o Cristo é nascido de Deus.", referencia: "1 João 5:1", resumo: "Nascer de Deus é começar vida nova com fonte nova de alegria." },
    { id: "fel94", tipo: "salmo", texto: "Feliz o povo que ouve a voz jubilosa.", referencia: "Salmos 89:15", resumo: "Quem aprende a distinguir a voz de Deus vive em festa contínua." },
    { id: "fel95", tipo: "versiculo", texto: "Regozijo-me em minhas fraquezas, para que sobre mim repouse o poder de Cristo.", referencia: "2 Coríntios 12:9", resumo: "Alegria paradoxal: nossa fraqueza revela o poder Dele. Menos ego, mais alegria." },
    { id: "fel96", tipo: "salmo", texto: "Feliz o homem que não anda segundo o conselho dos ímpios; antes, tem prazer na lei do Senhor.", referencia: "Salmos 1:1-2", resumo: "Prazer na Palavra é blindagem contra alegrias falsas. O real dura, o falso decepciona." },
    { id: "fel97", tipo: "versiculo", texto: "Vinde a mim, todos os que estais cansados, e eu vos aliviarei.", referencia: "Mateus 11:28", resumo: "Alívio de Cristo é porta de entrada para alegria genuína, além do cansaço." },
    { id: "fel98", tipo: "salmo", texto: "Faz sair o pão da terra, e o vinho que alegra o coração do homem.", referencia: "Salmos 104:14-15", resumo: "Deus cria coisas que alegram. Reconhecer isso em cada refeição é adoração." },
    { id: "fel99", tipo: "versiculo", texto: "Se, pois, o Filho vos libertar, verdadeiramente sereis livres.", referencia: "João 8:36", resumo: "Liberdade em Cristo é solo onde alegria cresce sem correntes de culpa." },
    { id: "fel100", tipo: "salmo", texto: "Aquele que habita no esconderijo do Altíssimo descansará à sombra do Onipotente.", referencia: "Salmos 91:1", resumo: "Descanso protegido é fonte de alegria calma que nenhuma tempestade tira." },
    { id: "fel101", tipo: "versiculo", texto: "O amor de Deus é derramado em nosso coração pelo Espírito Santo.", referencia: "Romanos 5:5", resumo: "Amor derramado dentro produz alegria que transborda para fora." },
    { id: "fel102", tipo: "salmo", texto: "Ainda que eu ande pelo vale da sombra da morte, não temerei mal algum.", referencia: "Salmos 23:4", resumo: "Alegria que caminha pelo vale é a mais sólida. Companhia de Deus muda tudo." },
    { id: "fel103", tipo: "versiculo", texto: "Se alguém está em Cristo, nova criatura é.", referencia: "2 Coríntios 5:17", resumo: "Identidade renovada em Cristo desbloqueia alegria que a velha vida não conhecia." },
    { id: "fel104", tipo: "salmo", texto: "O Senhor pelejará por vós, e vós vos calareis.", referencia: "Êxodo 14:14", resumo: "Saber que Deus luta por você libera alegria descansada em vez de ansiedade." },
    { id: "fel105", tipo: "versiculo", texto: "Sê fiel até à morte, e dar-te-ei a coroa da vida.", referencia: "Apocalipse 2:10", resumo: "Coroa de vida à frente ilumina o hoje. Alegria antecipada é já vitória." },
    { id: "fel106", tipo: "salmo", texto: "Deus é o nosso refúgio e fortaleza, socorro que sempre se acha nas tribulações.", referencia: "Salmos 46:1", resumo: "Ter refúgio garantido dá espaço para alegria mesmo no meio de crises." },
    { id: "fel107", tipo: "versiculo", texto: "Aquele que começou boa obra em vós há de completá-la.", referencia: "Filipenses 1:6", resumo: "Deus termina o que começa. Alegria vem de confiar no final da história." },
    { id: "fel108", tipo: "salmo", texto: "O Senhor é a força da minha vida.", referencia: "Salmos 27:1", resumo: "Força vem Dele — não de nós. Descansar nessa realidade produz alegria constante." },
    { id: "fel109", tipo: "versiculo", texto: "Achegai-vos a Deus, e ele se achegará a vós.", referencia: "Tiago 4:8", resumo: "Aproximar-se de Deus é aproximar-se da fonte da alegria." },
    { id: "fel110", tipo: "versiculo", texto: "O gozo do Senhor é a vossa força.", referencia: "Neemias 8:10", resumo: "Alegria em Deus é combustível espiritual. Fonte que sustenta em qualquer dia." },
  ],
  "Ansioso": [
    { id: "ans1", tipo: "versiculo", texto: "Não andem ansiosos por coisa alguma, mas em tudo apresentem seus pedidos a Deus.", referencia: "Filipenses 4:6", resumo: "Paulo oferece um caminho prático: substituir a preocupação pela oração com gratidão. A ansiedade prospera quando ruminamos em silêncio; perde força quando verbalizamos os pesos diante de Deus. O resultado é uma paz que age como sentinela." },
    { id: "ans2", tipo: "versiculo", texto: "Lancem sobre ele toda a sua ansiedade, porque ele tem cuidado de vocês.", referencia: "1 Pedro 5:7", resumo: "'Lançar' descreve arremessar algo pesado para longe — não entregar com hesitação, mas transferir definitivamente. A motivação é o caráter amoroso do Pai: Ele cuida por amor, não por obrigação." },
    { id: "ans3", tipo: "salmo", texto: "Quando a ansiedade já me dominava, o teu consolo trouxe alívio à minha alma.", referencia: "Salmos 94:19", resumo: "O salmista confessa abertamente: houve momentos em que a ansiedade dominou. O consolo de Deus não é fuga das dificuldades, mas presença ativa que entra na tempestade. Reconhecer e buscar esse consolo é o primeiro passo da libertação." },
    { id: "ans4", tipo: "versiculo", texto: "Quem de vocês, por mais que se preocupe, pode acrescentar uma hora que seja à sua vida?", referencia: "Mateus 6:27", resumo: "Jesus usa lógica direta: a preocupação não tem poder para mudar tempo, saúde ou circunstâncias. Ele convida a redirecionar essa energia para a confiança em Deus e a ação no presente." },
    { id: "ans5", tipo: "versiculo", texto: "Não vos inquieteis pelo dia de amanhã; basta a cada dia o seu mal.", referencia: "Mateus 6:34", resumo: "Jesus convida a viver um dia de cada vez. A ansiedade prospera quando misturamos os problemas de hoje com os medos do amanhã. Confiar no cuidado futuro de Deus libera o presente." },
    { id: "ans6", tipo: "salmo", texto: "Mesmo quando eu andar por um vale escuro como a morte, não temerei mal algum, porque tu estás comigo.", referencia: "Salmos 23:4", resumo: "A coragem não vem da ausência do vale, mas da companhia de Quem caminha junto. Saber que não estamos sozinhos transforma o medo em fé serena." },
    { id: "ans7", tipo: "salmo", texto: "Entrega o teu caminho ao Senhor, confia nele, e o mais ele fará.", referencia: "Salmos 37:5", resumo: "A ansiedade nasce de tentar controlar o incontrolável. Entregar conscientemente cada decisão e cada espera revela um Deus que cumpre o que prometeu." },
    { id: "ans8", tipo: "versiculo", texto: "Vinde a mim, todos os que estais cansados e sobrecarregados, e eu vos aliviarei.", referencia: "Mateus 11:28", resumo: "O convite de Jesus é pessoal e gratuito. Ir até Ele significa parar de tentar resolver tudo sozinho e permitir que o Pai sustente o que estava nos esmagando." },
    { id: "ans9", tipo: "salmo", texto: "Aquietai-vos e sabei que eu sou Deus.", referencia: "Salmos 46:10", resumo: "No meio do caos, Deus pede silêncio. Aquietar-se não é desistir, é reconhecer que existe Alguém maior cuidando do que escapa do nosso controle." },
    { id: "ans10", tipo: "salmo", texto: "Em paz me deitarei e dormirei, porque só tu, Senhor, me fazes habitar em segurança.", referencia: "Salmos 4:8", resumo: "Davi escreve em meio à perseguição, mas dorme em paz. A serenidade da noite vem do reconhecimento de que Deus continua acordado e cuidando. Uma oração noturna libertadora para a mente ansiosa." },
    { id: "ans11", tipo: "versiculo", texto: "Não se turbe o vosso coração; credes em Deus, crede também em mim.", referencia: "João 14:1", resumo: "Jesus liga diretamente a paz interior à fé. Quando o coração se agita, a saída é redirecionar a confiança para Deus e para Cristo. A turbação cede onde a fé entra." },
    { id: "ans12", tipo: "salmo", texto: "Em qualquer tempo em que eu temer, hei de confiar em ti.", referencia: "Salmos 56:3", resumo: "Davi não nega o medo — ele decide o que fazer com ele. Cada vez que sentir medo, a resposta será confiar. É uma disciplina espiritual treinada a longo prazo." },
    { id: "ans13", tipo: "reflexao", texto: "A ansiedade no coração do homem o abate, mas a boa palavra o alegra.", referencia: "Provérbios 12:25", resumo: "Palavras certas podem aliviar a alma esmagada. Buscar boas palavras — bíblicas, de amigos, de mentores — é estratégia real contra a ansiedade." },
    { id: "ans14", tipo: "salmo", texto: "Elevo os meus olhos para os montes; de onde virá o meu socorro? O meu socorro vem do Senhor.", referencia: "Salmos 121:1-2", resumo: "O salmista olha para fora e para cima — e identifica a fonte real do socorro. Em momentos ansiosos, mudar o foco para Deus reposiciona toda a perspectiva." },
    { id: "ans15", tipo: "versiculo", texto: "Humilhai-vos, pois, debaixo da potente mão de Deus, para que, a seu tempo, ele vos exalte.", referencia: "1 Pedro 5:6", resumo: "Antes de mandar lançar a ansiedade, Pedro pede humildade. Reconhecer que não controlamos tudo é o primeiro passo para descansar nas mãos de Quem controla." },
    { id: "ans16", tipo: "salmo", texto: "Ainda que eu ande angustiado, tu me reanimas; contra a ira dos meus inimigos estendes a mão.", referencia: "Salmos 138:7", resumo: "Mesmo angustiado, o salmista descobre reanimação ativa de Deus. A angústia não anula a presença divina; pelo contrário, é onde ela mais se manifesta." },
    { id: "ans17", tipo: "versiculo", texto: "Não recebestes o espírito de escravidão para outra vez estardes em temor, mas recebestes o espírito de adoção, baseados no qual clamamos: Aba, Pai!", referencia: "Romanos 8:15", resumo: "Paulo lembra: o cristão não vive sob medo de escravo, mas sob a confiança de filho. Chamar Deus de 'Pai' transforma a ansiedade em intimidade." },
    { id: "ans18", tipo: "versiculo", texto: "Dizei aos turbados de coração: Sede fortes, não temais; eis o vosso Deus.", referencia: "Isaías 35:4", resumo: "A cura do coração turbado começa com uma declaração: 'eis o vosso Deus'. Ver a Deus em primeiro lugar reduz qualquer ameaça ao tamanho real." },
    { id: "ans19", tipo: "salmo", texto: "O Senhor é refúgio para o oprimido, refúgio nos tempos de angústia.", referencia: "Salmos 9:9", resumo: "Quem está ansioso precisa de refúgio. Deus é exatamente isso: um abrigo seguro nas horas em que tudo parece grande demais." },
    { id: "ans20", tipo: "versiculo", texto: "Não vos inquieteis, pois, dizendo: Que comeremos? Vosso Pai celeste sabe que necessitais de todas elas.", referencia: "Mateus 6:31-32", resumo: "Jesus tira o peso da inquietação ao mostrar que o Pai já conhece cada necessidade. A ansiedade muitas vezes esquece esse fato simples e transformador." },
    { id: "ans21", tipo: "salmo", texto: "No dia da minha angústia, clamarei a ti, porque me respondes.", referencia: "Salmos 86:7", resumo: "A oração funciona. O salmista clama porque já experimentou respostas. Renovar essa confiança quebra o ciclo ansioso de pensamentos sem rumo." },
    { id: "ans22", tipo: "versiculo", texto: "Ora, o próprio Senhor da paz vos dê continuamente a paz em toda e qualquer circunstância.", referencia: "2 Tessalonicenses 3:16", resumo: "Paulo ora especificamente por paz contínua em qualquer cenário. Essa paz é dom de Deus, não conquista pessoal. Pedir por ela já é começar a recebê-la." },
    { id: "ans23", tipo: "salmo", texto: "Não temerás os terrores da noite, nem a seta que voa de dia.", referencia: "Salmos 91:5", resumo: "Promessa de proteção contra medos noturnos e diurnos. Quem habita à sombra do Altíssimo descansa numa cobertura que nenhuma ansiedade consegue romper." },
    { id: "ans24", tipo: "reflexao", texto: "Quando te deitares, não temerás; sim, deitar-te-ás, e o teu sono será suave.", referencia: "Provérbios 3:24", resumo: "A obediência à sabedoria divina produz sono tranquilo. Mente alinhada com Deus deita-se sem o peso que normalmente impede o descanso." },
    { id: "ans25", tipo: "salmo", texto: "Volta, minha alma, ao teu repouso, pois o Senhor te fez bem.", referencia: "Salmos 116:7", resumo: "O salmista convoca a própria alma de volta ao descanso. Lembrar do bem já feito por Deus é o caminho de regresso quando a inquietação tenta dominar." },
    { id: "ans26", tipo: "versiculo", texto: "O efeito da justiça será paz, e o resultado da justiça, repouso e segurança para sempre.", referencia: "Isaías 32:17", resumo: "Viver no caminho de Deus produz paz como fruto natural. Reordenar escolhas e prioridades segundo a justiça divina alivia muitas ansiedades." },
    { id: "ans27", tipo: "salmo", texto: "Acalmei e sosseguei a minha alma; ela está em mim como criança desmamada.", referencia: "Salmos 131:2", resumo: "Davi descreve uma alma que aprendeu a ficar quieta como criança no colo da mãe. Esse sossego é treinado — exige decisão diária de soltar." },
    { id: "ans28", tipo: "versiculo", texto: "E qual de vós, por ansioso que esteja, pode acrescentar um côvado ao curso da sua vida?", referencia: "Lucas 12:25-26", resumo: "Jesus repete a verdade: a ansiedade é improdutiva. Se ela nem nas coisas mínimas funciona, por que confiar nela nas maiores? Trocar inquietação por oração é racional." },
    { id: "ans29", tipo: "salmo", texto: "Quem me dera asas como de pomba! Voaria e acharia pouso.", referencia: "Salmos 55:6", resumo: "Davi reconhece o desejo humano de fugir. A Bíblia não esconde esse impulso — apenas mostra que o verdadeiro pouso está em Deus, não em escapadas." },
    { id: "ans30", tipo: "versiculo", texto: "Acheguemo-nos, portanto, confiadamente, junto ao trono da graça, para recebermos misericórdia e acharmos graça para socorro em ocasião oportuna.", referencia: "Hebreus 4:16", resumo: "O trono de Deus é descrito como 'da graça', não do julgamento. Em hora ansiosa, há socorro pronto para quem se aproxima com confiança." },
    { id: "ans31", tipo: "versiculo", texto: "Lançando sobre ele toda a vossa ansiedade, porque ele tem cuidado de vós.", referencia: "1 Pedro 5:7", resumo: "Ansiedade não deve ser carregada — deve ser entregue. Deus cuida ativamente de cada detalhe." },
    { id: "ans32", tipo: "salmo", texto: "Confia no Senhor de todo o teu coração e não te estribes no teu próprio entendimento.", referencia: "Provérbios 3:5", resumo: "Ansiedade cresce quando tentamos entender tudo. Confiar libera o peso do controle." },
    { id: "ans33", tipo: "versiculo", texto: "A paz de Deus, que excede todo o entendimento, guardará o vosso coração.", referencia: "Filipenses 4:7", resumo: "Paz que ultrapassa raciocínio é presente divino — vigia como sentinela do coração." },
    { id: "ans34", tipo: "salmo", texto: "Aquietai-vos e sabei que eu sou Deus.", referencia: "Salmos 46:10", resumo: "Silêncio interior é ato de fé. Parar de agir para lembrar quem realmente comanda." },
    { id: "ans35", tipo: "reflexao", texto: "Não vos inquieteis pela vida, pelo que haveis de comer ou beber; nem pelo corpo, pelo que haveis de vestir.", referencia: "Mateus 6:25", resumo: "Jesus ataca a raiz da ansiedade: preocupação com sustento. Deus alimenta pássaros — cuidará de você." },
    { id: "ans36", tipo: "versiculo", texto: "Buscai primeiro o reino de Deus e a sua justiça, e todas essas coisas vos serão acrescentadas.", referencia: "Mateus 6:33", resumo: "Reordenar prioridades cura ansiedade. Foco no reino desloca preocupação para expectativa." },
    { id: "ans37", tipo: "salmo", texto: "Tu conservarás em perfeita paz aquele cuja mente está firme em ti.", referencia: "Isaías 26:3", resumo: "Mente ancorada em Deus recebe paz completa. A cura da ansiedade é onde está a atenção." },
    { id: "ans38", tipo: "versiculo", texto: "Nada vos deixará que vos possa fazer mal.", referencia: "Lucas 10:19", resumo: "Autoridade de Cristo em nós desmonta a ilusão de estar desprotegido." },
    { id: "ans39", tipo: "salmo", texto: "O Senhor é o meu pastor; nada me faltará.", referencia: "Salmos 23:1", resumo: "Certeza da provisão retira o combustível principal da ansiedade." },
    { id: "ans40", tipo: "versiculo", texto: "Não temas, porque eu sou contigo; não te assombres, porque eu sou o teu Deus.", referencia: "Isaías 41:10", resumo: "Duas negações e duas afirmações. Deus não deixa margem para dúvida sobre estar com você." },
    { id: "ans41", tipo: "salmo", texto: "Entrega o teu caminho ao Senhor; confia nele, e ele tudo fará.", referencia: "Salmos 37:5", resumo: "Entregar é ação. Depois de entregue, o descanso é possível — Ele age." },
    { id: "ans42", tipo: "versiculo", texto: "Não vos inquieteis com o dia de amanhã, pois o amanhã trará os seus cuidados.", referencia: "Mateus 6:34", resumo: "Ansiedade é sempre sobre futuro. Ficar no hoje é obedecer a Cristo." },
    { id: "ans43", tipo: "salmo", texto: "Clamei ao Senhor na minha angústia, e ele me acudiu.", referencia: "Salmos 120:1", resumo: "Clamor é primeira resposta certa. Ansiedade se dissolve quando falamos com Deus." },
    { id: "ans44", tipo: "reflexao", texto: "O justo florescerá como a palmeira.", referencia: "Salmos 92:12", resumo: "Palmeira dobra na tempestade, mas não quebra. Ansiedade não determina o florescimento." },
    { id: "ans45", tipo: "versiculo", texto: "Deus não nos deu espírito de covardia, mas de poder, de amor e de moderação.", referencia: "2 Timóteo 1:7", resumo: "Ansiedade não é herança espiritual. Recebemos poder, amor e mente sã como padrão." },
    { id: "ans46", tipo: "salmo", texto: "Vim a saber que tudo quanto Deus faz durará eternamente.", referencia: "Eclesiastes 3:14", resumo: "O que Deus faz é permanente. Ancorar-se nisso reduz a ansiedade do temporário." },
    { id: "ans47", tipo: "versiculo", texto: "Vinde a mim, todos os que estais cansados e sobrecarregados.", referencia: "Mateus 11:28", resumo: "Convite direto. Ansiedade é peso que Jesus quer tirar dos ombros." },
    { id: "ans48", tipo: "salmo", texto: "Deposita em Deus a tua ansiedade, e ele te susterá.", referencia: "Salmos 55:22", resumo: "Deposita e é sustido. Não é troca — é entrega para receber sustento." },
    { id: "ans49", tipo: "versiculo", texto: "Não andeis, pois, ansiosos, dizendo: Que comeremos?", referencia: "Mateus 6:31", resumo: "Ansiedade sobre necessidades básicas é sinal de esquecer o Pai. Ele conhece cada carência." },
    { id: "ans50", tipo: "salmo", texto: "Ainda que eu ande pelo vale da sombra da morte, não temerei mal algum.", referencia: "Salmos 23:4", resumo: "Andar pelo vale sem temer — porque Ele vai junto. Presença é antídoto do medo." },
    { id: "ans51", tipo: "versiculo", texto: "Nele vivemos, nos movemos e existimos.", referencia: "Atos 17:28", resumo: "Cada respiração é em Deus. Ansiedade esquece essa proximidade radical." },
    { id: "ans52", tipo: "salmo", texto: "Tu és o meu esconderijo; tu me preservas da tribulação.", referencia: "Salmos 32:7", resumo: "Esconderijo divino é real. Não elimina tribulação — preserva o coração dentro dela." },
    { id: "ans53", tipo: "versiculo", texto: "Não temas, crê somente.", referencia: "Marcos 5:36", resumo: "Fé e medo brigam pelo mesmo espaço. Escolher crer é ejetar o temor." },
    { id: "ans54", tipo: "salmo", texto: "Deus é para nós refúgio e fortaleza.", referencia: "Salmos 46:1", resumo: "Duas figuras: refúgio (esconderijo) e fortaleza (proteção ativa). Ansiedade encolhe diante disso." },
    { id: "ans55", tipo: "versiculo", texto: "Se Deus é por nós, quem será contra nós?", referencia: "Romanos 8:31", resumo: "Aliança com Deus torna qualquer oposição pequena. Ansiedade perde chão." },
    { id: "ans56", tipo: "salmo", texto: "O Senhor guardará a tua saída e a tua entrada.", referencia: "Salmos 121:8", resumo: "Cobertura de porta em porta. Nenhum movimento seu está fora do olhar Dele." },
    { id: "ans57", tipo: "versiculo", texto: "Quem, dentre vós, por ansioso que esteja, pode acrescentar um côvado à sua estatura?", referencia: "Mateus 6:27", resumo: "Ansiedade não muda nada — só desgasta. Jesus expõe sua inutilidade." },
    { id: "ans58", tipo: "salmo", texto: "Bendize, ó minha alma, ao Senhor.", referencia: "Salmos 103:1", resumo: "Ordenar à alma que bendiga é retomar comando interior. Louvor derruba ansiedade." },
    { id: "ans59", tipo: "versiculo", texto: "Aprendei de mim, porque sou manso e humilde de coração; achareis descanso.", referencia: "Mateus 11:29", resumo: "Descanso é aprendido observando Jesus. Ansiedade se dissolve em Sua escola." },
    { id: "ans60", tipo: "salmo", texto: "Ele é a rocha, suas obras são perfeitas.", referencia: "Deuteronômio 32:4", resumo: "Perfeição de Deus não deixa espaço para ansiedade sobre erros divinos. Ele não falha." },
    { id: "ans61", tipo: "versiculo", texto: "Não temais, pequenino rebanho.", referencia: "Lucas 12:32", resumo: "Ternura de Pastor com rebanho pequeno. Ansiedade é abraçada — não repreendida." },
    { id: "ans62", tipo: "salmo", texto: "No dia em que temer, hei de confiar em ti.", referencia: "Salmos 56:3", resumo: "Reconhece medo — sem se render a ele. Confiança é resposta consciente." },
    { id: "ans63", tipo: "versiculo", texto: "O amor lança fora todo o medo.", referencia: "1 João 4:18", resumo: "Amor de Deus e medo não coexistem em plenitude. Encher-se de amor esvazia o medo." },
    { id: "ans64", tipo: "salmo", texto: "Deus é o meu rochedo; nele confiarei.", referencia: "2 Samuel 22:3", resumo: "Rocha não se move. Nada que dependa de rocha divina precisa de ansiedade humana." },
    { id: "ans65", tipo: "versiculo", texto: "Ele mesmo disse: De maneira alguma te deixarei, nunca jamais te abandonarei.", referencia: "Hebreus 13:5", resumo: "Tripla negação: nunca, jamais, de maneira alguma. Deus fecha a possibilidade de abandono." },
    { id: "ans66", tipo: "salmo", texto: "Levantai as vossas cabeças, porque a vossa redenção se aproxima.", referencia: "Lucas 21:28", resumo: "Redenção próxima é motivo de esperança, não de ansiedade. Olhar para cima muda tudo." },
    { id: "ans67", tipo: "versiculo", texto: "Não vos inquieteis com coisa alguma; em tudo, pela oração e súplica, apresentai as vossas petições a Deus.", referencia: "Filipenses 4:6", resumo: "Antídoto exato: preocupação vira oração. Cada ansiedade é convite para conversar com Deus." },
    { id: "ans68", tipo: "salmo", texto: "Melhor é confiar no Senhor do que confiar no homem.", referencia: "Salmos 118:8", resumo: "Fonte errada de segurança gera ansiedade. Confiar em Deus estabiliza." },
    { id: "ans69", tipo: "versiculo", texto: "Se Deus assim veste a erva do campo, quanto mais a vós?", referencia: "Mateus 6:30", resumo: "Argumento lógico de Jesus: se cuida das ervas, cuidará muito mais de você." },
    { id: "ans70", tipo: "salmo", texto: "Os seus caminhos são caminhos de delícias, e todas as suas veredas, paz.", referencia: "Provérbios 3:17", resumo: "Sabedoria de Deus conduz por veredas de paz. Ansiedade sinaliza que saímos delas." },
    { id: "ans71", tipo: "versiculo", texto: "O Senhor pelejará por vós, e vós vos calareis.", referencia: "Êxodo 14:14", resumo: "Silenciar quando Deus luta é ato de fé. Ansiedade parla — fé descansa." },
    { id: "ans72", tipo: "salmo", texto: "Feliz aquele cuja força está em ti.", referencia: "Salmos 84:5", resumo: "Força de Deus como fonte silencia ansiedade sobre esgotamento próprio." },
    { id: "ans73", tipo: "versiculo", texto: "Onde há o Espírito do Senhor, aí há liberdade.", referencia: "2 Coríntios 3:17", resumo: "Ansiedade prende. Espírito liberta. Onde Ele opera, cadeias mentais se soltam." },
    { id: "ans74", tipo: "salmo", texto: "Alegrai-vos no Senhor.", referencia: "Filipenses 4:4", resumo: "Alegria e ansiedade não moram juntas. Escolher alegria é despejar ansiedade." },
    { id: "ans75", tipo: "versiculo", texto: "A minha graça te basta, porque o poder se aperfeiçoa na fraqueza.", referencia: "2 Coríntios 12:9", resumo: "Graça suficiente cobre insuficiência que gera ansiedade. Fraqueza vira palco do poder Dele." },
    { id: "ans76", tipo: "salmo", texto: "Bem-aventurado o homem que confia no Senhor.", referencia: "Jeremias 17:7", resumo: "Confiança gera bem-aventurança — estado oposto à ansiedade. Escolha diária." },
    { id: "ans77", tipo: "versiculo", texto: "Ele mesmo é a nossa paz.", referencia: "Efésios 2:14", resumo: "Não é que Ele dá paz — Ele É paz. Ter Cristo é ter a paz em pessoa." },
    { id: "ans78", tipo: "salmo", texto: "Grande é a paz que têm os que amam a tua lei.", referencia: "Salmos 119:165", resumo: "Amor à Palavra produz paz que resiste a tropeços. Ansiedade encolhe diante da lei amada." },
    { id: "ans79", tipo: "versiculo", texto: "Perturba-se o vosso coração; crede em Deus, crede também em mim.", referencia: "João 14:1", resumo: "Jesus dá antídoto contra perturbação: fé dupla — em Deus e Nele mesmo." },
    { id: "ans80", tipo: "salmo", texto: "O Senhor é a minha luz e a minha salvação; a quem temerei?", referencia: "Salmos 27:1", resumo: "Luz e salvação removem o escuro que alimenta ansiedade. Nome de Deus dissipa medo." },
    { id: "ans81", tipo: "versiculo", texto: "Não vos inquieteis com o modo por que haveis de responder.", referencia: "Lucas 12:11", resumo: "Até em provações jurídicas — Deus dá palavras. Ansiedade sobre desempenho é desnecessária." },
    { id: "ans82", tipo: "salmo", texto: "Estes confiam em carros, aqueles em cavalos, mas nós faremos menção do nome do Senhor.", referencia: "Salmos 20:7", resumo: "Deslocar confiança de recursos humanos para o nome de Deus reduz ansiedade estrutural." },
    { id: "ans83", tipo: "versiculo", texto: "Deus é fiel, o qual não permitirá que sejais tentados além do que podeis.", referencia: "1 Coríntios 10:13", resumo: "Fidelidade divina limita a intensidade da provação. Nunca sobrecarga real — Ele mede." },
    { id: "ans84", tipo: "salmo", texto: "Guardarás em suma paz aquele cujo propósito é firme.", referencia: "Isaías 26:3", resumo: "Firmeza de propósito atrai proteção de paz. Coração dividido convida ansiedade." },
    { id: "ans85", tipo: "versiculo", texto: "Aquietai-vos.", referencia: "Marcos 4:39", resumo: "Palavra de Jesus ao mar e ao vento. Mesma autoridade aquieta tempestade interior." },
    { id: "ans86", tipo: "salmo", texto: "O Senhor dará forças ao seu povo; abençoará o seu povo com paz.", referencia: "Salmos 29:11", resumo: "Força e paz caminham juntas do trono de Deus. Não faltam a quem pertence a Ele." },
    { id: "ans87", tipo: "versiculo", texto: "Confortai-vos uns aos outros com estas palavras.", referencia: "1 Tessalonicenses 4:18", resumo: "Ansiedade se cura em comunidade. Palavras trocadas entre irmãos são remédio." },
    { id: "ans88", tipo: "salmo", texto: "O Senhor é bom, uma fortaleza no dia da angústia.", referencia: "Naum 1:7", resumo: "Angústia tem endereço seguro: a fortaleza que é Deus. Bondade Dele é abrigo." },
    { id: "ans89", tipo: "versiculo", texto: "Cristo é a nossa esperança.", referencia: "1 Timóteo 1:1", resumo: "Esperança que é pessoa, não conceito. Ansiedade recua diante de Cristo vivo." },
    { id: "ans90", tipo: "salmo", texto: "Como o pai se compadece de seus filhos, assim o Senhor se compadece dos que o temem.", referencia: "Salmos 103:13", resumo: "Compaixão paterna cobre cada ansiedade infantil. Deus se comove — não se irrita." },
    { id: "ans91", tipo: "versiculo", texto: "A vossa vida está oculta com Cristo em Deus.", referencia: "Colossenses 3:3", resumo: "Vida escondida em Deus é vida protegida. Ansiedade não penetra esse esconderijo." },
    { id: "ans92", tipo: "salmo", texto: "Espero no Senhor, a minha alma espera; eu espero na sua palavra.", referencia: "Salmos 130:5", resumo: "Esperar ativamente na Palavra desloca ansiedade para expectativa." },
    { id: "ans93", tipo: "versiculo", texto: "Todo aquele que Nele crê não será confundido.", referencia: "Romanos 10:11", resumo: "Confusão alimenta ansiedade. Fé em Cristo garante clareza no fim." },
    { id: "ans94", tipo: "salmo", texto: "O Senhor está perto de todos os que o invocam, dos que o invocam em verdade.", referencia: "Salmos 145:18", resumo: "Proximidade de Deus a um clamor sincero desarma qualquer ansiedade." },
    { id: "ans95", tipo: "versiculo", texto: "Sabemos que todas as coisas cooperam para o bem daqueles que amam a Deus.", referencia: "Romanos 8:28", resumo: "Se tudo coopera para o bem, ansiedade sobre resultados perde sentido." },
    { id: "ans96", tipo: "salmo", texto: "Ao Deus da minha alegria e do meu prazer.", referencia: "Salmos 43:4", resumo: "Fazer de Deus a fonte da alegria pessoal derruba ansiedade sobre outras fontes." },
    { id: "ans97", tipo: "versiculo", texto: "Não temas o que hás de padecer.", referencia: "Apocalipse 2:10", resumo: "Cristo autoriza a coragem antes mesmo do sofrimento. Ansiedade prévia é dispensada." },
    { id: "ans98", tipo: "salmo", texto: "Guarda a tua alma e liberta-a.", referencia: "Salmos 25:20", resumo: "Cuidar da alma é ato ativo. Ansiedade cede quando entregamos guarda a Deus." },
    { id: "ans99", tipo: "versiculo", texto: "Se algum de vós tem falta de sabedoria, peça-a a Deus.", referencia: "Tiago 1:5", resumo: "Falta de sabedoria gera ansiedade. Pedir a Deus é solução direta e generosa." },
    { id: "ans100", tipo: "salmo", texto: "O Senhor te guardará de todo mal.", referencia: "Salmos 121:7", resumo: "Guarda integral. Ansiedade cai diante da promessa abrangente." },
    { id: "ans101", tipo: "versiculo", texto: "Bem-aventurados os que choram, porque serão consolados.", referencia: "Mateus 5:4", resumo: "Consolo prometido cura ansiedade sobre a dor presente. Deus não ignora lágrima." },
    { id: "ans102", tipo: "salmo", texto: "Farto-me com o sono, quando desperto, com a tua semelhança.", referencia: "Salmos 17:15", resumo: "Foco em ver Deus no despertar substitui ansiedade matinal por expectativa." },
    { id: "ans103", tipo: "versiculo", texto: "Quem crê nele não perecerá.", referencia: "João 3:16", resumo: "Segurança eterna elimina a ansiedade última. Tudo mais é temporário." },
    { id: "ans104", tipo: "salmo", texto: "O olhar do Senhor está sobre os que o temem.", referencia: "Salmos 33:18", resumo: "Olhar constante de Deus. Ansiedade de ser esquecido não sobrevive a isso." },
    { id: "ans105", tipo: "versiculo", texto: "Tenho vencido o mundo.", referencia: "João 16:33", resumo: "Vitória de Cristo é dada aos Seus. Ansiedade combate um inimigo já derrotado." },
    { id: "ans106", tipo: "salmo", texto: "Ele te livrará do laço do passarinheiro e da peste perniciosa.", referencia: "Salmos 91:3", resumo: "Livramento específico e concreto. Ansiedade cede diante de proteção detalhada." },
    { id: "ans107", tipo: "versiculo", texto: "Não temas, filha de Sião.", referencia: "João 12:15", resumo: "Palavra a comunidade inteira. Ansiedade coletiva também tem endereço no evangelho." },
    { id: "ans108", tipo: "salmo", texto: "Eu me deitei e dormi; acordei, porque o Senhor me sustenta.", referencia: "Salmos 3:5", resumo: "Poder dormir e acordar em paz é sinal de confiança. Ansiedade rouba isso." },
    { id: "ans109", tipo: "versiculo", texto: "Estou convencido de que nem morte nem vida poderão separar-nos do amor de Deus.", referencia: "Romanos 8:38-39", resumo: "Amor eterno inseparável. Base sólida para dispensar ansiedade sobre relação com Deus." },
    { id: "ans110", tipo: "salmo", texto: "O Senhor te abençoe e te guarde.", referencia: "Números 6:24", resumo: "Bênção sacerdotal é ativa. Guardar é ato — não descrição. Ansiedade cede." },
  ],
  "Triste": [
    { id: "tri1", tipo: "versiculo", texto: "O Senhor está perto dos que têm o coração quebrantado.", referencia: "Salmos 34:18", resumo: "Davi descobriu que Deus tem proximidade especial com corações despedaçados. A dor não nos afasta de Deus — é onde Ele mais se aproxima. Ele oferece ternura, presença íntima e reconstrução interior." },
    { id: "tri2", tipo: "versiculo", texto: "Bem-aventurados os que choram, pois serão consolados.", referencia: "Mateus 5:4", resumo: "Jesus inverte os valores do mundo: declara felizes os que choram. A promessa não é que o choro será evitado, mas respondido com consolo divino. Reconhecer a dor é, paradoxalmente, o caminho da cura." },
    { id: "tri3", tipo: "salmo", texto: "O choro pode durar uma noite, mas a alegria vem pela manhã.", referencia: "Salmos 30:5", resumo: "A dor tem prazo, mesmo quando parece eterna. A fidelidade de Deus é como o nascer do sol: certa, pontual e capaz de iluminar até a noite mais escura." },
    { id: "tri4", tipo: "versiculo", texto: "Ele enxugará dos seus olhos toda lágrima.", referencia: "Apocalipse 21:4", resumo: "Imagem extraordinariamente íntima: Deus pessoalmente se inclinando para enxugar lágrimas. A promessa elimina não apenas o choro, mas suas causas. A dor atual é real, mas temporária." },
    { id: "tri5", tipo: "salmo", texto: "Ele sara os de coração quebrantado e cura-lhes as feridas.", referencia: "Salmos 147:3", resumo: "Deus age como médico atento, cuidando de cada ferida da alma. Saber que existe cura para o coração quebrado renova a esperança em meio à tristeza." },
    { id: "tri6", tipo: "salmo", texto: "Por que estás abatida, ó minha alma? Espera em Deus, pois ainda o louvarei.", referencia: "Salmos 42:11", resumo: "O salmista conversa com a própria alma, recusando-se a deixar a tristeza ter a última palavra. Mesmo na dor, direciona o coração para Deus e antecipa o louvor." },
    { id: "tri7", tipo: "reflexao", texto: "O Deus de toda graça vos restaurará, vos confirmará, vos fortalecerá e vos porá em firme fundamento.", referencia: "1 Pedro 5:10", resumo: "Pedro promete restauração depois do sofrimento. Deus não apenas conforta — Ele reconstrói. A dor passa, mas a obra que Ele faz em nós permanece." },
    { id: "tri8", tipo: "versiculo", texto: "Lança o teu cuidado sobre o Senhor, e ele te susterá.", referencia: "Salmos 55:22", resumo: "Sustentar é segurar para que não caia. Quando entregamos a tristeza a Deus, recebemos sustentação que não vem de nós, mas das mãos do Pai." },
    { id: "tri9", tipo: "salmo", texto: "O Senhor é o meu pastor; nada me faltará.", referencia: "Salmos 23:1", resumo: "Mesmo na tristeza, o Pastor cuida das ovelhas. Davi declara confiança numa provisão integral — espiritual, emocional, prática. Nada do que falta hoje está fora dos olhos de Deus." },
    { id: "tri10", tipo: "versiculo", texto: "Jesus chorou.", referencia: "João 11:35", resumo: "O menor versículo da Bíblia carrega uma das verdades mais consoladoras: Deus encarnado também chorou diante da dor humana. Suas lágrimas legitimam as nossas." },
    { id: "tri11", tipo: "salmo", texto: "Já estou cansado do meu gemido; toda noite faço nadar a minha cama; com as minhas lágrimas, molho o meu leito.", referencia: "Salmos 6:6-9", resumo: "A Bíblia não esconde o lamento profundo. Davi expressa exaustão emocional sem censura — e ainda assim termina na confiança de ser ouvido. Verbalizar a dor diante de Deus é parte da cura." },
    { id: "tri12", tipo: "reflexao", texto: "Pois o Senhor não rejeita para sempre; antes, se entristece, compadece-se segundo a multidão das suas misericórdias.", referencia: "Lamentações 3:31-33", resumo: "Mesmo nos vales mais profundos, a rejeição de Deus nunca é definitiva. Sua compaixão é maior que qualquer disciplina. A esperança volta porque Sua misericórdia é abundante." },
    { id: "tri13", tipo: "salmo", texto: "Tem compaixão de mim, Senhor, porque estou angustiado; consumidos estão de tristeza os meus olhos.", referencia: "Salmos 31:9-10", resumo: "Davi descreve dor física causada pela tristeza emocional. A Bíblia reconhece esse impacto integral. O caminho é pedir compaixão a Deus, que entende corpo e alma." },
    { id: "tri14", tipo: "versiculo", texto: "Bendito seja o Deus de toda consolação, que nos conforta em toda a nossa tribulação.", referencia: "2 Coríntios 1:3-4", resumo: "O consolo recebido se transforma em consolo oferecido. Deus nos cuida e através de nós cuida de outros. Nossa dor pode virar canal de cura para alguém amanhã." },
    { id: "tri15", tipo: "salmo", texto: "Tu contaste as minhas aflições; recolhe as minhas lágrimas no teu odre.", referencia: "Salmos 56:8", resumo: "Imagem belíssima: Deus guarda cada lágrima como tesouro. Nada do que sofremos é desperdiçado ou ignorado. Cada gota tem sentido aos olhos do Pai." },
    { id: "tri16", tipo: "versiculo", texto: "Era desprezado e o mais rejeitado entre os homens; homem de dores e que sabe o que é padecer.", referencia: "Isaías 53:3-4", resumo: "Cristo é descrito como homem de dores. Quando sofremos, encontramos um Salvador que não é distante — Ele conhece por experiência o que é a tristeza." },
    { id: "tri17", tipo: "salmo", texto: "Até quando, Senhor? Para sempre te esquecerás de mim? Até quando esconderás de mim o rosto?", referencia: "Salmos 13:1-2", resumo: "A Bíblia dá voz à pergunta amarga. Davi não é punido por isso — é registrado. Permitir-se questionar sem perder a fé é parte do amadurecimento espiritual." },
    { id: "tri18", tipo: "versiculo", texto: "Tomai sobre vós o meu jugo e aprendei de mim, porque sou manso e humilde de coração.", referencia: "Mateus 11:28-29", resumo: "Jesus oferece descanso real à alma cansada. O jugo dEle é diferente: leve, suave, treinado por mansidão. Aprender com Ele é encontrar paz mesmo nas dores." },
    { id: "tri19", tipo: "salmo", texto: "Tu, que me tens feito ver muitas e penosas tribulações, me restaurarás ainda a vida.", referencia: "Salmos 71:20", resumo: "Mesmo após muitas tribulações, o salmista mantém a expectativa de restauração. Deus que permitiu o vale também conduz à recuperação. A vida não termina na dor." },
    { id: "tri20", tipo: "versiculo", texto: "A vossa tristeza se converterá em alegria.", referencia: "João 16:20", resumo: "Jesus promete não apenas trocar a tristeza, mas convertê-la. A própria dor passa por uma alquimia divina que produz alegria mais profunda do que a anterior." },
    { id: "tri21", tipo: "salmo", texto: "Senhor, Deus da minha salvação, dia e noite clamo na tua presença.", referencia: "Salmos 88:1-2", resumo: "O salmo mais sombrio da Bíblia ainda começa com 'Senhor, Deus da minha salvação'. Mesmo no escuro, mantemos o endereço da oração. Isso, em si, já é fé." },
    { id: "tri22", tipo: "versiculo", texto: "Os sofrimentos do tempo presente não podem ser comparados com a glória a ser revelada em nós.", referencia: "Romanos 8:18", resumo: "Paulo coloca o sofrimento na balança da eternidade. A dor presente é real, mas finita. A glória futura supera infinitamente o peso atual." },
    { id: "tri23", tipo: "salmo", texto: "Os que com lágrimas semeiam com júbilo ceifarão.", referencia: "Salmos 126:5-6", resumo: "Lágrimas semeadas com fé produzem colheita de alegria. Nada do que choramos diante de Deus é perdido. A colheita pode demorar, mas vem." },
    { id: "tri24", tipo: "reflexao", texto: "Melhor é ir à casa onde há luto do que ir à casa onde há banquete, pois naquela está o fim de todos os homens.", referencia: "Eclesiastes 7:3", resumo: "O luto tem o que o entretenimento não tem: profundidade. Ele nos ensina sobre a vida, sobre Deus e sobre o que realmente importa. A dor é mestra silenciosa." },
    { id: "tri25", tipo: "salmo", texto: "Senhor, diante de ti está todo o meu desejo, e o meu gemido não te é oculto.", referencia: "Salmos 38:9", resumo: "Deus enxerga e ouve o gemido que ninguém mais percebe. Você não precisa traduzir sua dor em palavras bonitas — Ele entende mesmo o gemido." },
    { id: "tri26", tipo: "versiculo", texto: "Tornarei o seu pranto em alegria, eu os consolarei e os alegrarei em vez da sua tristeza.", referencia: "Jeremias 31:13", resumo: "Promessa de troca: pranto por alegria, tristeza por consolo. Deus se compromete pessoalmente com essa transformação no tempo dEle." },
    { id: "tri27", tipo: "salmo", texto: "Preciosa é à vista do Senhor a morte dos seus santos.", referencia: "Salmos 116:15", resumo: "Em meio ao luto, esta verdade consola: Deus valoriza profundamente a vida dos que partem em fé. Eles não estão perdidos — estão preciosos diante dEle." },
    { id: "tri28", tipo: "versiculo", texto: "A nossa leve e momentânea tribulação produz para nós eterno peso de glória, acima de toda comparação.", referencia: "2 Coríntios 4:17", resumo: "O que parece pesado e longo é, na perspectiva eterna, leve e momentâneo. E está produzindo algo de valor incomparável. A dor tem propósito." },
    { id: "tri29", tipo: "salmo", texto: "Senhor, escuta a minha oração, e chegue a ti o meu clamor.", referencia: "Salmos 102:1-2", resumo: "Salmo do aflito, modelo de oração para dias pesados. Ele não pede para sair da dor primeiro — pede para ser ouvido. Ser ouvido por Deus já é metade da cura." },
    { id: "tri30", tipo: "versiculo", texto: "O Espírito do Senhor Deus está sobre mim... para consolar todos os que choram, para conceder consolo aos que choram em Sião.", referencia: "Isaías 61:1-3", resumo: "Profecia messiânica que Jesus aplicou a Si mesmo. A missão dEle inclui especificamente consolar quem chora e trocar cinza por enfeite, óleo de alegria por luto." },
    { id: "tri31", tipo: "versiculo", texto: "Bem-aventurados os que choram, porque serão consolados.", referencia: "Mateus 5:4", resumo: "Jesus honra o choro. Tristeza não é fraqueza — é caminho para consolo divino real." },
    { id: "tri32", tipo: "salmo", texto: "Perto está o Senhor dos que têm o coração quebrantado.", referencia: "Salmos 34:18", resumo: "Quebrantamento atrai proximidade divina. Onde outros se afastam, Deus se aproxima." },
    { id: "tri33", tipo: "versiculo", texto: "Chorai com os que choram.", referencia: "Romanos 12:15", resumo: "Tristeza é para ser compartilhada, não escondida. Comunidade multiplica cura." },
    { id: "tri34", tipo: "salmo", texto: "As lágrimas duram uma noite, mas a alegria vem pela manhã.", referencia: "Salmos 30:5", resumo: "Tristeza tem tempo de expiração. Deus governa amanheceres — cada um traz alívio novo." },
    { id: "tri35", tipo: "versiculo", texto: "Deus enxugará dos seus olhos toda lágrima.", referencia: "Apocalipse 21:4", resumo: "Promessa final: cada lágrima é contada e será enxugada pessoalmente por Deus." },
    { id: "tri36", tipo: "salmo", texto: "Não abandonarei os órfãos.", referencia: "João 14:18", resumo: "Jesus promete não deixar sozinho. Tristeza tem companhia divina permanente." },
    { id: "tri37", tipo: "reflexao", texto: "Deus é o Pai das misericórdias e o Deus de toda consolação.", referencia: "2 Coríntios 1:3", resumo: "Deus especialista em consolo. Toda tristeza encontra Nele um Pai que sabe consolar." },
    { id: "tri38", tipo: "versiculo", texto: "Quando eu passar pelas águas, estarei contigo.", referencia: "Isaías 43:2", resumo: "Deus não promete sem águas — promete presença nas águas. Tristeza atravessada com Ele." },
    { id: "tri39", tipo: "salmo", texto: "Recolhe as minhas lágrimas no teu odre.", referencia: "Salmos 56:8", resumo: "Deus guarda cada lágrima como tesouro. Nenhum choro é desperdiçado ou ignorado." },
    { id: "tri40", tipo: "versiculo", texto: "Vinde a mim, todos os que estais cansados e sobrecarregados.", referencia: "Mateus 11:28", resumo: "Cansaço emocional tem porta aberta em Cristo. Convite direto para descarregar." },
    { id: "tri41", tipo: "salmo", texto: "Amaste-me com amor eterno; por isso, com amor te atraí.", referencia: "Jeremias 31:3", resumo: "Amor que não termina segura na tristeza. Base sólida para atravessar o vale." },
    { id: "tri42", tipo: "versiculo", texto: "Não vos entristeçais como os outros, que não têm esperança.", referencia: "1 Tessalonicenses 4:13", resumo: "Tristeza cristã tem esperança dentro. Não nega dor — mas não termina nela." },
    { id: "tri43", tipo: "salmo", texto: "Espera no Senhor, anima-te.", referencia: "Salmos 27:14", resumo: "Ordem gentil: esperar e animar. Ambos são atos de fé no meio da tristeza." },
    { id: "tri44", tipo: "reflexao", texto: "Tenho-vos dito estas coisas para que em mim tenhais paz.", referencia: "João 16:33", resumo: "Paz de Cristo coexiste com aflição. Não elimina tristeza — sustenta dentro dela." },
    { id: "tri45", tipo: "versiculo", texto: "Ele foi ferido pelas nossas transgressões.", referencia: "Isaías 53:5", resumo: "Cristo carregou tristeza no lugar dos Seus. Não estamos sozinhos — Ele já passou." },
    { id: "tri46", tipo: "salmo", texto: "Bendito seja Deus, o Pai que nos consola.", referencia: "2 Coríntios 1:3-4", resumo: "Consolação é ministério de Deus. Ele mesmo consola — direto, sem intermediário." },
    { id: "tri47", tipo: "versiculo", texto: "Aquele que semeia em lágrimas com júbilo ceifará.", referencia: "Salmos 126:5", resumo: "Lágrimas viram semente. Tristeza é solo fértil quando entregue a Deus." },
    { id: "tri48", tipo: "salmo", texto: "Levanto os meus olhos para os montes; de onde me virá o socorro?", referencia: "Salmos 121:1-2", resumo: "Erguer olhos é ato de fé. Socorro vem do Deus dos montes, não das circunstâncias." },
    { id: "tri49", tipo: "versiculo", texto: "Não temais, porque eu vim para vos consolar.", referencia: "João 14:16-18", resumo: "Espírito Santo é Consolador enviado. Tristeza tem Aquele que ministra por dentro." },
    { id: "tri50", tipo: "salmo", texto: "Tu, Senhor, és escudo em derredor de mim; és a minha glória e o que exalta a minha cabeça.", referencia: "Salmos 3:3", resumo: "Deus levanta cabeça caída. Tristeza abaixa — Ele reergue com dignidade." },
    { id: "tri51", tipo: "versiculo", texto: "O Filho do homem veio buscar e salvar o que se havia perdido.", referencia: "Lucas 19:10", resumo: "Cristo busca ativamente. Tristeza de sentir-se perdido é atendida por quem procura." },
    { id: "tri52", tipo: "salmo", texto: "Alegra a alma do teu servo, porque a ti, Senhor, elevo a minha alma.", referencia: "Salmos 86:4", resumo: "Elevar alma a Deus é ato ativo. Alegria vem em resposta, não em antecipação." },
    { id: "tri53", tipo: "versiculo", texto: "O Espírito ajuda em nossas fraquezas.", referencia: "Romanos 8:26", resumo: "Ajuda vem por dentro. Tristeza tem Advogado que ora quando faltam palavras." },
    { id: "tri54", tipo: "salmo", texto: "Restaura a minha alma.", referencia: "Salmos 23:3", resumo: "Pastor restaura — é papel Dele. Almas cansadas encontram cura na Sua liderança." },
    { id: "tri55", tipo: "versiculo", texto: "Não vos deixarei órfãos; voltarei para vós outros.", referencia: "João 14:18", resumo: "Promessa dupla: não abandono e retorno. Tristeza de ausência é temporária." },
    { id: "tri56", tipo: "salmo", texto: "O choro pode durar uma noite, mas a alegria vem pela manhã.", referencia: "Salmos 30:5", resumo: "Choro tem prazo. Manhã traz alegria — porque manhã pertence a Deus." },
    { id: "tri57", tipo: "versiculo", texto: "Nele temos a redenção pelo seu sangue, a remissão dos pecados.", referencia: "Efésios 1:7", resumo: "Redenção pessoal apaga tristeza de culpa. Sangue de Cristo é lavagem completa." },
    { id: "tri58", tipo: "salmo", texto: "Clama a mim, e responder-te-ei.", referencia: "Jeremias 33:3", resumo: "Clamor sempre encontra resposta. Tristeza que grita é ouvida — sempre." },
    { id: "tri59", tipo: "versiculo", texto: "Cristo ressuscitou dos mortos, sendo ele as primícias dos que dormem.", referencia: "1 Coríntios 15:20", resumo: "Ressurreição desativa tristeza última. Morte tem palavra final revertida em Cristo." },
    { id: "tri60", tipo: "salmo", texto: "O Senhor é bom, é fortaleza no dia da angústia.", referencia: "Naum 1:7", resumo: "Angústia tem fortaleza. Deus é abrigo específico para momentos ruins." },
    { id: "tri61", tipo: "versiculo", texto: "Tenho compaixão desta multidão.", referencia: "Marcos 8:2", resumo: "Compaixão de Cristo é reação genuína — não performance. Tristeza é vista." },
    { id: "tri62", tipo: "salmo", texto: "O Senhor te abençoará e te guardará.", referencia: "Números 6:24", resumo: "Bênção sacerdotal é sobre você. Tristeza é envolvida em bênção declarada." },
    { id: "tri63", tipo: "versiculo", texto: "Estarei convosco todos os dias até à consumação do século.", referencia: "Mateus 28:20", resumo: "Todos os dias — inclui os tristes. Presença não falta nem no pior." },
    { id: "tri64", tipo: "salmo", texto: "O Senhor é o meu pastor; nada me faltará.", referencia: "Salmos 23:1", resumo: "Ter pastor perfeito é ter suficiência garantida. Tristeza de falta cede." },
    { id: "tri65", tipo: "versiculo", texto: "Ele te sustenta, e não permitirá que jamais o justo seja abalado.", referencia: "Salmos 55:22", resumo: "Sustento contínuo. Tristeza pode abalar sentimento — não a base." },
    { id: "tri66", tipo: "salmo", texto: "Deus é o meu forte refúgio.", referencia: "Salmos 71:7", resumo: "Refúgio forte suporta o peso da tristeza sem ceder. Base confiável." },
    { id: "tri67", tipo: "versiculo", texto: "Ainda que meu pai e minha mãe me abandonem, o Senhor me acolherá.", referencia: "Salmos 27:10", resumo: "Deus preenche abandonos humanos. Tristeza de ser rejeitado tem cura Nele." },
    { id: "tri68", tipo: "salmo", texto: "Ele me tira do lodo profundo.", referencia: "Salmos 40:2", resumo: "Tirar do lodo — trabalho ativo de Deus. Tristeza afundada tem quem puxe." },
    { id: "tri69", tipo: "versiculo", texto: "Sofri contigo em tuas tribulações.", referencia: "Isaías 63:9", resumo: "Deus não observa distante — sofre junto. Tristeza é compartilhada Nele." },
    { id: "tri70", tipo: "salmo", texto: "O justo tem muitas aflições, mas de todas o livra o Senhor.", referencia: "Salmos 34:19", resumo: "Aflições existem — livramento também. Tristeza tem contrapartida garantida." },
    { id: "tri71", tipo: "versiculo", texto: "Vinde a mim, e eu vos aliviarei.", referencia: "Mateus 11:28", resumo: "Alívio prometido diretamente. Tristeza tem endereço para receber descanso." },
    { id: "tri72", tipo: "salmo", texto: "Bendize, ó minha alma, ao Senhor.", referencia: "Salmos 103:1", resumo: "Ordenar louvor à alma triste é fé em ação. Muda a atmosfera interna." },
    { id: "tri73", tipo: "versiculo", texto: "Deus é fiel; não permitirá que sejais tentados além das vossas forças.", referencia: "1 Coríntios 10:13", resumo: "Tristeza tem limite fixado por Deus. Nunca passa da medida da graça." },
    { id: "tri74", tipo: "salmo", texto: "Ele guardará os pés dos seus santos.", referencia: "1 Samuel 2:9", resumo: "Deus guarda passos. Tristeza não te faz tropeçar quando Ele guarda." },
    { id: "tri75", tipo: "versiculo", texto: "Se sofremos, também com ele reinaremos.", referencia: "2 Timóteo 2:12", resumo: "Sofrimento hoje conecta a reinado futuro. Tristeza ganha significado." },
    { id: "tri76", tipo: "salmo", texto: "Habitarei na casa do Senhor por longos dias.", referencia: "Salmos 23:6", resumo: "Destino final é a casa de Deus. Tristeza é passagem, não destino." },
    { id: "tri77", tipo: "versiculo", texto: "A minha graça te basta.", referencia: "2 Coríntios 12:9", resumo: "Graça suficiente cobre cada tristeza. Sempre há o bastante Nele." },
    { id: "tri78", tipo: "salmo", texto: "Meu Deus, meu Deus, por que me desamparaste?", referencia: "Salmos 22:1", resumo: "Até tristeza extrema tem lugar diante de Deus. Cristo mesmo orou assim." },
    { id: "tri79", tipo: "versiculo", texto: "Como o Pai me amou, também eu vos amei.", referencia: "João 15:9", resumo: "Amor infinito flui para dentro. Tristeza é abraçada por amor cósmico." },
    { id: "tri80", tipo: "salmo", texto: "Aumenta as tribulações do meu coração; tira-me das minhas angústias.", referencia: "Salmos 25:17", resumo: "Petição sincera vale mais que aparência. Deus escuta oração de tristeza real." },
    { id: "tri81", tipo: "versiculo", texto: "O Espírito e a noiva dizem: Vem!", referencia: "Apocalipse 22:17", resumo: "Tristeza terrena termina no retorno. Expectativa acesa alivia o presente." },
    { id: "tri82", tipo: "salmo", texto: "Volta, ó Senhor, livra a minha alma.", referencia: "Salmos 6:4", resumo: "Pedir livramento é fé. Tristeza que ora ao Deus vivo já começa a curar." },
    { id: "tri83", tipo: "versiculo", texto: "O Deus da esperança vos encha de todo gozo e paz.", referencia: "Romanos 15:13", resumo: "Ele mesmo enche — não pede que você produza. Tristeza cede diante da fonte divina." },
    { id: "tri84", tipo: "salmo", texto: "Comigo estás; o teu bordão me consola.", referencia: "Salmos 23:4", resumo: "Bordão do pastor é ferramenta de consolo. Tristeza sente disciplina como amor." },
    { id: "tri85", tipo: "versiculo", texto: "Nada nos separará do amor de Deus.", referencia: "Romanos 8:39", resumo: "Amor inseparável. Tristeza tenta sussurrar afastamento — mas é mentira." },
    { id: "tri86", tipo: "salmo", texto: "Sara os quebrantados de coração e lhes cura as feridas.", referencia: "Salmos 147:3", resumo: "Cirurgião divino. Feridas de tristeza têm médico especializado em quebrantados." },
    { id: "tri87", tipo: "versiculo", texto: "O Senhor é bom para com os que nele esperam.", referencia: "Lamentações 3:25", resumo: "Esperar em Deus é solo onde a bondade Dele floresce. Tristeza espera com propósito." },
    { id: "tri88", tipo: "salmo", texto: "Ainda que eu ande pelo vale da sombra da morte, não temerei.", referencia: "Salmos 23:4", resumo: "Vale existe — medo não precisa. Tristeza atravessada com companhia divina." },
    { id: "tri89", tipo: "versiculo", texto: "Pai, nas tuas mãos entrego o meu espírito.", referencia: "Lucas 23:46", resumo: "Entregar espírito ao Pai é ato final de confiança. Tristeza tem endereço para descansar." },
    { id: "tri90", tipo: "salmo", texto: "O choroso semeia; o segador colhe cantando.", referencia: "Salmos 126:6", resumo: "Choro tem função — é semente. Tristeza vivida com fé produz colheita." },
    { id: "tri91", tipo: "versiculo", texto: "Deus fez todas as coisas formosas em seu tempo.", referencia: "Eclesiastes 3:11", resumo: "Beleza no tempo certo. Tristeza atual não é palavra final da história de Deus." },
    { id: "tri92", tipo: "salmo", texto: "Meu coração se apega a ti.", referencia: "Salmos 63:8", resumo: "Apego consciente a Deus na tristeza sustenta. Ele apoia com destra." },
    { id: "tri93", tipo: "versiculo", texto: "O nosso homem interior se renova de dia em dia.", referencia: "2 Coríntios 4:16", resumo: "Renovação diária. Tristeza gasta o exterior — interior é revigorado por Deus." },
    { id: "tri94", tipo: "salmo", texto: "O Senhor governa; alegre-se a terra.", referencia: "Salmos 97:1", resumo: "Governo divino é motivo de alegria mesmo em tristeza. Alguém competente comanda." },
    { id: "tri95", tipo: "versiculo", texto: "Ele carregou as nossas tristezas.", referencia: "Isaías 53:4", resumo: "Cristo assumiu tristezas humanas. Não caminhamos com peso que não seja compartilhado." },
    { id: "tri96", tipo: "salmo", texto: "Todos os meus ossos dirão: Senhor, quem é como tu?", referencia: "Salmos 35:10", resumo: "Louvor do corpo inteiro. Tristeza rendida transforma em adoração admirativa." },
    { id: "tri97", tipo: "versiculo", texto: "Todo aquele que Nele crê recebe remissão dos pecados.", referencia: "Atos 10:43", resumo: "Perdão liberta de tristeza de culpa. Base para nova temporada." },
    { id: "tri98", tipo: "salmo", texto: "A minha carne e o meu coração desfalecem; mas Deus é a força do meu coração.", referencia: "Salmos 73:26", resumo: "Corpo pode falhar — Deus sustenta o interior. Tristeza física tem base espiritual firme." },
    { id: "tri99", tipo: "versiculo", texto: "O Deus da paz seja com todos vós.", referencia: "Romanos 15:33", resumo: "Bênção coletiva de paz. Tristeza é abraçada em oração comunitária." },
    { id: "tri100", tipo: "salmo", texto: "O Senhor é a minha luz e a minha salvação.", referencia: "Salmos 27:1", resumo: "Luz dissipa trevas de tristeza. Salvação é ativa — não passiva." },
    { id: "tri101", tipo: "versiculo", texto: "Vós vos entristecereis, mas a vossa tristeza se converterá em alegria.", referencia: "João 16:20", resumo: "Conversão prometida. Tristeza é matéria-prima de alegria futura." },
    { id: "tri102", tipo: "salmo", texto: "Longe estejam de mim os que praticam iniquidade.", referencia: "Salmos 6:8", resumo: "Tristeza pede afastar más companhias. Cuidado com influência preserva alma." },
    { id: "tri103", tipo: "versiculo", texto: "Tudo posso naquele que me fortalece.", referencia: "Filipenses 4:13", resumo: "Tudo — inclui atravessar tristeza. Fortalecimento vem de dentro." },
    { id: "tri104", tipo: "salmo", texto: "Ele conhece o pó de que somos formados.", referencia: "Salmos 103:14", resumo: "Deus lembra da fragilidade humana. Tristeza é vista com compreensão." },
    { id: "tri105", tipo: "versiculo", texto: "Cristo é o mesmo, ontem, hoje e eternamente.", referencia: "Hebreus 13:8", resumo: "Constância divina em mundo mutante. Tristeza sobre mudanças cede diante do imutável." },
    { id: "tri106", tipo: "salmo", texto: "Ao Senhor, ó minha alma, elevo os meus olhos.", referencia: "Salmos 25:1", resumo: "Olhos elevados desviam da tristeza que consome quando fixamos nela." },
    { id: "tri107", tipo: "versiculo", texto: "O que se comprometeu convosco é fiel.", referencia: "1 Tessalonicenses 5:24", resumo: "Deus cumpre. Tristeza sobre promessas não cumpridas cede diante da fidelidade." },
    { id: "tri108", tipo: "salmo", texto: "Levar-me-á, e junto de si tem morada preparada.", referencia: "João 14:2-3", resumo: "Casa preparada aguarda. Tristeza terrena tem alívio na esperança do lar eterno." },
    { id: "tri109", tipo: "versiculo", texto: "Ele me tirou de um poço horrível.", referencia: "Salmos 40:2", resumo: "Deus especialista em tirar de fundos escuros. Tristeza abissal tem quem alcance." },
    { id: "tri110", tipo: "salmo", texto: "Feliz o homem cuja força está em ti.", referencia: "Salmos 84:5", resumo: "Força de Deus como fonte pessoal. Tristeza esgota — Deus repõe." },
  ],
  "Sozinho": [
    { id: "soz1", tipo: "versiculo", texto: "E eu estarei sempre convosco, até a consumação dos séculos.", referencia: "Mateus 28:20", resumo: "As últimas palavras de Jesus aos discípulos antes da ascensão. 'Sempre' não admite exceções. Sua presença é real através do Espírito Santo. Você nunca está realmente sozinho, mesmo quando sente assim." },
    { id: "soz2", tipo: "versiculo", texto: "Ele nunca te deixará, nunca te abandonará. Não tenha medo!", referencia: "Deuteronômio 31:8", resumo: "Moisés transmite a Josué em momento de transição enorme. Deus não é como pessoas que mudam de opinião ou se cansam. Sua fidelidade depende do Seu caráter imutável, não do nosso desempenho." },
    { id: "soz3", tipo: "salmo", texto: "Ainda que meu pai e minha mãe me abandonem, o Senhor me acolherá.", referencia: "Salmos 27:10", resumo: "Davi aponta para as relações mais fundamentais — e declara que o cuidado de Deus é superior. Para quem viveu abandono, existe um Pai que sempre acolhe." },
    { id: "soz4", tipo: "versiculo", texto: "Não vos deixarei órfãos; voltarei para vós outros.", referencia: "João 14:18", resumo: "Jesus prepara os discípulos para Sua partida prometendo o Espírito Santo. Você tem um Pai presente, um Consolador ativo, uma companhia interior que nunca se ausenta." },
    { id: "soz5", tipo: "versiculo", texto: "De modo nenhum te deixarei, nunca jamais te abandonarei.", referencia: "Hebreus 13:5", resumo: "A construção grega é enfática, com múltiplas negativas. Deus não apenas escolhe ficar — Ele é incapaz de nos abandonar. Para quem se sente esquecido, essa garantia é uma âncora." },
    { id: "soz6", tipo: "salmo", texto: "Perto está o Senhor de todos os que o invocam, de todos os que o invocam em verdade.", referencia: "Salmos 145:18", resumo: "Basta um chamado sincero para sentir a aproximação de Deus. A solidão se desfaz quando lembramos que o Pai está a um suspiro de distância." },
    { id: "soz7", tipo: "salmo", texto: "Ele me faz repousar em pastos verdejantes; leva-me para junto das águas de descanso.", referencia: "Salmos 23:2", resumo: "Mesmo a ovelha solitária permanece sob cuidados do Pastor. Ele guia a lugares de descanso e provisão. A solidão se transforma em comunhão quando reconhecemos quem conduz a jornada." },
    { id: "soz8", tipo: "versiculo", texto: "Eis que estou contigo e te guardarei por onde quer que fores.", referencia: "Gênesis 28:15", resumo: "Deus diz isso a Jacó, em fuga e sozinho no deserto. Nos momentos de exílio pessoal, a presença divina é a companhia mais constante. Onde quer que você esteja, Ele está." },
    { id: "soz9", tipo: "salmo", texto: "Tu és o meu refúgio; tu me preservas da angústia.", referencia: "Salmos 32:7", resumo: "Refúgio é lugar seguro onde podemos descansar. Deus se oferece como esse lugar para a alma isolada. Quando o mundo parece vazio, Ele continua sendo o abrigo certo." },
    { id: "soz10", tipo: "salmo", texto: "Para onde me irei do teu Espírito? Para onde fugirei da tua face?", referencia: "Salmos 139:7", resumo: "Davi celebra o que normalmente seria assustador: é impossível escapar da presença de Deus. Para quem se sente solitário, isso vira a melhor notícia — Ele está em todo lugar onde estamos." },
    { id: "soz11", tipo: "salmo", texto: "Deus faz que o solitário viva em família.", referencia: "Salmos 68:6", resumo: "Deus se importa especificamente com solitários — e os coloca em comunidade. Pedir-Lhe famílias espirituais, igreja, amizades verdadeiras é uma oração que Ele se compraz em responder." },
    { id: "soz12", tipo: "versiculo", texto: "Estou bem certo de que nem a morte, nem a vida... nem qualquer outra criatura poderá separar-nos do amor de Deus.", referencia: "Romanos 8:38-39", resumo: "Paulo lista praticamente tudo o que poderia separar — e descarta cada item. Nenhuma força no universo é capaz de tirar você do amor de Deus. Esse amor é a companhia mais constante que existe." },
    { id: "soz13", tipo: "versiculo", texto: "E eu rogarei ao Pai, e ele vos dará outro Consolador, a fim de que esteja para sempre convosco.", referencia: "João 14:16", resumo: "Jesus envia o Espírito como Consolador permanente. 'Para sempre' é literal — Ele habita no crente como presença interior constante. A solidão tem antídoto vivendo dentro de você." },
    { id: "soz14", tipo: "salmo", texto: "Olha para mim e tem compaixão de mim, porque estou solitário e aflito.", referencia: "Salmos 25:16", resumo: "Davi não esconde a solidão; ele a leva diretamente a Deus. Pedir olhar e compaixão é uma oração legítima e ouvida. A solidão pode virar intimidade quando se torna oração." },
    { id: "soz15", tipo: "versiculo", texto: "Não temas, porque eu te remi; chamei-te pelo teu nome, tu és meu.", referencia: "Isaías 43:1-2", resumo: "Deus te chama pelo nome, não como número. Você pertence a Ele. Mesmo nas águas e nos rios da vida, Ele caminha junto. Pertencer a Deus é a cura definitiva da solidão." },
    { id: "soz16", tipo: "salmo", texto: "Todavia, estou sempre contigo, pois me sustentas pela mão direita.", referencia: "Salmos 73:23", resumo: "O salmista descobre que mesmo nos momentos mais confusos da vida, Deus o segura pela mão direita. Há uma mão divina segurando a sua agora, mesmo que você não sinta." },
    { id: "soz17", tipo: "versiculo", texto: "Onde estiverem dois ou três reunidos em meu nome, ali estou no meio deles.", referencia: "Mateus 18:20", resumo: "Jesus promete presença concreta onde há comunhão. Buscar irmãos na fé não é luxo, é necessidade. A presença de Cristo se manifesta também através do corpo dEle." },
    { id: "soz18", tipo: "salmo", texto: "Tenho posto o Senhor continuamente diante de mim; estando ele à minha direita, não serei abalado.", referencia: "Salmos 16:8", resumo: "Manter Deus continuamente diante dos olhos é prática. Quem o faz descobre estabilidade — não por estar acompanhado de pessoas, mas porque a Presença divina é constante." },
    { id: "soz19", tipo: "versiculo", texto: "Mas o Senhor esteve comigo e me revestiu de forças.", referencia: "2 Timóteo 4:17", resumo: "Paulo escreve isso da prisão, abandonado por amigos. Mesmo nos momentos de mais desamparo humano, ele afirma: o Senhor esteve comigo. A presença divina supera ausências humanas." },
    { id: "soz20", tipo: "salmo", texto: "Não há ninguém que me conheça; refúgio não há mais para mim. Clamo a ti, Senhor.", referencia: "Salmos 142:4-5", resumo: "Davi descreve uma solidão extrema — e ainda assim clama. A oração funciona mesmo quando ninguém ao redor parece se importar. Deus continua sendo abrigo e quinhão." },
    { id: "soz21", tipo: "versiculo", texto: "Pode uma mulher esquecer-se do filho que ainda mama? Ainda que esta viesse a esquecer-se, eu não me esquecerei de ti.", referencia: "Isaías 49:15-16", resumo: "Deus se compara — e se supera — em relação ao amor materno mais profundo. Você está gravado nas palmas das Suas mãos. Esquecimento de Deus em relação a você é impossível." },
    { id: "soz22", tipo: "versiculo", texto: "O que vem a mim, de modo nenhum o lançarei fora.", referencia: "João 6:37", resumo: "Jesus garante: quem se aproxima dEle nunca será rejeitado. Esse 'de modo nenhum' não tem exceções. Para quem teme rejeição, este versículo é fundamental." },
    { id: "soz23", tipo: "salmo", texto: "Clamam os justos, e o Senhor os escuta e os livra de todas as suas tribulações.", referencia: "Salmos 34:17", resumo: "Deus escuta. Esse fato simples muda a experiência da solidão. Mesmo quando ninguém mais ouve, Ele ouve — e age." },
    { id: "soz24", tipo: "versiculo", texto: "O Senhor, teu Deus, está no meio de ti, poderoso para te salvar; ele se alegra com cânticos.", referencia: "Sofonias 3:17", resumo: "Deus não apenas está presente — Ele se alegra com você. Imagine isso quando se sentir só: Alguém poderoso celebra a sua existência com cânticos." },
    { id: "soz25", tipo: "salmo", texto: "Em ti, Senhor, confiarão os que conhecem o teu nome, porque tu, Senhor, nunca desamparaste os que te buscam.", referencia: "Salmos 9:10", resumo: "Quem conhece o caráter de Deus confia. A história inteira da Bíblia mostra: Ele nunca desampara quem busca. Esse padrão se aplica também a você." },
    { id: "soz26", tipo: "reflexao", texto: "Não estava o Senhor no terremoto; e, depois do terremoto, um fogo; mas também o Senhor não estava no fogo; e, depois do fogo, uma voz tranquila e suave.", referencia: "1 Reis 19:11-12", resumo: "Elias se sentiu sozinho a ponto de desejar a morte. Deus apareceu não no espetáculo, mas no sussurro. Quando se sentir só, escute o sussurro — Ele está mais próximo do que parece." },
    { id: "soz27", tipo: "salmo", texto: "Velo e sou como pardal solitário no telhado.", referencia: "Salmos 102:7", resumo: "A Bíblia dá voz à imagem da solidão extrema. Mas o salmo termina com Deus ouvindo, restaurando, eternizando. Mesmo o pardal solitário tem o olhar do Pai." },
    { id: "soz28", tipo: "versiculo", texto: "Eis que estou à porta e bato; se alguém ouvir a minha voz e abrir a porta, entrarei em sua casa.", referencia: "Apocalipse 3:20", resumo: "Jesus se oferece como companhia íntima. Ele bate, espera, entra para jantar — imagem de comunhão profunda. Ninguém precisa estar sozinho à mesa da própria vida." },
    { id: "soz29", tipo: "salmo", texto: "Na minha angústia, invoquei o Senhor, e ele me ouviu.", referencia: "Salmos 18:6", resumo: "Quando invocado, Deus responde. Esse é o padrão consistente das Escrituras. Sua angústia não cai no vazio." },
    { id: "soz30", tipo: "versiculo", texto: "Quem nos separará do amor de Cristo? Será tribulação, ou angústia, ou perseguição?", referencia: "Romanos 8:35", resumo: "Paulo lista as forças que tentariam isolar — e nega o poder delas. Nada do que você está vivendo agora consegue separar você do amor de Cristo." },
    { id: "soz31", tipo: "versiculo", texto: "Não te deixarei, nem te desampararei.", referencia: "Josué 1:5", resumo: "Dupla promessa: não deixar (partir) e não desamparar (esquecer). Solidão é impossível para quem tem Deus." },
    { id: "soz32", tipo: "salmo", texto: "Ainda que meu pai e minha mãe me abandonem, o Senhor me acolherá.", referencia: "Salmos 27:10", resumo: "Deus preenche vazios humanos. Onde há falha, Ele é presença ativa." },
    { id: "soz33", tipo: "versiculo", texto: "Chegar-me-ei também a ti, para que sejas comigo onde eu estou.", referencia: "João 14:3", resumo: "Jesus prepara lugar para estar junto. Solidão eterna não é destino dos Seus." },
    { id: "soz34", tipo: "salmo", texto: "O Senhor está perto de todos os que o invocam em verdade.", referencia: "Salmos 145:18", resumo: "Proximidade condicional à sinceridade. Chamar com verdade é receber presença certa." },
    { id: "soz35", tipo: "reflexao", texto: "Onde estão dois ou três reunidos em meu nome, ali estou eu no meio deles.", referencia: "Mateus 18:20", resumo: "Reunião em nome de Cristo garante Sua presença. Solidão desmontada pela comunhão." },
    { id: "soz36", tipo: "versiculo", texto: "Sou contigo até à consumação do século.", referencia: "Mateus 28:20", resumo: "Presença durando até o fim. Nenhum momento fica descoberto de companhia divina." },
    { id: "soz37", tipo: "salmo", texto: "Se subir ao céu, tu ali estás.", referencia: "Salmos 139:8", resumo: "Deus onipresente. Nenhum lugar remove Sua companhia — solidão geográfica é ilusão." },
    { id: "soz38", tipo: "versiculo", texto: "Vos amo com amor eterno.", referencia: "Jeremias 31:3", resumo: "Amor eterno é companhia eterna. Solidão é combatida no coração antes das circunstâncias." },
    { id: "soz39", tipo: "salmo", texto: "O Senhor é a minha porção.", referencia: "Salmos 73:26", resumo: "Ter Deus como herança é ter Alguém para sempre. Solidão perde base." },
    { id: "soz40", tipo: "versiculo", texto: "O Consolador vos ensinará todas as coisas.", referencia: "João 14:26", resumo: "Espírito por dentro é presença íntima. Solidão externa não elimina companhia interna." },
    { id: "soz41", tipo: "salmo", texto: "Guiar-te-ei com os meus olhos.", referencia: "Salmos 32:8", resumo: "Olhar constante orienta. Solidão de não saber para onde ir tem Guia dedicado." },
    { id: "soz42", tipo: "versiculo", texto: "Eu vos amei como o Pai me amou.", referencia: "João 15:9", resumo: "Amor divino fluindo. Solidão relacional cede diante desse amor infinito." },
    { id: "soz43", tipo: "salmo", texto: "Comigo estás; o teu bordão me consola.", referencia: "Salmos 23:4", resumo: "Companhia com ferramenta. Deus não só está — Ele age para consolar." },
    { id: "soz44", tipo: "reflexao", texto: "Sou o Deus que vê.", referencia: "Gênesis 16:13", resumo: "Deus vê Agar no deserto. Solidão vista por Deus deixa de ser solidão total." },
    { id: "soz45", tipo: "versiculo", texto: "Deus é fiel, o qual não permitirá.", referencia: "1 Coríntios 10:13", resumo: "Fidelidade divina cuida além do que sentimos. Solidão nunca é abandono real." },
    { id: "soz46", tipo: "salmo", texto: "O Senhor está do meu lado; não temerei.", referencia: "Salmos 118:6", resumo: "Lado ocupado por Deus. Solidão de estar sozinho contra o mundo — impossível." },
    { id: "soz47", tipo: "versiculo", texto: "Rogarei ao Pai, e ele vos dará outro Consolador.", referencia: "João 14:16", resumo: "Consolador enviado para dentro. Solidão espiritual tem cura permanente." },
    { id: "soz48", tipo: "salmo", texto: "Feliz o povo cujo Deus é o Senhor.", referencia: "Salmos 33:12", resumo: "Pertencer a Deus é fim da solidão essencial. Identidade curada primeiro." },
    { id: "soz49", tipo: "versiculo", texto: "Se Deus é por nós, quem será contra nós?", referencia: "Romanos 8:31", resumo: "Aliado divino. Solidão de estar contra tudo cede diante desse por." },
    { id: "soz50", tipo: "salmo", texto: "Tu me cercas por trás e por diante.", referencia: "Salmos 139:5", resumo: "Deus por todos os lados. Solidão geográfica não sobrevive à onipresença." },
    { id: "soz51", tipo: "versiculo", texto: "Não vos deixarei órfãos.", referencia: "João 14:18", resumo: "Órfão é destino recusado. Solidão de ser deixado é impossível em Cristo." },
    { id: "soz52", tipo: "salmo", texto: "O Senhor guardará a tua saída e a tua entrada.", referencia: "Salmos 121:8", resumo: "Cobertura de porta em porta. Nenhuma partida ou chegada em solidão." },
    { id: "soz53", tipo: "versiculo", texto: "Nele vivemos, nos movemos e existimos.", referencia: "Atos 17:28", resumo: "Existir em Deus. Solidão fundamental é filosoficamente impossível para o crente." },
    { id: "soz54", tipo: "salmo", texto: "Ele me tira do meio dos meus inimigos.", referencia: "2 Samuel 22:49", resumo: "Deus liberta ativamente. Solidão em cerco tem quem intervenha." },
    { id: "soz55", tipo: "versiculo", texto: "Chegai-vos a Deus, e ele se chegará a vós.", referencia: "Tiago 4:8", resumo: "Movimento mútuo. Solidão cede a cada passo de aproximação." },
    { id: "soz56", tipo: "salmo", texto: "Tu és o meu esconderijo.", referencia: "Salmos 32:7", resumo: "Esconderijo é lugar íntimo com Deus. Solidão vira intimidade escolhida." },
    { id: "soz57", tipo: "versiculo", texto: "Ide, portanto, fazei discípulos.", referencia: "Mateus 28:19", resumo: "Chamado missionário. Solidão substituída por propósito comum." },
    { id: "soz58", tipo: "salmo", texto: "Bem-aventurado o homem que teme ao Senhor.", referencia: "Salmos 112:1", resumo: "Temor a Deus produz bem-aventurança. Solidão cede a preenchimento espiritual." },
    { id: "soz59", tipo: "versiculo", texto: "Amados, amemo-nos uns aos outros.", referencia: "1 João 4:7", resumo: "Amor mútuo é remédio de solidão. Iniciar amor recebe amor." },
    { id: "soz60", tipo: "salmo", texto: "Feliz aquele cuja força está em ti.", referencia: "Salmos 84:5", resumo: "Força divina como fonte. Solidão energética tem reabastecimento constante." },
    { id: "soz61", tipo: "versiculo", texto: "Sede fortes e corajosos.", referencia: "Josué 1:9", resumo: "Coragem porque Deus vai contigo. Solidão da missão tem companhia sobrenatural." },
    { id: "soz62", tipo: "salmo", texto: "O Senhor está perto dos que têm o coração quebrantado.", referencia: "Salmos 34:18", resumo: "Quebrantamento atrai proximidade. Solidão de dor tem visita divina." },
    { id: "soz63", tipo: "versiculo", texto: "O amor de Deus é derramado em nosso coração.", referencia: "Romanos 5:5", resumo: "Derramamento por dentro. Solidão emocional recebe irrigação divina." },
    { id: "soz64", tipo: "salmo", texto: "O Senhor te abençoe e te guarde.", referencia: "Números 6:24", resumo: "Bênção pessoal. Solidão de anonimato cede diante da atenção divina." },
    { id: "soz65", tipo: "versiculo", texto: "Confortai-vos uns aos outros.", referencia: "1 Tessalonicenses 4:18", resumo: "Conforto mútuo. Solidão comunitária tem solução em serviço." },
    { id: "soz66", tipo: "salmo", texto: "O Senhor pelejará por vós.", referencia: "Êxodo 14:14", resumo: "Deus luta ao lado. Solidão em batalha é substituída por aliança." },
    { id: "soz67", tipo: "versiculo", texto: "Não temas, porque eu sou contigo.", referencia: "Isaías 41:10", resumo: "Companhia declarada. Solidão de temor recebe presença calmante." },
    { id: "soz68", tipo: "salmo", texto: "Meu Deus, em ti confio.", referencia: "Salmos 25:2", resumo: "Confiança pessoal. Solidão de dúvida cede a certeza relacional." },
    { id: "soz69", tipo: "versiculo", texto: "Rogo-vos que vivais de modo digno da vocação.", referencia: "Efésios 4:1", resumo: "Vocação comum une. Solidão perde solo diante do propósito compartilhado." },
    { id: "soz70", tipo: "salmo", texto: "O Senhor guarda os fiéis.", referencia: "Salmos 31:23", resumo: "Guarda ativa dos fiéis. Solidão vigiada por olhar amoroso." },
    { id: "soz71", tipo: "versiculo", texto: "Eis que estou à porta e bato.", referencia: "Apocalipse 3:20", resumo: "Cristo bate — quer entrar. Solidão convidada a receber presença." },
    { id: "soz72", tipo: "salmo", texto: "Ao Senhor pertence a terra e a sua plenitude.", referencia: "Salmos 24:1", resumo: "Tudo é dEle. Solidão no universo é filosoficamente impossível." },
    { id: "soz73", tipo: "versiculo", texto: "Estarei com a tua boca.", referencia: "Êxodo 4:12", resumo: "Deus com a boca — presença íntima na fala. Solidão no medo de falar tem ajuda." },
    { id: "soz74", tipo: "salmo", texto: "Levantai as vossas cabeças.", referencia: "Salmos 24:7", resumo: "Erguer olhos é ver mais. Solidão baixa — presença de Deus levanta." },
    { id: "soz75", tipo: "versiculo", texto: "O Senhor é o meu ajudador.", referencia: "Hebreus 13:6", resumo: "Ajudador declarado. Solidão de necessidade tem quem responda." },
    { id: "soz76", tipo: "salmo", texto: "O Senhor pastoreia a mim.", referencia: "Salmos 23:1", resumo: "Pastor pessoal. Solidão da ovelha perdida tem quem busque." },
    { id: "soz77", tipo: "versiculo", texto: "Achegai-vos aos irmãos.", referencia: "Hebreus 10:25", resumo: "Comunhão como remédio. Solidão evitável em vida comunitária." },
    { id: "soz78", tipo: "salmo", texto: "O Senhor é a luz da minha vida.", referencia: "Salmos 27:1", resumo: "Luz interior. Solidão escura tem farol divino permanente." },
    { id: "soz79", tipo: "versiculo", texto: "Muitos há que se achegarão do oriente e do ocidente.", referencia: "Mateus 8:11", resumo: "Comunhão eterna com multidão. Solidão terrena tem prazo." },
    { id: "soz80", tipo: "salmo", texto: "O Senhor me sustentou.", referencia: "2 Samuel 22:19", resumo: "Sustento ativo. Solidão na queda tem quem segure." },
    { id: "soz81", tipo: "versiculo", texto: "Estamos convosco todos os dias.", referencia: "Mateus 28:20", resumo: "Companhia diária. Solidão diária impossibilitada." },
    { id: "soz82", tipo: "salmo", texto: "Ouve, ó minha alma, o Senhor te é bom.", referencia: "Salmos 116:7", resumo: "Bondade divina como refúgio. Solidão cede a intimidade bondosa." },
    { id: "soz83", tipo: "versiculo", texto: "Ide e ensinai todas as nações.", referencia: "Mateus 28:19", resumo: "Missão coletiva. Solidão superada em obra comum." },
    { id: "soz84", tipo: "salmo", texto: "O Senhor está no seu santo templo.", referencia: "Habacuque 2:20", resumo: "Deus localizável. Solidão de não saber onde encontrá-Lo cede." },
    { id: "soz85", tipo: "versiculo", texto: "Amemo-nos porque ele nos amou primeiro.", referencia: "1 João 4:19", resumo: "Amor original de Deus. Solidão essencial curada Nele." },
    { id: "soz86", tipo: "salmo", texto: "Sela: espera no Senhor.", referencia: "Salmos 27:14", resumo: "Esperar é pausa relacional. Solidão da espera é vivida com Ele." },
    { id: "soz87", tipo: "versiculo", texto: "Ele te sustenta.", referencia: "Salmos 55:22", resumo: "Sustento pessoal. Solidão do peso cede diante do apoio divino." },
    { id: "soz88", tipo: "salmo", texto: "O Senhor guarda os pequenos.", referencia: "Salmos 116:6", resumo: "Guarda dos frágeis. Solidão do pequeno tem cuidado especial." },
    { id: "soz89", tipo: "versiculo", texto: "Ide, portanto, e fazei discípulos.", referencia: "Mateus 28:19", resumo: "Vocação una a outros. Solidão substituída por serviço compartilhado." },
    { id: "soz90", tipo: "salmo", texto: "O meu socorro vem do Senhor.", referencia: "Salmos 121:2", resumo: "Fonte identificada. Solidão de não saber onde buscar tem endereço." },
    { id: "soz91", tipo: "versiculo", texto: "Cristo em vós, esperança da glória.", referencia: "Colossenses 1:27", resumo: "Cristo por dentro. Solidão essencial impossível — Ele habita." },
    { id: "soz92", tipo: "salmo", texto: "O Senhor está perto de mim.", referencia: "Salmos 34:18", resumo: "Proximidade declarada. Solidão emocional cede diante da presença." },
    { id: "soz93", tipo: "versiculo", texto: "Vinde a mim.", referencia: "Mateus 11:28", resumo: "Convite direto. Solidão convidada a caminhar em direção Dele." },
    { id: "soz94", tipo: "salmo", texto: "O Senhor é o meu escudo.", referencia: "Salmos 3:3", resumo: "Proteção ativa. Solidão do ataque tem defesa divina permanente." },
    { id: "soz95", tipo: "versiculo", texto: "O Deus da paz esteja convosco.", referencia: "Romanos 15:33", resumo: "Bênção de presença. Solidão evitada por bênção comunitária." },
    { id: "soz96", tipo: "salmo", texto: "Tu conheces o meu caminho.", referencia: "Salmos 142:3", resumo: "Deus conhece cada passo. Solidão de ninguém entender cede diante do Onisciente." },
    { id: "soz97", tipo: "versiculo", texto: "Se alguém me abrir a porta, entrarei.", referencia: "Apocalipse 3:20", resumo: "Cristo entra quando convidado. Solidão termina em porta aberta." },
    { id: "soz98", tipo: "salmo", texto: "Ele conhece os que confiam nele.", referencia: "Naum 1:7", resumo: "Conhecimento pessoal. Solidão anônima cede diante do reconhecimento divino." },
    { id: "soz99", tipo: "versiculo", texto: "Andai como filhos da luz.", referencia: "Efésios 5:8", resumo: "Identidade em Deus. Solidão de identidade cede diante da adoção." },
    { id: "soz100", tipo: "salmo", texto: "Feliz aquele a quem o Deus de Jacó ajuda.", referencia: "Salmos 146:5", resumo: "Ajuda divina. Solidão do desamparado tem socorro constante." },
    { id: "soz101", tipo: "versiculo", texto: "Meu Pai vos ama.", referencia: "João 16:27", resumo: "Amor paterno declarado. Solidão do desamado é reversa diante desse amor." },
    { id: "soz102", tipo: "salmo", texto: "O Senhor está comigo; não temerei.", referencia: "Salmos 118:6", resumo: "Fórmula: presença + coragem. Solidão de medo cede duplamente." },
    { id: "soz103", tipo: "versiculo", texto: "Enviei-vos como ovelhas para o meio de lobos.", referencia: "Mateus 10:16", resumo: "Missão em ambiente hostil — mas com pastor. Solidão missionária tem cobertura." },
    { id: "soz104", tipo: "salmo", texto: "Nas tuas mãos entrego o meu espírito.", referencia: "Salmos 31:5", resumo: "Entrega íntima. Solidão de responsabilidade cede diante da confiança." },
    { id: "soz105", tipo: "versiculo", texto: "O Espírito ora por vós com gemidos inexprimíveis.", referencia: "Romanos 8:26", resumo: "Intercessor interno. Solidão da oração é impossível — Ele ora dentro." },
    { id: "soz106", tipo: "salmo", texto: "O Senhor sustém a minha vida.", referencia: "Salmos 54:4", resumo: "Sustento vital. Solidão do fraco tem base divina inabalável." },
    { id: "soz107", tipo: "versiculo", texto: "Cristo é a nossa vida.", referencia: "Colossenses 3:4", resumo: "Identidade compartilhada. Solidão do sentido cede diante do foco em Cristo." },
    { id: "soz108", tipo: "salmo", texto: "Feliz o povo que ouve os sons festivos.", referencia: "Salmos 89:15", resumo: "Comunidade em festa. Solidão substituída por celebração coletiva." },
    { id: "soz109", tipo: "versiculo", texto: "Nunca vos deixarei nem vos abandonarei.", referencia: "Hebreus 13:5", resumo: "Tripla negação. Solidão essencial não sobrevive a essa promessa." },
    { id: "soz110", tipo: "salmo", texto: "Aos teus filhos hei de mostrar a tua bondade.", referencia: "Salmos 145:12", resumo: "Deus mostra bondade. Solidão relacional cede diante da revelação divina." },
  ],
  "Agradecido": [
    { id: "agr1", tipo: "versiculo", texto: "Rendei graças ao Senhor, porque ele é bom; o seu amor dura para sempre.", referencia: "Salmos 107:1", resumo: "Dois fundamentos da gratidão cristã: a bondade essencial de Deus e a permanência eterna do Seu amor. Diferente da gratidão humana, ela é ancorada em quem Deus é, não no que recebemos." },
    { id: "agr2", tipo: "versiculo", texto: "Em tudo dai graças, porque esta é a vontade de Deus em Cristo Jesus para convosco.", referencia: "1 Tessalonicenses 5:18", resumo: "Não 'por' todas as coisas, mas 'em' todas. Podemos agradecer dentro da tragédia, reconhecendo a presença e o cuidado de Deus mesmo no caos. Funciona como ato de fé." },
    { id: "agr3", tipo: "salmo", texto: "Bendize, ó minha alma, ao Senhor, e não te esqueças de nem um dos seus benefícios.", referencia: "Salmos 103:2", resumo: "Davi exorta a própria alma contra o esquecimento. Memória ativa da fidelidade combate desânimo. Listar bênçãos passadas dá fé para o presente." },
    { id: "agr4", tipo: "versiculo", texto: "Toda boa dádiva e todo dom perfeito vêm do alto.", referencia: "Tiago 1:17", resumo: "Tudo o que é genuinamente bom tem origem divina. Bênção, pessoa ou realização — a fonte última é sempre Deus. Reconhecer isso nos torna humildes e generosos." },
    { id: "agr5", tipo: "salmo", texto: "Entrai por suas portas com ação de graças e em seus átrios, com hinos de louvor.", referencia: "Salmos 100:4", resumo: "A gratidão é porta de entrada para a presença de Deus. Antes de pedir, agradecer; antes de reclamar, lembrar. Esse reordenamento muda o tom de qualquer dia." },
    { id: "agr6", tipo: "salmo", texto: "Rendei graças ao Senhor, porque ele é bom, porque a sua misericórdia dura para sempre.", referencia: "Salmos 136:1", resumo: "Este refrão repete-se 26 vezes no Salmo 136, ensinando que a gratidão precisa ser exercitada com constância. A bondade de Deus é fundamento permanente do louvor." },
    { id: "agr7", tipo: "salmo", texto: "Bendize, ó minha alma, ao Senhor, e tudo o que há em mim bendiga o seu santo nome.", referencia: "Salmos 103:1", resumo: "Davi convoca toda a sua interioridade para adorar. A gratidão não é só palavra dita, mas orientação completa da alma. Adorar com tudo o que há em nós renova o coração." },
    { id: "agr8", tipo: "versiculo", texto: "Dando sempre graças por tudo a nosso Deus e Pai, em nome de nosso Senhor Jesus Cristo.", referencia: "Efésios 5:20", resumo: "Paulo amplia a ação de graças para 'sempre' e 'por tudo'. Esse estilo de vida transforma a percepção das circunstâncias e a relação com Deus." },
    { id: "agr9", tipo: "salmo", texto: "Cantarei ao Senhor enquanto eu viver; cantarei louvores ao meu Deus enquanto eu existir.", referencia: "Salmos 104:33", resumo: "A gratidão se transforma em cântico contínuo. Enquanto houver fôlego, há motivo para celebrar. Esse compromisso firma a alma em meio às tempestades." },
    { id: "agr10", tipo: "versiculo", texto: "E tudo o que fizerdes, seja em palavra, seja em ação, fazei-o em nome do Senhor Jesus, dando por ele graças a Deus Pai.", referencia: "Colossenses 3:17", resumo: "Cada palavra e cada ação podem se tornar agradecimento. Não há tarefa pequena demais para ser oferecida como gratidão." },
    { id: "agr11", tipo: "salmo", texto: "Render-te-ei graças, Senhor, de todo o meu coração; contarei todas as tuas maravilhas.", referencia: "Salmos 9:1", resumo: "Gratidão integral envolve coração inteiro e fala ativa. Contar as maravilhas de Deus a si mesmo e aos outros multiplica a alegria." },
    { id: "agr12", tipo: "versiculo", texto: "Por isso, recebendo nós um reino inabalável, retenhamos a graça, pela qual sirvamos a Deus de modo agradável.", referencia: "Hebreus 12:28", resumo: "A gratidão é resposta natural a quem recebeu um reino inabalável. Ela vira combustível para um serviço alegre e leve, não pesado." },
    { id: "agr13", tipo: "salmo", texto: "Apresentemo-nos diante dele com ações de graças, vitoriemo-lhe com salmos.", referencia: "Salmos 95:2", resumo: "A adoração começa com gratidão. Antes de pedir, agradecer. Esse princípio reorganiza toda oração e abre o coração para receber mais." },
    { id: "agr14", tipo: "versiculo", texto: "Graças a Deus pelo seu dom inefável!", referencia: "2 Coríntios 9:15", resumo: "Paulo se refere a Cristo — o dom indescritível. Quando faltam palavras para agradecer, lembrar de Jesus traz à tona o maior motivo de gratidão." },
    { id: "agr15", tipo: "salmo", texto: "Oferece a Deus sacrifício de ações de graças e cumpre os teus votos para com o Altíssimo.", referencia: "Salmos 50:14", resumo: "Gratidão é descrita como 'sacrifício' — algo que se oferece intencionalmente. Há dias em que custa, mas justamente nesses agradecer tem mais peso espiritual." },
    { id: "agr16", tipo: "versiculo", texto: "Dou graças ao meu Deus por tudo o que recordo de vós.", referencia: "Filipenses 1:3", resumo: "Paulo agradece por pessoas. A gratidão também se expressa em valorizar relacionamentos. Lembrar de quem nos abençoou e agradecer por elas multiplica afeto." },
    { id: "agr17", tipo: "salmo", texto: "Que darei ao Senhor por todos os seus benefícios para comigo?", referencia: "Salmos 116:12", resumo: "O salmista pergunta como retribuir tanta bondade. A gratidão amadurecida busca formas de devolver — em adoração, serviço, generosidade — o que recebeu." },
    { id: "agr18", tipo: "versiculo", texto: "A ti, ó Deus dos meus pais, eu rendo graças e te louvo, porque me deste sabedoria e poder.", referencia: "Daniel 2:23", resumo: "Daniel agradece especificamente pela sabedoria recebida. Reconhecer Deus como fonte de cada habilidade nos guarda da arrogância." },
    { id: "agr19", tipo: "salmo", texto: "De todo o coração te darei graças, Senhor; cantar-te-ei louvores diante dos deuses.", referencia: "Salmos 138:1", resumo: "Gratidão pública é parte do agradecimento. Declarar a bondade de Deus diante de outros honra a Ele e fortalece a fé alheia." },
    { id: "agr20", tipo: "versiculo", texto: "Amém! O louvor, e a glória, e a sabedoria, e as ações de graças sejam ao nosso Deus pelos séculos dos séculos.", referencia: "Apocalipse 7:12", resumo: "Imagem da adoração celestial: a gratidão é parte da eternidade. Praticá-la agora é treino para o que viveremos para sempre." },
    { id: "agr21", tipo: "salmo", texto: "Tornaste o meu pranto em folguedo... para que o meu coração te cante louvores e não se cale.", referencia: "Salmos 30:12", resumo: "Gratidão é a resposta natural à libertação. Quem foi tirado do pranto não consegue ficar calado. Esse cântico vira identidade." },
    { id: "agr22", tipo: "salmo", texto: "Rendei graças ao Senhor porque ele é bom, eterna é a sua misericórdia.", referencia: "1 Crônicas 16:34", resumo: "Davi instituiu esse cântico como adoração regular. Repetir verdades sobre a bondade de Deus é prática espiritual que sustenta a fé a longo prazo." },
    { id: "agr23", tipo: "salmo", texto: "Graças te damos, ó Deus, graças te damos; perto está o teu nome.", referencia: "Salmos 75:1", resumo: "A gratidão repetida marca a proximidade de Deus. Quanto mais agradecemos, mais sentimos Sua presença. Causa e efeito espiritual." },
    { id: "agr24", tipo: "versiculo", texto: "Porque dele, e por meio dele, e para ele são todas as coisas. A ele, pois, a glória eternamente.", referencia: "Romanos 11:36", resumo: "Reconhecer Deus como origem, meio e fim de tudo é gratidão fundamental. Coloca cada bênção em perspectiva correta." },
    { id: "agr25", tipo: "salmo", texto: "Bom é render graças ao Senhor e cantar louvores ao teu nome, ó Altíssimo.", referencia: "Salmos 92:1-2", resumo: "Agradecer faz bem. A Bíblia confirma o que estudos modernos comprovam: a gratidão melhora a vida. Mas vai além — ela honra Quem merece honra." },
    { id: "agr26", tipo: "versiculo", texto: "Pois toda criatura de Deus é boa, e nada deve ser rejeitado, se for recebido com ações de graças.", referencia: "1 Timóteo 4:4", resumo: "Receber com gratidão santifica o uso das coisas. Comida, descanso, prazeres legítimos — tudo se torna mais quando recebido com agradecimento consciente." },
    { id: "agr27", tipo: "salmo", texto: "Rendei graças ao Senhor, invocai o seu nome, fazei conhecidos os seus feitos entre os povos.", referencia: "Salmos 105:1", resumo: "Gratidão se expande para missão. Contar o que Deus fez gera fé em outros. A própria experiência se torna testemunho útil." },
    { id: "agr28", tipo: "salmo", texto: "Rendei graças ao Senhor, porque ele é bom; porque a sua misericórdia dura para sempre.", referencia: "Salmos 118:1", resumo: "Refrão repetido como base de toda adoração. Saber esse versículo de memória é ter uma resposta pronta para qualquer circunstância: gratidão à misericórdia eterna." },
    { id: "agr29", tipo: "versiculo", texto: "Um deles, vendo que estava curado, voltou glorificando a Deus em alta voz.", referencia: "Lucas 17:15-16", resumo: "Dos dez leprosos curados, apenas um voltou para agradecer. A gratidão é minoria. Ser dos que voltam glorificando é alinhar-se com o coração de Deus." },
    { id: "agr30", tipo: "salmo", texto: "Aleluia! Louvai, servos do Senhor, louvai o nome do Senhor. Seja bendito o nome do Senhor.", referencia: "Salmos 113:1-3", resumo: "Convocação à gratidão universal — do nascer ao pôr do sol. Toda a vida pode ser moldada como um louvor contínuo ao nome do Senhor." },
    { id: "agr31", tipo: "versiculo", texto: "Em tudo dai graças.", referencia: "1 Tessalonicenses 5:18", resumo: "Gratidão universal — não seletiva. Vontade de Deus é agradecer inclusive no difícil." },
    { id: "agr32", tipo: "salmo", texto: "Rendei graças ao Senhor, invocai o seu nome.", referencia: "1 Crônicas 16:8", resumo: "Gratidão e invocação juntas. Agradecer é começar oração no tom certo." },
    { id: "agr33", tipo: "versiculo", texto: "Sede sempre gratos.", referencia: "Colossenses 3:15", resumo: "Gratidão constante como estilo. Não humor — decisão diária." },
    { id: "agr34", tipo: "salmo", texto: "Rendei graças ao Senhor, porque ele é bom.", referencia: "Salmos 118:1", resumo: "Base da gratidão: bondade Dele. Independe de circunstâncias." },
    { id: "agr35", tipo: "reflexao", texto: "Bendize, ó minha alma, ao Senhor.", referencia: "Salmos 103:1", resumo: "Ordem interna à alma. Gratidão precisa de comando quando emoção falha." },
    { id: "agr36", tipo: "versiculo", texto: "Todo bom dom vem do alto.", referencia: "Tiago 1:17", resumo: "Reconhecer origem divina de cada bem gera gratidão profunda." },
    { id: "agr37", tipo: "salmo", texto: "Louvor a ti, Senhor, com todo o meu coração.", referencia: "Salmos 138:1", resumo: "Louvor total. Gratidão fragmentada não honra o Doador integral." },
    { id: "agr38", tipo: "versiculo", texto: "Dando sempre graças por todas as coisas.", referencia: "Efésios 5:20", resumo: "Gratidão por tudo, sempre. Nada fica de fora — inclusive o que dói." },
    { id: "agr39", tipo: "salmo", texto: "Cantai ao Senhor um cântico novo.", referencia: "Salmos 96:1", resumo: "Cantar novo mantém gratidão viva. Rotina rouba admiração." },
    { id: "agr40", tipo: "versiculo", texto: "Ele nos consola em toda a nossa tribulação.", referencia: "2 Coríntios 1:4", resumo: "Consolação recebida vira material para gratidão diária." },
    { id: "agr41", tipo: "salmo", texto: "O Senhor é bom; a sua misericórdia dura para sempre.", referencia: "Salmos 100:5", resumo: "Duas âncoras: bondade e misericórdia eterna. Gratidão inesgotável." },
    { id: "agr42", tipo: "versiculo", texto: "Andai, portanto, cheios do Espírito.", referencia: "Efésios 5:18-20", resumo: "Espírito produz gratidão. Andar cheio Dele é vida grata." },
    { id: "agr43", tipo: "salmo", texto: "Deus nos abençoou.", referencia: "Salmos 67:6", resumo: "Reconhecer bênção passada alimenta gratidão presente." },
    { id: "agr44", tipo: "reflexao", texto: "Toda dádiva perfeita vem do alto.", referencia: "Tiago 1:17", resumo: "Perfeição das dádivas divinas — sempre no tempo e medida certos." },
    { id: "agr45", tipo: "versiculo", texto: "Sabemos que Deus faz cooperar todas as coisas para o bem.", referencia: "Romanos 8:28", resumo: "Fé nessa promessa produz gratidão por tudo, inclusive processos." },
    { id: "agr46", tipo: "salmo", texto: "Os teus olhos me viram a substância ainda informe.", referencia: "Salmos 139:16", resumo: "Gratidão pela atenção pré-natal. Deus cuidou antes da consciência." },
    { id: "agr47", tipo: "versiculo", texto: "Tudo posso naquele que me fortalece.", referencia: "Filipenses 4:13", resumo: "Gratidão pela força recebida. Cada dia é milagre de sustentação." },
    { id: "agr48", tipo: "salmo", texto: "Bendize, ó minha alma, ao Senhor, e não te esqueças de nenhum dos seus benefícios.", referencia: "Salmos 103:2", resumo: "Memória ativa da bondade. Esquecer é enfraquecer gratidão." },
    { id: "agr49", tipo: "versiculo", texto: "Nele fostes selados com o Espírito Santo.", referencia: "Efésios 1:13", resumo: "Selo divino é motivo de gratidão profunda. Pertença garantida." },
    { id: "agr50", tipo: "salmo", texto: "Aquele que se coroa de bondade e de misericórdia.", referencia: "Salmos 103:4", resumo: "Coroas invisíveis — reconhecê-las produz gratidão constante." },
    { id: "agr51", tipo: "versiculo", texto: "Rendei graças em todas as circunstâncias.", referencia: "1 Tessalonicenses 5:18", resumo: "Circunstâncias variadas — gratidão constante. Estilo de vida." },
    { id: "agr52", tipo: "salmo", texto: "Todo o meu ser bendiz o teu santo nome.", referencia: "Salmos 103:1", resumo: "Ser inteiro em gratidão. Fragmentos não honram plenitude divina." },
    { id: "agr53", tipo: "versiculo", texto: "Todas as coisas foram criadas por meio dele.", referencia: "Colossenses 1:16", resumo: "Cada detalhe existe por Cristo. Gratidão cósmica pelo Criador." },
    { id: "agr54", tipo: "salmo", texto: "O Senhor é a minha porção.", referencia: "Salmos 16:5", resumo: "Ter Deus como herança é motivo primeiro de gratidão." },
    { id: "agr55", tipo: "versiculo", texto: "Vinde a mim, e eu vos aliviarei.", referencia: "Mateus 11:28", resumo: "Alívio recebido gera gratidão. Cristo cuida ativamente." },
    { id: "agr56", tipo: "salmo", texto: "Cantarei ao Senhor enquanto viver.", referencia: "Salmos 104:33", resumo: "Gratidão vitalícia. Nenhum dia sem canto." },
    { id: "agr57", tipo: "versiculo", texto: "Sempre alegres, orando sem cessar.", referencia: "1 Tessalonicenses 5:16-17", resumo: "Alegria contínua vem de gratidão ativa. Fluxo natural." },
    { id: "agr58", tipo: "salmo", texto: "Bendito seja Deus, que não rejeitou a minha oração.", referencia: "Salmos 66:20", resumo: "Gratidão por oração ouvida. Cada resposta merece reconhecimento." },
    { id: "agr59", tipo: "versiculo", texto: "Deus é fiel; por meio dele fostes chamados.", referencia: "1 Coríntios 1:9", resumo: "Chamado divino é motivo diário de gratidão. Fomos escolhidos." },
    { id: "agr60", tipo: "salmo", texto: "O Senhor é grande e mui digno de ser louvado.", referencia: "Salmos 145:3", resumo: "Grandeza divina merece louvor. Gratidão proporcional ao Deus." },
    { id: "agr61", tipo: "versiculo", texto: "Louvai o nome do Senhor.", referencia: "Salmos 113:1", resumo: "Louvor ao nome — a essência Dele. Gratidão a quem Ele é, não só ao que faz." },
    { id: "agr62", tipo: "salmo", texto: "Alegre-se o coração dos que buscam o Senhor.", referencia: "1 Crônicas 16:10", resumo: "Buscar produz gratidão pelo processo, não só pelo achado." },
    { id: "agr63", tipo: "versiculo", texto: "Agradeço a Deus por vós todos.", referencia: "Filipenses 1:3", resumo: "Gratidão por pessoas. Comunidade merece reconhecimento constante." },
    { id: "agr64", tipo: "salmo", texto: "Ao Senhor pertence a salvação.", referencia: "Salmos 3:8", resumo: "Salvação como dom. Gratidão diária pela redenção recebida." },
    { id: "agr65", tipo: "versiculo", texto: "O sangue de Cristo purifica.", referencia: "1 João 1:7", resumo: "Purificação recebida — gratidão pela graça constante do perdão." },
    { id: "agr66", tipo: "salmo", texto: "Ele resgata a tua vida da cova.", referencia: "Salmos 103:4", resumo: "Resgate ativo. Gratidão pelas quedas evitadas por Deus." },
    { id: "agr67", tipo: "versiculo", texto: "Deus é amor.", referencia: "1 João 4:8", resumo: "Essência divina é amor. Gratidão pela natureza Dele, não só pelos atos." },
    { id: "agr68", tipo: "salmo", texto: "O Senhor é a luz da minha vida.", referencia: "Salmos 27:1", resumo: "Luz recebida — gratidão pelo escuro dissipado." },
    { id: "agr69", tipo: "versiculo", texto: "Aquele que começou boa obra em vós há de completá-la.", referencia: "Filipenses 1:6", resumo: "Obra iniciada e prometida. Gratidão antecipada pelo que virá." },
    { id: "agr70", tipo: "salmo", texto: "Rendei graças, invocai o nome do Senhor.", referencia: "Isaías 12:4", resumo: "Ordem dupla: gratidão e invocação. Ritmo espiritual saudável." },
    { id: "agr71", tipo: "versiculo", texto: "O Senhor te abençoe e te guarde.", referencia: "Números 6:24", resumo: "Bênção recebida — gratidão pela cobertura sacerdotal." },
    { id: "agr72", tipo: "salmo", texto: "Tu me cercas por trás e por diante.", referencia: "Salmos 139:5", resumo: "Presença envolvente. Gratidão pela cobertura permanente." },
    { id: "agr73", tipo: "versiculo", texto: "Nele vivemos, nos movemos.", referencia: "Atos 17:28", resumo: "Existir em Deus. Gratidão pela sustentação fundamental." },
    { id: "agr74", tipo: "salmo", texto: "Cantai ao Senhor com ação de graças.", referencia: "Salmos 147:7", resumo: "Canto + gratidão. Combinação que eleva o espírito." },
    { id: "agr75", tipo: "versiculo", texto: "Cristo nos amou e se entregou por nós.", referencia: "Efésios 5:2", resumo: "Amor sacrificial. Gratidão pela entrega máxima recebida." },
    { id: "agr76", tipo: "salmo", texto: "Deus é o meu Salvador.", referencia: "Salmos 62:2", resumo: "Salvação pessoal. Gratidão íntima pela intervenção divina." },
    { id: "agr77", tipo: "versiculo", texto: "Ele cuida de vós.", referencia: "1 Pedro 5:7", resumo: "Cuidado ativo divino. Gratidão diária pela atenção detalhada." },
    { id: "agr78", tipo: "salmo", texto: "Tu és a minha esperança, Senhor Deus.", referencia: "Salmos 71:5", resumo: "Esperança pessoal. Gratidão pela ancoragem no futuro Dele." },
    { id: "agr79", tipo: "versiculo", texto: "Ele nos fez para si.", referencia: "Efésios 2:10", resumo: "Feitura divina. Gratidão pela existência com propósito." },
    { id: "agr80", tipo: "salmo", texto: "O Senhor te sustentará.", referencia: "Salmos 55:22", resumo: "Sustentação prometida. Gratidão pelo apoio constante." },
    { id: "agr81", tipo: "versiculo", texto: "Ele deu o seu Filho unigênito.", referencia: "João 3:16", resumo: "Dom máximo. Gratidão pela oferta mais cara possível." },
    { id: "agr82", tipo: "salmo", texto: "Buscai o Senhor e a sua força.", referencia: "Salmos 105:4", resumo: "Busca ativa. Gratidão pelo convite constante de aproximação." },
    { id: "agr83", tipo: "versiculo", texto: "Nele temos redenção.", referencia: "Efésios 1:7", resumo: "Redenção pessoal. Gratidão pela liberdade recebida." },
    { id: "agr84", tipo: "salmo", texto: "O Senhor é o meu pastor.", referencia: "Salmos 23:1", resumo: "Pastor pessoal. Gratidão pela liderança amorosa constante." },
    { id: "agr85", tipo: "versiculo", texto: "O amor é longânimo.", referencia: "1 Coríntios 13:4", resumo: "Amor divino paciente. Gratidão pela tolerância que recebemos." },
    { id: "agr86", tipo: "salmo", texto: "O Senhor é a força da minha vida.", referencia: "Salmos 27:1", resumo: "Força recebida. Gratidão pela energia sobrenatural diária." },
    { id: "agr87", tipo: "versiculo", texto: "Estamos convosco todos os dias.", referencia: "Mateus 28:20", resumo: "Companhia contínua. Gratidão pela presença ininterrupta." },
    { id: "agr88", tipo: "salmo", texto: "Louvai o Senhor porque é bom.", referencia: "Salmos 106:1", resumo: "Bondade como razão. Gratidão fundamentada na natureza divina." },
    { id: "agr89", tipo: "versiculo", texto: "Andai em amor.", referencia: "Efésios 5:2", resumo: "Amor como caminho. Gratidão pela orientação amorosa recebida." },
    { id: "agr90", tipo: "salmo", texto: "Feliz o povo cujo Deus é o Senhor.", referencia: "Salmos 33:12", resumo: "Pertença. Gratidão pela adoção divina." },
    { id: "agr91", tipo: "versiculo", texto: "O Deus da paz esteja convosco.", referencia: "Romanos 15:33", resumo: "Bênção de paz. Gratidão pela cobertura pacífica." },
    { id: "agr92", tipo: "salmo", texto: "Grandes são as obras do Senhor.", referencia: "Salmos 111:2", resumo: "Obras magníficas. Gratidão pela grandeza observável de Deus." },
    { id: "agr93", tipo: "versiculo", texto: "O amor de Cristo constrange.", referencia: "2 Coríntios 5:14", resumo: "Amor motivador. Gratidão pela força que amor divino gera." },
    { id: "agr94", tipo: "salmo", texto: "Ele restaura a minha alma.", referencia: "Salmos 23:3", resumo: "Restauração recebida. Gratidão pela cura interior contínua." },
    { id: "agr95", tipo: "versiculo", texto: "Onde há o Espírito, há liberdade.", referencia: "2 Coríntios 3:17", resumo: "Liberdade recebida. Gratidão pelo Espírito libertador." },
    { id: "agr96", tipo: "salmo", texto: "O Senhor te guardará de todo mal.", referencia: "Salmos 121:7", resumo: "Guarda integral. Gratidão pela proteção abrangente." },
    { id: "agr97", tipo: "versiculo", texto: "Todo aquele que crê tem a vida eterna.", referencia: "João 3:36", resumo: "Vida eterna. Gratidão pela promessa mais duradoura possível." },
    { id: "agr98", tipo: "salmo", texto: "O Senhor é bom.", referencia: "Salmos 100:5", resumo: "Bondade essencial. Gratidão pela natureza divina invariável." },
    { id: "agr99", tipo: "versiculo", texto: "Ele nos livrou.", referencia: "Colossenses 1:13", resumo: "Livramento passado. Gratidão pelas transferências espirituais." },
    { id: "agr100", tipo: "salmo", texto: "Nunca me esquecerei dos teus preceitos.", referencia: "Salmos 119:93", resumo: "Palavra guardada. Gratidão pela revelação recebida." },
    { id: "agr101", tipo: "versiculo", texto: "Rende graças ao Pai.", referencia: "Colossenses 1:12", resumo: "Filiação. Gratidão pelo Pai divino perfeito." },
    { id: "agr102", tipo: "salmo", texto: "O Senhor guarda os fiéis.", referencia: "Salmos 31:23", resumo: "Guarda seletiva. Gratidão pela atenção específica." },
    { id: "agr103", tipo: "versiculo", texto: "Ele nos escolheu.", referencia: "Efésios 1:4", resumo: "Escolha divina. Gratidão pela eleição amorosa." },
    { id: "agr104", tipo: "salmo", texto: "Feliz aquele que teme ao Senhor.", referencia: "Salmos 112:1", resumo: "Bem-aventurança. Gratidão pela promessa da reverência." },
    { id: "agr105", tipo: "versiculo", texto: "O amor lança fora o medo.", referencia: "1 João 4:18", resumo: "Amor libertador. Gratidão pela cura do medo." },
    { id: "agr106", tipo: "salmo", texto: "O Senhor é o meu escudo.", referencia: "Salmos 3:3", resumo: "Escudo divino. Gratidão pela defesa constante." },
    { id: "agr107", tipo: "versiculo", texto: "Sabemos que amamos porque ele primeiro nos amou.", referencia: "1 João 4:19", resumo: "Amor original. Gratidão pela iniciativa divina." },
    { id: "agr108", tipo: "salmo", texto: "Alegre-me em ti.", referencia: "Salmos 9:2", resumo: "Alegria em Deus. Gratidão que produz júbilo." },
    { id: "agr109", tipo: "versiculo", texto: "Todo joelho se dobrará.", referencia: "Filipenses 2:10", resumo: "Reverência universal. Gratidão pela dignidade de Cristo." },
    { id: "agr110", tipo: "salmo", texto: "Cantai louvores ao seu nome.", referencia: "Salmos 66:2", resumo: "Louvor. Gratidão sonora." },
  ],
  "Nervoso": [
    { id: "ner1", tipo: "versiculo", texto: "O Senhor é a minha luz e a minha salvação; a quem temerei?", referencia: "Salmos 27:1", resumo: "Davi escreve cercado de inimigos e ainda assim faz uma declaração corajosa. Luz dissipa trevas do medo; salvação indica resgate ativo. Diante de Deus, ameaças perdem poder." },
    { id: "ner2", tipo: "versiculo", texto: "Porque Deus não nos tem dado espírito de covardia, mas de poder, de amor e de moderação.", referencia: "2 Timóteo 1:7", resumo: "Paulo lembra Timóteo: o medo paralisante não vem de Deus. O Pai equipa Seus filhos com poder, amor e domínio próprio. Pânico não é do Espírito; pode ser rejeitado conscientemente." },
    { id: "ner3", tipo: "reflexao", texto: "Os ossos sãos são vida para o corpo, mas a inveja é a podridão dos ossos.", referencia: "Provérbios 14:30", resumo: "A serenidade interior afeta saúde física. Cultivar paz no espírito é cuidar do corpo. Nervosismo crônico corrói por dentro; calma reconstrói." },
    { id: "ner4", tipo: "salmo", texto: "Descansa no Senhor e espera nele, não te irrites por causa do homem que prospera em seu caminho.", referencia: "Salmos 37:7", resumo: "Davi alerta contra o nervoso causado por comparação. Descansar em Deus liberta de comparar resultados com os outros. A paz vem quando paramos de medir." },
    { id: "ner5", tipo: "versiculo", texto: "O Senhor pelejará por vós, e vós vos calareis.", referencia: "Êxodo 14:14", resumo: "Diante do mar, Israel queria reagir. Deus pediu silêncio. Quando o nervosismo nos impulsiona à reação imediata, o convite é parar e deixar Ele agir primeiro." },
    { id: "ner6", tipo: "salmo", texto: "Aparta-te do mal e faze o bem; procura a paz e empenha-te por alcançá-la.", referencia: "Salmos 34:14", resumo: "A paz é ativa, se busca. Em momentos de agitação, respirar, orar e desacelerar são decisões espirituais que constroem serenidade." },
    { id: "ner7", tipo: "reflexao", texto: "A resposta branda desvia o furor, mas a palavra dura suscita a ira.", referencia: "Provérbios 15:1", resumo: "Quando o nervosismo cresce, a forma de responder muda o ambiente. Brandura não é fraqueza — é sabedoria. Controlar a língua preserva relacionamentos." },
    { id: "ner8", tipo: "versiculo", texto: "Todo homem seja pronto para ouvir, tardio para falar, tardio para se irar.", referencia: "Tiago 1:19-20", resumo: "Tiago dá fórmula prática contra o nervoso: ouvir primeiro, falar depois, irar-se por último. Essa ordem invertida no mundo é o caminho da paz." },
    { id: "ner9", tipo: "reflexao", texto: "Não te apresses no teu espírito a irar-te, porque a ira mora no íntimo dos insensatos.", referencia: "Eclesiastes 7:9", resumo: "Pressa em irar-se é marca de insensatez. Demorar a reagir é sinal de maturidade espiritual. Cada minuto de pausa salva muitas situações." },
    { id: "ner10", tipo: "reflexao", texto: "Melhor é o longânimo do que o herói da guerra, e o que domina o seu espírito do que o que toma uma cidade.", referencia: "Provérbios 16:32", resumo: "Dominar o próprio espírito é vitória maior que conquistas externas. Quem se controla é mais forte do que quem conquista territórios. Esse triunfo se constrói no íntimo." },
    { id: "ner11", tipo: "salmo", texto: "Deixa a ira, abandona o furor; não te impacientes; certamente, isso acabará mal.", referencia: "Salmos 37:8", resumo: "Davi descreve a ira como algo que se 'deixa' — uma escolha. Reter o furor sempre cobra preço alto. Soltar é opção que protege a alma." },
    { id: "ner12", tipo: "versiculo", texto: "Irai-vos e não pequeis; não se ponha o sol sobre a vossa ira; nem deis lugar ao diabo.", referencia: "Efésios 4:26-27", resumo: "Sentir raiva não é pecado; agir com raiza pode ser. Resolver antes do fim do dia evita que se torne porta para o mal. Disciplina prática." },
    { id: "ner13", tipo: "salmo", texto: "Põe, Senhor, guarda à minha boca; vigia a porta dos meus lábios.", referencia: "Salmos 141:3", resumo: "Davi ora para que Deus controle sua boca. Reconhecer que precisamos de ajuda divina para falar bem é maturidade. Oração antes da resposta evita estragos." },
    { id: "ner14", tipo: "versiculo", texto: "A língua é fogo... contamina o corpo inteiro, incendeia o curso da vida.", referencia: "Tiago 3:5-6", resumo: "Tiago compara a língua a fogo. Em momentos nervosos, palavras destroem em segundos o que levou anos. Pesar cada palavra é mordomia espiritual." },
    { id: "ner15", tipo: "reflexao", texto: "O tolo dá vazão a toda a sua ira, mas o sábio, domando-a, a apazigua.", referencia: "Provérbios 29:11", resumo: "O sábio doma a ira em vez de despejá-la. Esse autocontrole é treinável e nasce de comunhão com Deus, que é lento para irar-Se." },
    { id: "ner16", tipo: "salmo", texto: "Disse: Guardarei os meus caminhos para não pecar com a minha língua.", referencia: "Salmos 39:1", resumo: "Decisão consciente: guardar o que diz como quem guarda um caminho. Pequena disciplina diária com efeitos profundos." },
    { id: "ner17", tipo: "versiculo", texto: "Qualquer que se irar contra seu irmão estará sujeito a julgamento.", referencia: "Mateus 5:22", resumo: "Jesus eleva o padrão: ira injusta é tratada como crime espiritual. Não é proibido sentir, mas alimentar e agir movido por ira destrói." },
    { id: "ner18", tipo: "reflexao", texto: "A discrição do homem o torna tardio em irar-se, e sua glória está em esquecer ofensas.", referencia: "Provérbios 19:11", resumo: "Esquecer ofensas é glória — não fraqueza. Quem libera dores antigas vive mais leve. O perdão é antídoto direto contra o nervosismo crônico." },
    { id: "ner19", tipo: "salmo", texto: "O Senhor é misericordioso e compassivo; longânimo e grande em benignidade.", referencia: "Salmos 103:8", resumo: "Deus é o modelo de paciência. Imitar Sua longanimidade nos torna mais semelhantes a Ele e mais serenos diante das pessoas." },
    { id: "ner20", tipo: "versiculo", texto: "Se possível, quanto depender de vós, tende paz com todos os homens.", referencia: "Romanos 12:18", resumo: "Paulo reconhece que nem sempre a paz depende só de nós — mas pede que façamos nossa parte. Buscar paz quando depender de você desativa muitos focos de tensão." },
    { id: "ner21", tipo: "reflexao", texto: "Não te associes com o iracundo, nem andes com o homem colérico.", referencia: "Provérbios 22:24-25", resumo: "Ambiente molda comportamento. Conviver com pessoas iradas contagia. Escolher boas companhias é estratégia espiritual contra o próprio nervoso." },
    { id: "ner22", tipo: "salmo", texto: "Deus é juiz justo, um Deus que se ira todos os dias.", referencia: "Salmos 7:11", resumo: "Curiosamente, este salmo nos lembra que Deus se ira contra injustiça — mas com justiça, não impulsivamente. Existe ira santa, lenta, deliberada. Diferente da nossa pressa." },
    { id: "ner23", tipo: "versiculo", texto: "Em vos converterdes e em sossegardes, está a vossa salvação; na tranquilidade e na confiança, a vossa força.", referencia: "Isaías 30:15", resumo: "A força vem da tranquilidade, não da agitação. Voltar-se a Deus e aquietar-se é mais poderoso que reagir. Israel resistiu — e perdeu. Você pode escolher diferente hoje." },
    { id: "ner24", tipo: "reflexao", texto: "Como cidade derrubada, que não tem muros, assim é o homem que não tem domínio próprio.", referencia: "Provérbios 25:28", resumo: "Sem autocontrole, ficamos vulneráveis a qualquer ataque emocional. Cultivar domínio próprio é construir muros que protegem a paz interior." },
    { id: "ner25", tipo: "salmo", texto: "Emudeci com silêncio, calei-me mesmo acerca do bem, e a minha dor se agravou.", referencia: "Salmos 39:2-3", resumo: "Davi também tentou simplesmente engolir a raiva — e descobriu que não funciona. Existe um caminho equilibrado entre estourar e reprimir: levar tudo a Deus." },
    { id: "ner26", tipo: "versiculo", texto: "O fruto do Espírito é amor, alegria, paz, longanimidade, benignidade, bondade, fidelidade, mansidão, domínio próprio.", referencia: "Gálatas 5:22-23", resumo: "Domínio próprio é fruto do Espírito — cultivado, não comprado. Quanto mais andamos no Espírito, mais essas qualidades brotam naturalmente." },
    { id: "ner27", tipo: "salmo", texto: "Mas tu, Senhor, és Deus compassivo e misericordioso, longânimo, grande em amor e fidelidade.", referencia: "Salmos 86:15", resumo: "Meditar nesta descrição de Deus desacelera o nervoso. Lembrar como Ele é nos ensina a sermos parecidos com Ele." },
    { id: "ner28", tipo: "versiculo", texto: "Pela vossa perseverança, ganhareis as vossas almas.", referencia: "Lucas 21:19", resumo: "Perseverar é vencer. Em momentos nervosos, simplesmente continuar firme sem explodir já é vitória. A constância salva a alma." },
    { id: "ner29", tipo: "salmo", texto: "Não sejais como o cavalo ou a mula, sem entendimento, que necessitam de freios e cabrestos.", referencia: "Salmos 32:9", resumo: "Deus pede que escolhamos ser dirigíveis pela Sua sabedoria em vez de precisar de freio externo. A maturidade evita conflitos antes que cresçam." },
    { id: "nerextra", tipo: "versiculo", texto: "A tranquilidade aplaca grandes ofensas.", referencia: "Eclesiastes 10:4", resumo: "Salomão ensina que manter a calma desarma situações tensas. Onde outros explodem, o tranquilo encontra solução. Tranquilidade é estratégia, não passividade." },
    { id: "ner31", tipo: "versiculo", texto: "Sede irados e não pequeis.", referencia: "Efésios 4:26", resumo: "Ira existe — mas com limite. Nervosismo pode ser vivido sem gerar dano." },
    { id: "ner32", tipo: "salmo", texto: "A resposta branda desvia o furor.", referencia: "Provérbios 15:1", resumo: "Palavra escolhida acalma tempestade. Nervosismo cede diante da brandura." },
    { id: "ner33", tipo: "versiculo", texto: "Cada um seja tardio para se irar.", referencia: "Tiago 1:19", resumo: "Ira demorada é escolha sábia. Nervosismo apressado é impulso, não decisão." },
    { id: "ner34", tipo: "salmo", texto: "Ira do homem não produz a justiça de Deus.", referencia: "Tiago 1:20", resumo: "Nervosismo não gera resultado divino. Autocontrole abre espaço para agir de Deus." },
    { id: "ner35", tipo: "reflexao", texto: "Melhor é o longânimo do que o valente.", referencia: "Provérbios 16:32", resumo: "Paciência é força superior. Vencer nervosismo é vitória interior maior que qualquer conquista." },
    { id: "ner36", tipo: "versiculo", texto: "O manso possuirá a terra.", referencia: "Mateus 5:5", resumo: "Mansidão herda. Nervosismo perde — brandura ganha o futuro." },
    { id: "ner37", tipo: "salmo", texto: "O Senhor é bom, refúgio no dia da angústia.", referencia: "Naum 1:7", resumo: "Refúgio para nervosismo. Angústia tem abrigo divino." },
    { id: "ner38", tipo: "versiculo", texto: "Não paguem a ninguém mal por mal.", referencia: "Romanos 12:17", resumo: "Interromper ciclo de nervosismo. Não retribuir é começar cura." },
    { id: "ner39", tipo: "salmo", texto: "Aquietai-vos e sabei que eu sou Deus.", referencia: "Salmos 46:10", resumo: "Silêncio interior derruba nervosismo. Lembrar quem manda tranquiliza." },
    { id: "ner40", tipo: "versiculo", texto: "Não vos vingueis a vós mesmos.", referencia: "Romanos 12:19", resumo: "Justiça é de Deus. Nervosismo cede quando confiamos no Juiz." },
    { id: "ner41", tipo: "salmo", texto: "O Senhor pelejará por vós, e vós vos calareis.", referencia: "Êxodo 14:14", resumo: "Silêncio quando Deus luta. Nervosismo é substituído por confiança." },
    { id: "ner42", tipo: "versiculo", texto: "Não vos alegreis quando cair o vosso inimigo.", referencia: "Provérbios 24:17", resumo: "Coração cuidado. Nervosismo com inimigos cede diante de compaixão." },
    { id: "ner43", tipo: "salmo", texto: "O Senhor é misericordioso e tardio em irar-se.", referencia: "Salmos 145:8", resumo: "Modelo divino. Deus contém ira — inspiração para conter nervosismo." },
    { id: "ner44", tipo: "reflexao", texto: "O homem discreto encobre o insulto.", referencia: "Provérbios 12:16", resumo: "Discrição derrota nervosismo. Nem toda ofensa merece reação." },
    { id: "ner45", tipo: "versiculo", texto: "Bendizei aos que vos perseguem.", referencia: "Romanos 12:14", resumo: "Bênção transforma nervosismo. Falar bem é gesto radical de cura." },
    { id: "ner46", tipo: "salmo", texto: "Não te indignes contra os malfeitores.", referencia: "Salmos 37:1", resumo: "Nervosismo com injustiça consome. Confiar em Deus liberta." },
    { id: "ner47", tipo: "versiculo", texto: "Deixando cair o mau contentamento.", referencia: "Efésios 4:31", resumo: "Amargura descartada. Nervosismo perde combustível quando amargura sai." },
    { id: "ner48", tipo: "salmo", texto: "O justo se compadecerá.", referencia: "Salmos 37:26", resumo: "Compaixão é resposta do justo. Nervosismo cede à empatia." },
    { id: "ner49", tipo: "versiculo", texto: "O amor não se irrita.", referencia: "1 Coríntios 13:5", resumo: "Amor sem irritação. Nervosismo é sinal para exercitar mais amor." },
    { id: "ner50", tipo: "salmo", texto: "O Senhor sustém o justo.", referencia: "Salmos 37:17", resumo: "Sustento divino. Nervosismo por sobrecarga tem apoio invisível." },
    { id: "ner51", tipo: "versiculo", texto: "O Senhor guarda os simples.", referencia: "Salmos 116:6", resumo: "Simplicidade guardada. Nervosismo de complicação cede diante da confiança simples." },
    { id: "ner52", tipo: "salmo", texto: "O sol não te ferirá de dia.", referencia: "Salmos 121:6", resumo: "Proteção contra elementos. Nervosismo pelas circunstâncias tem escudo." },
    { id: "ner53", tipo: "versiculo", texto: "A minha alma se acalma como criança desmamada.", referencia: "Salmos 131:2", resumo: "Alma acalmada como criança contente. Nervosismo cede a descanso." },
    { id: "ner54", tipo: "salmo", texto: "O Senhor é o meu bom pastor.", referencia: "João 10:11", resumo: "Pastor bom. Nervosismo do rebanho tem quem cuide." },
    { id: "ner55", tipo: "versiculo", texto: "Não vos deixeis vencer do mal.", referencia: "Romanos 12:21", resumo: "Não deixar mal vencer. Nervosismo é campo de batalha — vencer com bem." },
    { id: "ner56", tipo: "salmo", texto: "O justo vive por fé.", referencia: "Habacuque 2:4", resumo: "Fé como estilo. Nervosismo cede diante da fé constante." },
    { id: "ner57", tipo: "versiculo", texto: "Deus não é homem para que minta.", referencia: "Números 23:19", resumo: "Fidelidade divina. Nervosismo por promessas humanas cede diante de Deus fiel." },
    { id: "ner58", tipo: "salmo", texto: "Espera pacientemente pelo Senhor.", referencia: "Salmos 40:1", resumo: "Paciência ativa. Nervosismo cede quando esperamos com propósito." },
    { id: "ner59", tipo: "versiculo", texto: "Se possível, tende paz com todos.", referencia: "Romanos 12:18", resumo: "Paz como esforço. Nervosismo cede quando escolhemos o caminho pacífico." },
    { id: "ner60", tipo: "salmo", texto: "O Senhor é a força da minha vida.", referencia: "Salmos 27:1", resumo: "Força divina. Nervosismo por fraqueza cede diante da fonte poderosa." },
    { id: "ner61", tipo: "versiculo", texto: "Nada façais por partidarismo.", referencia: "Filipenses 2:3", resumo: "Motivação limpa. Nervosismo cede quando removemos vaidade." },
    { id: "ner62", tipo: "salmo", texto: "Alegre-se o meu coração.", referencia: "Salmos 13:5", resumo: "Alegria escolhida. Nervosismo cede diante da alegria consciente." },
    { id: "ner63", tipo: "versiculo", texto: "Cada um seja tardio em falar.", referencia: "Tiago 1:19", resumo: "Palavra medida. Nervosismo cede quando controlamos boca." },
    { id: "ner64", tipo: "salmo", texto: "O Senhor te esconderá no dia da adversidade.", referencia: "Salmos 27:5", resumo: "Esconderijo divino. Nervosismo de exposição cede diante do abrigo." },
    { id: "ner65", tipo: "versiculo", texto: "Sê submisso a Deus; resiste ao diabo.", referencia: "Tiago 4:7", resumo: "Ordem espiritual. Nervosismo cede quando escolhemos lado." },
    { id: "ner66", tipo: "salmo", texto: "O Senhor guarda a tua saída.", referencia: "Salmos 121:8", resumo: "Cobertura constante. Nervosismo de partir cede diante da guarda." },
    { id: "ner67", tipo: "versiculo", texto: "O amor cobre multidão de pecados.", referencia: "1 Pedro 4:8", resumo: "Amor abrangente. Nervosismo com falhas alheias cede diante do amor cobridor." },
    { id: "ner68", tipo: "salmo", texto: "O Senhor é justo.", referencia: "Salmos 145:17", resumo: "Justiça divina. Nervosismo por injustiça cede — Deus julga." },
    { id: "ner69", tipo: "versiculo", texto: "Tudo posso naquele que me fortalece.", referencia: "Filipenses 4:13", resumo: "Força para tudo. Nervosismo por incapacidade cede diante da capacitação." },
    { id: "ner70", tipo: "salmo", texto: "O Senhor te livrará.", referencia: "Salmos 91:14", resumo: "Livramento pessoal. Nervosismo por ameaça cede diante da promessa." },
    { id: "ner71", tipo: "versiculo", texto: "O Senhor é bom.", referencia: "Salmos 34:8", resumo: "Bondade essencial. Nervosismo com o mundo cede diante da bondade divina." },
    { id: "ner72", tipo: "salmo", texto: "O Deus da paz seja com todos vós.", referencia: "Romanos 15:33", resumo: "Paz de Deus. Nervosismo cede diante da bênção pacífica." },
    { id: "ner73", tipo: "versiculo", texto: "Bendito seja o Deus.", referencia: "Efésios 1:3", resumo: "Bênção a Deus. Nervosismo cede quando louvamos." },
    { id: "ner74", tipo: "salmo", texto: "O Senhor é minha porção.", referencia: "Lamentações 3:24", resumo: "Ter Deus como parte. Nervosismo por escassez cede diante da suficiência." },
    { id: "ner75", tipo: "versiculo", texto: "Deus é fiel.", referencia: "1 Coríntios 10:13", resumo: "Fidelidade divina. Nervosismo por infidelidade humana cede diante de Deus." },
    { id: "ner76", tipo: "salmo", texto: "O Senhor é a minha luz.", referencia: "Salmos 27:1", resumo: "Luz interna. Nervosismo escuro cede diante da luz divina." },
    { id: "ner77", tipo: "versiculo", texto: "Não temas o rebanho.", referencia: "Lucas 12:32", resumo: "Coragem para o rebanho. Nervosismo de responsabilidade cede." },
    { id: "ner78", tipo: "salmo", texto: "O Senhor te sustente na tua enfermidade.", referencia: "Salmos 41:3", resumo: "Sustento no enfermo. Nervosismo por saúde cede diante da atenção divina." },
    { id: "ner79", tipo: "versiculo", texto: "Amai os vossos inimigos.", referencia: "Mateus 5:44", resumo: "Amor radical. Nervosismo pelos inimigos cede diante do amor sobrenatural." },
    { id: "ner80", tipo: "salmo", texto: "Feliz o que se compadece do pobre.", referencia: "Provérbios 14:21", resumo: "Compaixão. Nervosismo por injustiça cede quando ajudamos." },
    { id: "ner81", tipo: "versiculo", texto: "Sede pacíficos entre vós.", referencia: "1 Tessalonicenses 5:13", resumo: "Paz na comunidade. Nervosismo interno cede diante da harmonia." },
    { id: "ner82", tipo: "salmo", texto: "Levanta-me da porta da morte.", referencia: "Salmos 9:13", resumo: "Livramento. Nervosismo pela fragilidade cede diante do poder salvador." },
    { id: "ner83", tipo: "versiculo", texto: "Estai firmes.", referencia: "Efésios 6:14", resumo: "Firmeza. Nervosismo por instabilidade cede diante da postura firme em Deus." },
    { id: "ner84", tipo: "salmo", texto: "O Senhor te guardará de todo mal.", referencia: "Salmos 121:7", resumo: "Guarda integral. Nervosismo por ameaças cede diante da cobertura." },
    { id: "ner85", tipo: "versiculo", texto: "Aprendei de mim, porque sou manso.", referencia: "Mateus 11:29", resumo: "Escola da mansidão. Nervosismo cede quando aprendemos de Cristo." },
    { id: "ner86", tipo: "salmo", texto: "O Senhor guarda os pequeninos.", referencia: "Salmos 116:6", resumo: "Guarda dos frágeis. Nervosismo por fragilidade cede diante do cuidado divino." },
    { id: "ner87", tipo: "versiculo", texto: "O manso rei salvará.", referencia: "Zacarias 9:9", resumo: "Rei manso. Nervosismo por autoridade cede diante do modelo divino." },
    { id: "ner88", tipo: "salmo", texto: "O Senhor guarda a tua alma.", referencia: "Salmos 121:7", resumo: "Guarda íntima. Nervosismo interior cede diante da atenção divina." },
    { id: "ner89", tipo: "versiculo", texto: "Nele fostes selados.", referencia: "Efésios 1:13", resumo: "Selo do Espírito. Nervosismo de insegurança cede diante da marca divina." },
    { id: "ner90", tipo: "salmo", texto: "O Senhor sustenta o justo.", referencia: "Salmos 37:24", resumo: "Sustento contínuo. Nervosismo pela queda cede diante do apoio." },
    { id: "ner91", tipo: "versiculo", texto: "Ide, pois, e fazei discípulos.", referencia: "Mateus 28:19", resumo: "Missão. Nervosismo por propósito cede diante da vocação." },
    { id: "ner92", tipo: "salmo", texto: "O Senhor te ajudará.", referencia: "Salmos 46:5", resumo: "Ajuda divina. Nervosismo por falta cede diante do socorro." },
    { id: "ner93", tipo: "versiculo", texto: "Todo aquele que confia nele.", referencia: "Romanos 10:11", resumo: "Confiança sem confusão. Nervosismo cede diante da fé." },
    { id: "ner94", tipo: "salmo", texto: "O Senhor guarda a saída dos justos.", referencia: "Provérbios 2:8", resumo: "Guarda seletiva. Nervosismo por caminhos cede diante da direção." },
    { id: "ner95", tipo: "versiculo", texto: "O amor lança fora o medo.", referencia: "1 João 4:18", resumo: "Amor perfeito. Nervosismo cede diante do amor pleno." },
    { id: "ner96", tipo: "salmo", texto: "O Senhor conhece os teus caminhos.", referencia: "Salmos 1:6", resumo: "Deus conhece caminho. Nervosismo por incerteza cede diante do conhecimento divino." },
    { id: "ner97", tipo: "versiculo", texto: "Alegrai-vos sempre.", referencia: "1 Tessalonicenses 5:16", resumo: "Alegria constante. Nervosismo cede diante da alegria escolhida." },
    { id: "ner98", tipo: "salmo", texto: "O Senhor é o meu Salvador.", referencia: "Miqueias 7:7", resumo: "Salvação pessoal. Nervosismo cede diante da certeza da salvação." },
    { id: "ner99", tipo: "versiculo", texto: "Não juzgueis.", referencia: "Mateus 7:1", resumo: "Ordem contra juízo. Nervosismo com outros cede diante da autolimitação." },
    { id: "ner100", tipo: "salmo", texto: "O Senhor faz justiça aos oprimidos.", referencia: "Salmos 103:6", resumo: "Justiça divina para oprimidos. Nervosismo por injustiça cede diante da promessa." },
    { id: "ner101", tipo: "versiculo", texto: "Não vos deixeis levar por doutrinas.", referencia: "Hebreus 13:9", resumo: "Estabilidade doutrinária. Nervosismo por confusão cede diante da firmeza." },
    { id: "ner102", tipo: "salmo", texto: "O Senhor te abençoe.", referencia: "Números 6:24", resumo: "Bênção pessoal. Nervosismo cede diante da bênção." },
    { id: "ner103", tipo: "versiculo", texto: "Rende bem por mal.", referencia: "Romanos 12:21", resumo: "Superar mal com bem. Nervosismo cede quando escolhemos o bem." },
    { id: "ner104", tipo: "salmo", texto: "O Senhor guarda os fiéis.", referencia: "Salmos 31:23", resumo: "Guarda dos fiéis. Nervosismo por infidelidade cede diante da guarda seletiva." },
    { id: "ner105", tipo: "versiculo", texto: "O Senhor é meu ajudador.", referencia: "Hebreus 13:6", resumo: "Ajuda pessoal. Nervosismo cede diante do socorro identificado." },
    { id: "ner106", tipo: "salmo", texto: "O Senhor te livrará.", referencia: "Salmos 91:15", resumo: "Livramento. Nervosismo por ameaça cede diante da promessa de livramento." },
    { id: "ner107", tipo: "versiculo", texto: "Bendito seja Deus.", referencia: "2 Coríntios 1:3", resumo: "Bênção. Nervosismo cede diante do louvor." },
    { id: "ner108", tipo: "salmo", texto: "O Senhor é bom.", referencia: "Salmos 118:1", resumo: "Bondade essencial. Nervosismo cede diante da bondade divina." },
    { id: "ner109", tipo: "versiculo", texto: "Estai firmes.", referencia: "1 Coríntios 16:13", resumo: "Firmeza. Nervosismo por instabilidade cede diante da firmeza escolhida." },
    { id: "ner110", tipo: "salmo", texto: "O Senhor é o meu pastor.", referencia: "Salmos 23:1", resumo: "Pastor pessoal. Nervosismo cede diante da liderança amorosa." },
  ],
  "Preciso de esperança": [
    { id: "pre1", tipo: "versiculo", texto: "Porque sou eu que conheço os planos que tenho para vós: planos de paz, e não de mal, para vos dar um futuro e uma esperança.", referencia: "Jeremias 29:11", resumo: "Escrito a exilados em Babilônia. Mesmo no meio do exílio, existia um plano divino. Para quem vive seu próprio 'exílio', Deus enxerga o quadro completo." },
    { id: "pre2", tipo: "versiculo", texto: "Mas os que esperam no Senhor renovam as suas forças, sobem com asas como águias.", referencia: "Isaías 40:31", resumo: "Esperar em hebraico indica entrelaçar-se com Deus. Quem espera recebe renovação descrita em três imagens: voar, correr, caminhar — para fases diferentes da vida." },
    { id: "pre3", tipo: "salmo", texto: "Por que estás abatida, ó minha alma? Espera em Deus, porque ainda o louvarei, salvação minha e Deus meu.", referencia: "Salmos 43:5", resumo: "O salmista dialoga com a própria alma, redirecionando-a para Deus. Esperança é uma disciplina espiritual — falar verdades à alma mesmo quando ela resiste." },
    { id: "pre4", tipo: "versiculo", texto: "E a esperança não confunde, porque o amor de Deus é derramado em nosso coração pelo Espírito Santo.", referencia: "Romanos 5:5", resumo: "Tribulações produzem perseverança, perseverança gera caráter, caráter produz esperança que não decepciona. O fundamento é o amor de Deus experimentado interiormente." },
    { id: "pre5", tipo: "salmo", texto: "Espera no Senhor, anima-te, e ele fortalecerá o teu coração; espera, pois, no Senhor.", referencia: "Salmos 27:14", resumo: "Esperar em Deus é postura ativa do coração. Não é desistir, é confiar enquanto Ele trabalha nos bastidores. A força chega à medida que continuamos esperando." },
    { id: "pre6", tipo: "versiculo", texto: "O Deus da esperança vos encha de todo gozo e paz no vosso crer, para que sejais ricos de esperança.", referencia: "Romanos 15:13", resumo: "Paulo descreve Deus como fonte da esperança. Quanto mais cremos, mais Ele transborda em nós alegria e paz. A esperança vem do próprio caráter de Deus." },
    { id: "pre7", tipo: "reflexao", texto: "Os que confiam no Senhor são como o monte Sião, que não se abala, firme para sempre.", referencia: "Salmos 125:1", resumo: "A esperança que confia em Deus é firme como uma montanha. Ventos podem soprar, mas a base não cede. Estabilidade interior em meio às tempestades." },
    { id: "pre8", tipo: "versiculo", texto: "Estou plenamente certo de que aquele que começou boa obra em vós há de completá-la até o Dia de Cristo Jesus.", referencia: "Filipenses 1:6", resumo: "Deus não abandona projetos pela metade. Se Ele começou algo em você, terminará. Essa certeza dá fôlego para continuar nas fases longas e silenciosas." },
    { id: "pre9", tipo: "salmo", texto: "Pois tu és a minha esperança, Senhor Deus, a minha confiança desde a minha mocidade.", referencia: "Salmos 71:5", resumo: "Confiança em Deus é uma história, não um momento. Quem caminha com Ele acumula testemunhos da Sua fidelidade que sustentam a esperança nos dias difíceis." },
    { id: "pre10", tipo: "versiculo", texto: "Bendito o homem que confia no Senhor e cuja esperança é o Senhor.", referencia: "Jeremias 17:7", resumo: "Confiar em Deus produz bem-aventurança — uma felicidade profunda e estável. Transferir o peso da esperança das pessoas para Aquele que não falha." },
    { id: "pre11", tipo: "versiculo", texto: "Ora, a fé é a certeza de coisas que se esperam, a convicção de fatos que se não veem.", referencia: "Hebreus 11:1", resumo: "A esperança não é desejo vago, é certeza fundamentada. Mesmo sem ver, há convicção. Esse tipo de esperança move montanhas." },
    { id: "pre12", tipo: "salmo", texto: "Eis que os olhos do Senhor estão sobre os que o temem, sobre os que esperam na sua misericórdia.", referencia: "Salmos 33:18", resumo: "Quem espera em Deus está sob Seu olhar atento. Não é solitário aguardar — é estar acompanhado pelo cuidado divino." },
    { id: "pre13", tipo: "versiculo", texto: "Pois nessa esperança fomos salvos. Ora, a esperança que se vê não é esperança; quem espera o que vê?", referencia: "Romanos 8:24-25", resumo: "Esperança real envolve aguardar o invisível. Esse exercício amadurece a alma e sustenta a fé em fases longas de espera." },
    { id: "pre14", tipo: "salmo", texto: "Aguardo o Senhor; a minha alma o aguarda, e espero na sua palavra.", referencia: "Salmos 130:5", resumo: "A palavra de Deus é âncora durante a espera. Quem se apega às promessas escritas tem onde se segurar enquanto aguarda." },
    { id: "pre15", tipo: "versiculo", texto: "Aguardando a bem-aventurada esperança e a manifestação da glória do nosso grande Deus e Salvador.", referencia: "Tito 2:13", resumo: "A esperança cristã tem destino: a volta de Cristo. Esse horizonte transforma toda a forma de viver o presente." },
    { id: "pre16", tipo: "salmo", texto: "Agora, pois, Senhor, que espero eu? A minha esperança está em ti.", referencia: "Salmos 39:7", resumo: "Em meio à fragilidade da vida, o salmista identifica onde mora sua esperança. Essa clareza simplifica e centraliza tudo." },
    { id: "pre17", tipo: "versiculo", texto: "Bendito o Deus e Pai de nosso Senhor Jesus Cristo, que... nos gerou de novo para uma viva esperança.", referencia: "1 Pedro 1:3", resumo: "A ressurreição de Cristo é fonte de esperança viva — não morta, não estática. Essa esperança pulsa e renova continuamente." },
    { id: "pre18", tipo: "salmo", texto: "Espera, ó minha alma, somente em Deus, porque dele vem a minha esperança.", referencia: "Salmos 62:5", resumo: "'Somente' é a palavra-chave. Espalhar a esperança em várias fontes enfraquece. Concentrá-la em Deus dá foco e força." },
    { id: "pre19", tipo: "versiculo", texto: "A qual temos como âncora da alma, segura e firme.", referencia: "Hebreus 6:19", resumo: "A esperança em Cristo é descrita como âncora — algo que segura a alma firme em meio às tempestades. Sem ela, derivamos." },
    { id: "pre20", tipo: "salmo", texto: "Sede fortes, e revigore-se o vosso coração, todos os que esperais no Senhor.", referencia: "Salmos 31:24", resumo: "Esperar não é fraqueza passiva — exige coração revigorado. Quem espera é orientado a se fortalecer, não a se acovardar." },
    { id: "pre21", tipo: "reflexao", texto: "A minha porção é o Senhor, diz a minha alma; portanto, esperarei nele.", referencia: "Lamentações 3:24-26", resumo: "No meio da maior dor, o autor encontra esperança. Saber que Deus é nossa porção sustenta o aguardar de qualquer transformação." },
    { id: "pre22", tipo: "salmo", texto: "Bem-aventurado aquele que tem o Deus de Jacó por seu auxílio, e cuja esperança está posta no Senhor, seu Deus.", referencia: "Salmos 146:5", resumo: "A bem-aventurança verdadeira está em colocar a esperança no Deus certo. Outras esperanças desapontam; essa não." },
    { id: "pre23", tipo: "versiculo", texto: "Os que esperam por mim não serão envergonhados.", referencia: "Isaías 49:23", resumo: "Promessa direta: esperar em Deus não traz vergonha. Pode demorar, pode parecer atrasar — mas Ele cumpre." },
    { id: "pre24", tipo: "salmo", texto: "Tu és o meu refúgio e o meu escudo; na tua palavra espero.", referencia: "Salmos 119:114", resumo: "A palavra é onde a esperança se ancora. Cada promessa lida e meditada renova a confiança no Autor." },
    { id: "pre25", tipo: "versiculo", texto: "Esperou contra a esperança, e creu, para se tornar pai de muitas nações.", referencia: "Romanos 4:18", resumo: "Abraão é modelo: esperar quando não há motivo natural. Esse tipo de esperança nasce da fé no Deus que dá vida ao que estava morto." },
    { id: "pre26", tipo: "salmo", texto: "A nossa alma espera no Senhor; ele é o nosso auxílio e o nosso escudo.", referencia: "Salmos 33:20-22", resumo: "Esperança coletiva, declarada em comunidade. Esperar com outros fortalece o aguardar individual." },
    { id: "pre27", tipo: "reflexao", texto: "Pois há um futuro, e a tua esperança não será frustrada.", referencia: "Provérbios 23:18", resumo: "Promessa do Provérbios: há futuro, e a esperança será cumprida. Mesmo quando o presente parece sem rumo, há um amanhã preparado por Deus." },
    { id: "pre28", tipo: "salmo", texto: "Desfalece a minha alma, aguardando a tua salvação; espero na tua palavra.", referencia: "Salmos 119:81", resumo: "O salmista descreve o cansaço da espera — mas continua. Honrar a Palavra mesmo quando a alma desfalece é fidelidade que Deus honra." },
    { id: "pre29", tipo: "versiculo", texto: "Eu, porém, esperarei no Senhor; esperarei no Deus da minha salvação. O meu Deus me ouvirá.", referencia: "Miquéias 7:7", resumo: "Em meio à decadência ao redor, Miquéias escolhe esperar. Essa decisão individual contraria o ambiente — e é exatamente o que Deus honra." },
    { id: "pre30", tipo: "versiculo", texto: "Agora, pois, permanecem a fé, a esperança e o amor, estes três; porém o maior destes é o amor.", referencia: "1 Coríntios 13:13", resumo: "Esperança permanece — não desaparece com o tempo. Junto com fé e amor, é um dos três pilares eternos da vida cristã." },
    { id: "pre91", tipo: "versiculo", texto: "Se esperamos o que não vemos, com paciência o aguardamos.", referencia: "Romanos 8:25", resumo: "Esperança e paciência juntas. Esperar sem ver é fé em ação." },
    { id: "pre92", tipo: "salmo", texto: "Espera no Senhor, anima-te.", referencia: "Salmos 27:14", resumo: "Esperar ativamente. Esperança que se anima é fé em movimento." },
    { id: "pre93", tipo: "versiculo", texto: "Cristo em vós, esperança da glória.", referencia: "Colossenses 1:27", resumo: "Cristo interior é fonte de esperança. Ele é a esperança." },
    { id: "pre94", tipo: "salmo", texto: "A minha alma espera no Senhor.", referencia: "Salmos 130:6", resumo: "Espera profunda. Esperança do centro do ser." },
    { id: "pre95", tipo: "reflexao", texto: "A esperança não confunde.", referencia: "Romanos 5:5", resumo: "Esperança verdadeira não decepciona. Base é o amor de Deus." },
    { id: "pre96", tipo: "versiculo", texto: "Eu sei os planos que tenho para vós, planos de paz e não de mal.", referencia: "Jeremias 29:11", resumo: "Deus tem planos bons. Esperança fundamentada no propósito divino." },
    { id: "pre97", tipo: "salmo", texto: "Espero na tua palavra.", referencia: "Salmos 130:5", resumo: "Palavra como âncora. Esperança nas promessas divinas." },
    { id: "pre98", tipo: "versiculo", texto: "O Deus da esperança vos encha.", referencia: "Romanos 15:13", resumo: "Deus enche de esperança. Ele mesmo é a fonte." },
    { id: "pre99", tipo: "salmo", texto: "Os que esperam no Senhor renovam as suas forças.", referencia: "Isaías 40:31", resumo: "Esperar renova. Esperança recarrega energia interior." },
    { id: "pre100", tipo: "versiculo", texto: "A tua esperança não será cortada.", referencia: "Provérbios 23:18", resumo: "Esperança preservada. Deus guarda o que promete." },
    { id: "pre101", tipo: "salmo", texto: "Espera no Senhor.", referencia: "Salmos 37:34", resumo: "Ordem repetida. Esperar em Deus é caminho." },
    { id: "pre102", tipo: "versiculo", texto: "Andar por fé, não por vista.", referencia: "2 Coríntios 5:7", resumo: "Fé além da vista. Esperança que não depende de evidência imediata." },
    { id: "pre103", tipo: "salmo", texto: "Feliz aquele que tem a esperança no Senhor.", referencia: "Salmos 146:5", resumo: "Bem-aventurança da esperança. Estado interior de expectativa." },
    { id: "pre104", tipo: "reflexao", texto: "A esperança adiada faz adoecer o coração.", referencia: "Provérbios 13:12", resumo: "Reconhece dor da espera — e promete árvore de vida quando cumprida." },
    { id: "pre105", tipo: "versiculo", texto: "Bendito seja o Deus, que nos gerou de novo para viva esperança.", referencia: "1 Pedro 1:3", resumo: "Regeneração produz esperança viva — não morta. Fresca sempre." },
    { id: "pre106", tipo: "salmo", texto: "Deus fará justiça aos aflitos.", referencia: "Salmos 140:12", resumo: "Justiça futura garantida. Esperança para os oprimidos." },
    { id: "pre107", tipo: "versiculo", texto: "Sois herdeiros conforme a promessa.", referencia: "Gálatas 3:29", resumo: "Herança prometida. Esperança da posse futura." },
    { id: "pre108", tipo: "salmo", texto: "Ainda esperarei nele.", referencia: "Jó 13:15", resumo: "Esperança extrema. Confiar mesmo no pior." },
    { id: "pre109", tipo: "versiculo", texto: "O que se aproxima de Deus creia que ele é galardoador.", referencia: "Hebreus 11:6", resumo: "Deus recompensa quem busca. Esperança do encontro." },
    { id: "pre110", tipo: "salmo", texto: "O Senhor te livrará.", referencia: "Salmos 91:14", resumo: "Livramento prometido. Esperança concreta na intervenção divina." },
    { id: "pre111", tipo: "versiculo", texto: "A esperança faz-nos viver.", referencia: "Romanos 8:24", resumo: "Esperança sustenta vida. Sem ela, murcha o interior." },
    { id: "pre112", tipo: "salmo", texto: "O Senhor é bom para os que nele esperam.", referencia: "Lamentações 3:25", resumo: "Bondade condicional. Esperança atrai bondade divina." },
    { id: "pre113", tipo: "versiculo", texto: "O nosso Senhor Jesus Cristo é a nossa esperança.", referencia: "1 Timóteo 1:1", resumo: "Cristo é esperança pessoal. Fonte identificada." },
    { id: "pre114", tipo: "salmo", texto: "A tua misericórdia, Senhor, encha a terra.", referencia: "Salmos 33:22", resumo: "Esperança na misericórdia divina abundante." },
    { id: "pre115", tipo: "versiculo", texto: "O Deus da paz vos encha.", referencia: "Filipenses 4:9", resumo: "Paz de Deus abundante. Esperança em Deus como fonte." },
    { id: "pre116", tipo: "salmo", texto: "Bendize, ó minha alma, ao Senhor.", referencia: "Salmos 103:1", resumo: "Louvor sustenta esperança. Bendizer é escolha." },
    { id: "pre117", tipo: "versiculo", texto: "Cristo é a nossa vida.", referencia: "Colossenses 3:4", resumo: "Cristo como vida. Esperança fundamentada Nele." },
    { id: "pre118", tipo: "salmo", texto: "Feliz aquele cuja força está em ti.", referencia: "Salmos 84:5", resumo: "Força divina como fonte. Esperança na fonte inesgotável." },
    { id: "pre119", tipo: "versiculo", texto: "Não vos entristeçais como os que não têm esperança.", referencia: "1 Tessalonicenses 4:13", resumo: "Tristeza cristã com esperança. Diferença essencial." },
    { id: "pre120", tipo: "salmo", texto: "O Senhor é a minha rocha.", referencia: "Salmos 18:2", resumo: "Rocha firme. Esperança em fundação inabalável." },
    { id: "pre121", tipo: "versiculo", texto: "O Deus da esperança vos encha de gozo.", referencia: "Romanos 15:13", resumo: "Esperança que produz gozo. Fruto natural." },
    { id: "pre122", tipo: "salmo", texto: "O Senhor é o meu Salvador.", referencia: "Miqueias 7:7", resumo: "Salvação pessoal. Esperança concreta na intervenção divina." },
    { id: "pre123", tipo: "versiculo", texto: "A vossa vida está escondida com Cristo em Deus.", referencia: "Colossenses 3:3", resumo: "Vida escondida em Deus. Esperança de segurança eterna." },
    { id: "pre124", tipo: "salmo", texto: "O Senhor guarda os fiéis.", referencia: "Salmos 31:23", resumo: "Guarda dos fiéis. Esperança na proteção seletiva." },
    { id: "pre125", tipo: "versiculo", texto: "Bem-aventurados os que choram, porque serão consolados.", referencia: "Mateus 5:4", resumo: "Consolo prometido. Esperança do alívio." },
    { id: "pre126", tipo: "salmo", texto: "O Senhor é a força do seu povo.", referencia: "Salmos 28:8", resumo: "Força coletiva. Esperança em Deus como fortaleza." },
    { id: "pre127", tipo: "versiculo", texto: "Ninguém vos poderá arrancar da minha mão.", referencia: "João 10:28", resumo: "Segurança eterna. Esperança de proteção invencível." },
    { id: "pre128", tipo: "salmo", texto: "O Senhor guarda a alma dos seus santos.", referencia: "Salmos 97:10", resumo: "Guarda íntima. Esperança na atenção divina detalhada." },
    { id: "pre129", tipo: "versiculo", texto: "O amor de Deus é derramado.", referencia: "Romanos 5:5", resumo: "Derramamento de amor. Esperança fundamentada em amor concreto." },
    { id: "pre130", tipo: "salmo", texto: "Espera no Senhor, e ele te guiará.", referencia: "Salmos 37:5", resumo: "Espera guiada. Esperança que conduz." },
    { id: "pre131", tipo: "versiculo", texto: "O que confia no Senhor é como o monte Sião.", referencia: "Salmos 125:1", resumo: "Confiança firme. Esperança em fundação inabalável." },
    { id: "pre132", tipo: "salmo", texto: "Ele salvará os pobres.", referencia: "Salmos 72:13", resumo: "Salvação dos pobres. Esperança para os desprivilegiados." },
    { id: "pre133", tipo: "versiculo", texto: "Buscai primeiro o reino.", referencia: "Mateus 6:33", resumo: "Prioridade correta. Esperança nas providências consequentes." },
    { id: "pre134", tipo: "salmo", texto: "O Senhor está perto.", referencia: "Salmos 34:18", resumo: "Proximidade divina. Esperança na presença permanente." },
    { id: "pre135", tipo: "versiculo", texto: "O tempo se abrevia.", referencia: "1 Coríntios 7:29", resumo: "Perspectiva temporal. Esperança da eternidade próxima." },
    { id: "pre136", tipo: "salmo", texto: "O Senhor será a tua confiança.", referencia: "Provérbios 3:26", resumo: "Confiança em Deus. Esperança fundamentada." },
    { id: "pre137", tipo: "versiculo", texto: "Todo aquele que crê nele não será confundido.", referencia: "Romanos 10:11", resumo: "Fé sem confusão. Esperança em resultado claro." },
    { id: "pre138", tipo: "salmo", texto: "O Senhor te sustentará.", referencia: "Salmos 55:22", resumo: "Sustento pessoal. Esperança no apoio invisível." },
    { id: "pre139", tipo: "versiculo", texto: "O Senhor virá.", referencia: "Apocalipse 22:20", resumo: "Retorno prometido. Esperança máxima do futuro." },
    { id: "pre140", tipo: "salmo", texto: "O Senhor guarda os simples.", referencia: "Salmos 116:6", resumo: "Guarda dos simples. Esperança na atenção especial." },
    { id: "pre141", tipo: "versiculo", texto: "A minha graça te basta.", referencia: "2 Coríntios 12:9", resumo: "Graça suficiente. Esperança na provisão constante." },
    { id: "pre142", tipo: "salmo", texto: "O Senhor te livrará de todo mal.", referencia: "2 Timóteo 4:18", resumo: "Livramento integral. Esperança em Deus como libertador." },
    { id: "pre143", tipo: "versiculo", texto: "Fostes chamados para a liberdade.", referencia: "Gálatas 5:13", resumo: "Chamado à liberdade. Esperança da vida sem correntes." },
    { id: "pre144", tipo: "salmo", texto: "O Senhor te abençoe.", referencia: "Números 6:24", resumo: "Bênção pessoal. Esperança na cobertura sacerdotal." },
    { id: "pre145", tipo: "versiculo", texto: "Cristo vive em mim.", referencia: "Gálatas 2:20", resumo: "Cristo por dentro. Esperança de vida transformada." },
    { id: "pre146", tipo: "salmo", texto: "O Senhor é a minha rocha.", referencia: "Salmos 42:9", resumo: "Rocha pessoal. Esperança em fundação firme." },
    { id: "pre147", tipo: "versiculo", texto: "O que começou boa obra em vós há de completá-la.", referencia: "Filipenses 1:6", resumo: "Completude prometida. Esperança no acabamento divino." },
    { id: "pre148", tipo: "salmo", texto: "O Senhor te sustenta.", referencia: "Salmos 3:5", resumo: "Sustento contínuo. Esperança na energia divina diária." },
    { id: "pre149", tipo: "versiculo", texto: "O Senhor conhece o caminho dos justos.", referencia: "Salmos 1:6", resumo: "Conhecimento divino. Esperança na direção conhecida." },
    { id: "pre150", tipo: "salmo", texto: "O Senhor guarda a tua vida.", referencia: "Salmos 121:7", resumo: "Guarda vital. Esperança na proteção da vida." },
    { id: "pre151", tipo: "versiculo", texto: "Nele fostes selados.", referencia: "Efésios 1:13", resumo: "Selo do Espírito. Esperança em pertença marcada." },
    { id: "pre152", tipo: "salmo", texto: "O Senhor te acompanhe.", referencia: "Salmos 91:11", resumo: "Acompanhamento angelical. Esperança na cobertura sobrenatural." },
    { id: "pre153", tipo: "versiculo", texto: "Cristo é a nossa paz.", referencia: "Efésios 2:14", resumo: "Cristo como paz. Esperança na paz pessoal." },
    { id: "pre154", tipo: "salmo", texto: "O Senhor te dará a herança.", referencia: "Salmos 37:29", resumo: "Herança prometida. Esperança na posse futura." },
    { id: "pre155", tipo: "versiculo", texto: "Sabemos que todas as coisas cooperam.", referencia: "Romanos 8:28", resumo: "Cooperação divina. Esperança no propósito de tudo." },
    { id: "pre156", tipo: "salmo", texto: "O Senhor te sustente.", referencia: "Salmos 20:2", resumo: "Sustento oracional. Esperança na resposta divina." },
    { id: "pre157", tipo: "versiculo", texto: "Deus é fiel.", referencia: "1 Coríntios 1:9", resumo: "Fidelidade divina. Esperança na constância de Deus." },
    { id: "pre158", tipo: "salmo", texto: "O Senhor é o meu escudo.", referencia: "Salmos 3:3", resumo: "Escudo divino. Esperança na proteção ativa." },
    { id: "pre159", tipo: "versiculo", texto: "O amor lança fora o medo.", referencia: "1 João 4:18", resumo: "Amor sem medo. Esperança no amor pleno." },
    { id: "pre160", tipo: "salmo", texto: "O Senhor guarda a alma dos justos.", referencia: "Provérbios 2:8", resumo: "Guarda dos justos. Esperança na atenção divina." },
    { id: "pre161", tipo: "versiculo", texto: "Cristo em vós é a esperança da glória.", referencia: "Colossenses 1:27", resumo: "Esperança da glória. Cristo interior é garantia." },
    { id: "pre162", tipo: "salmo", texto: "O Senhor te salvará.", referencia: "Salmos 3:8", resumo: "Salvação pessoal. Esperança na intervenção divina." },
    { id: "pre163", tipo: "versiculo", texto: "Bendito seja Deus.", referencia: "Efésios 1:3", resumo: "Bênção. Esperança no louvor." },
    { id: "pre164", tipo: "salmo", texto: "O Senhor é bom.", referencia: "Salmos 100:5", resumo: "Bondade essencial. Esperança na natureza divina." },
    { id: "pre165", tipo: "versiculo", texto: "O Deus da paz esteja convosco.", referencia: "Romanos 15:33", resumo: "Paz de Deus. Esperança na paz coletiva." },
    { id: "pre166", tipo: "salmo", texto: "O Senhor é a minha luz.", referencia: "Salmos 27:1", resumo: "Luz interior. Esperança na iluminação." },
    { id: "pre167", tipo: "versiculo", texto: "O Senhor é o meu ajudador.", referencia: "Hebreus 13:6", resumo: "Ajuda pessoal. Esperança no socorro identificado." },
    { id: "pre168", tipo: "salmo", texto: "Feliz o povo cujo Deus é o Senhor.", referencia: "Salmos 33:12", resumo: "Pertença. Esperança na adoção divina." },
    { id: "pre169", tipo: "versiculo", texto: "Cristo é a nossa vida.", referencia: "Colossenses 3:4", resumo: "Cristo como vida. Esperança fundamentada." },
    { id: "pre170", tipo: "salmo", texto: "O Senhor te livrará.", referencia: "Salmos 91:14", resumo: "Livramento pessoal. Esperança na intervenção divina." },
  ],
  "Preciso de paz": [
    { id: "pre31", tipo: "versiculo", texto: "Deixo-vos a paz, a minha paz vos dou; não vo-la dou como a dá o mundo.", referencia: "João 14:27", resumo: "Jesus oferece Sua própria paz aos discípulos antes da cruz. Diferente da paz mundana que depende de ausência de problemas, esta coexiste com tempestades. Calma profunda ancorada na soberania de Deus." },
    { id: "pre32", tipo: "versiculo", texto: "Tu, Senhor, conservarás em perfeita paz aquele cujo propósito é firme; porque ele confia em ti.", referencia: "Isaías 26:3", resumo: "'Shalom shalom' — paz duplicada, completa, integral. A condição é firmar o pensamento em Deus. Em era de distrações, manter mente focada nEle é o segredo da serenidade." },
    { id: "pre33", tipo: "salmo", texto: "O Senhor abençoa o seu povo com paz.", referencia: "Salmos 29:11", resumo: "O mesmo Deus que governa tempestades cósmicas escolhe sussurrar paz no coração de Seus filhos. A paz é parte da herança espiritual do crente." },
    { id: "pre34", tipo: "versiculo", texto: "E a paz de Deus, que excede todo o entendimento, guardará o vosso coração e a vossa mente em Cristo Jesus.", referencia: "Filipenses 4:7", resumo: "Paz que não tem explicação racional. Age como sentinela militar guardando coração e mente contra invasões de ansiedade e medo." },
    { id: "pre35", tipo: "salmo", texto: "Muita paz têm os que amam a tua lei, e para eles não há tropeço.", referencia: "Salmos 119:165", resumo: "Quem caminha alinhado com a Palavra encontra estabilidade. A paz não vem de evitar conflitos, mas de andar no caminho certo com consciência tranquila." },
    { id: "pre36", tipo: "versiculo", texto: "Seja a paz de Cristo o árbitro em vosso coração.", referencia: "Colossenses 3:15", resumo: "Paulo usa imagem esportiva: a paz de Cristo decide cada disputa interior. Quando vários sentimentos competem, ela deve dar a palavra final." },
    { id: "pre37", tipo: "reflexao", texto: "Naquela mesma hora, o Espírito Santo vos ensinará o que deveis dizer.", referencia: "Lucas 12:12", resumo: "Em momentos de tensão, o Espírito dá direção. Saber que existe um conselheiro interior disponível traz paz especial para situações complicadas." },
    { id: "pre38", tipo: "versiculo", texto: "Segui a paz com todos e a santificação, sem a qual ninguém verá o Senhor.", referencia: "Hebreus 12:14", resumo: "Buscar paz é ação intencional. Exige esforço consciente nos relacionamentos. Caminho de paz é também caminho de proximidade com Deus." },
    { id: "pre39", tipo: "salmo", texto: "O Senhor te abençoe e te guarde; o Senhor faça resplandecer o rosto sobre ti... o Senhor te dê a paz.", referencia: "Números 6:24-26", resumo: "Bênção sacerdotal antiga que culmina na paz. Receber a paz é receber o rosto de Deus sobre nós. Use essa bênção sobre si mesmo e sobre outros." },
    { id: "pre40", tipo: "versiculo", texto: "Bem-aventurados os pacificadores, porque serão chamados filhos de Deus.", referencia: "Mateus 5:9", resumo: "Promover paz é marca espiritual visível. Quem cultiva paz no próprio coração reflete o caráter do Pai e abençoa os ambientes onde está." },
    { id: "pre41", tipo: "versiculo", texto: "Justificados, pois, mediante a fé, temos paz com Deus por meio de nosso Senhor Jesus Cristo.", referencia: "Romanos 5:1", resumo: "A paz mais fundamental é com Deus, conquistada por Cristo. De lá brotam todas as outras pazes. Sem essa base, nenhuma outra paz se sustenta." },
    { id: "pre42", tipo: "salmo", texto: "Mas os mansos herdarão a terra e se deleitarão na abundância de paz.", referencia: "Salmos 37:11", resumo: "Mansidão e paz andam juntas. Quem renuncia ao orgulho recebe paz abundante como herança. Trocar afirmação própria por mansidão liberta." },
    { id: "pre43", tipo: "versiculo", texto: "Ah, se tivesses dado ouvidos aos meus mandamentos! Então, seria a tua paz como um rio.", referencia: "Isaías 48:18", resumo: "Obedecer a Deus produz paz como rio constante. Cada vez que escolhemos Sua sabedoria, abrimos canal para mais paz fluir em nós." },
    { id: "pre44", tipo: "versiculo", texto: "O reino de Deus... é justiça, e paz, e alegria no Espírito Santo.", referencia: "Romanos 14:17", resumo: "Paz é parte essencial do Reino. Onde Cristo reina, paz reina. Buscar Seu Reino primeiro é buscar paz como consequência." },
    { id: "pre45", tipo: "salmo", texto: "Escutarei o que disser o Senhor Deus, pois falará de paz ao seu povo e aos seus santos.", referencia: "Salmos 85:8", resumo: "Deus fala de paz a quem escuta. Reservar tempo de silêncio para ouvi-Lo é estratégia direta para receber paz." },
    { id: "pre46", tipo: "versiculo", texto: "E ele, despertando, repreendeu o vento e disse ao mar: Acalma-te, emudece!", referencia: "Marcos 4:39", resumo: "Jesus comandou paz à tempestade física — e comanda paz às tempestades interiores. A mesma voz que aquietou o mar pode aquietar você." },
    { id: "pre47", tipo: "salmo", texto: "Haja paz dentro dos teus muros e prosperidade dentro dos teus palácios.", referencia: "Salmos 122:7", resumo: "Oração por paz no lar e na cidade. Onde habitamos importa para Deus. Orar paz sobre nossos espaços é mordomia espiritual." },
    { id: "pre48", tipo: "reflexao", texto: "Quando os caminhos do homem agradam ao Senhor, este reconcilia com ele até os seus inimigos.", referencia: "Provérbios 16:7", resumo: "Quando vivemos para agradar a Deus, Ele cuida das relações ao nosso redor. Conflitos resistentes muitas vezes cedem quando o foco volta para Ele." },
    { id: "pre49", tipo: "salmo", texto: "Florescerão em seus dias o justo, e a abundância de paz, até que cesse a lua.", referencia: "Salmos 72:7", resumo: "Promessa profética do reino messiânico: paz abundante e duradoura. Esse é o destino final para quem está em Cristo." },
    { id: "pre50", tipo: "versiculo", texto: "Porque ele é a nossa paz, o qual de ambos fez um.", referencia: "Efésios 2:14", resumo: "Cristo é a paz em pessoa. Quem está nEle vive na fonte. Não buscamos paz como conceito — buscamos um Salvador que é paz." },
    { id: "pre51", tipo: "salmo", texto: "Cantem de júbilo... os que se comprazem na paz do seu servo.", referencia: "Salmos 35:27", resumo: "Deus tem prazer na paz dos Seus servos. Ele não nos quer agitados — quer-nos serenos. Esse desejo divino é fundamento para descansar." },
    { id: "pre52", tipo: "versiculo", texto: "Paz, paz para o que está longe e para o que está perto; eu o sararei.", referencia: "Isaías 57:19", resumo: "Promessa de paz para todos — longe ou perto. Onde houver fé, há paz disponível. Não importa o ponto de partida, há cura." },
    { id: "pre53", tipo: "versiculo", texto: "O Deus da paz seja com todos vós. Amém.", referencia: "Romanos 15:33", resumo: "Paulo encerra suas cartas frequentemente com essa oração. Ter o Deus da paz consigo é o maior bem possível. Pedi-Lo sobre os outros é abençoar profundamente." },
    { id: "pre54", tipo: "salmo", texto: "Ele dá paz aos teus limites; do mais excelente trigo te farta.", referencia: "Salmos 147:14", resumo: "Paz nos limites — proteção das fronteiras da vida. Deus cuida do perímetro para que dentro dele haja descanso e provisão." },
    { id: "pre55", tipo: "versiculo", texto: "O fruto da justiça semeia-se em paz para os que promovem a paz.", referencia: "Tiago 3:18", resumo: "Quem semeia paz colhe justiça. Esse ciclo virtuoso transforma comunidades. Investir em paz é investir no que produz mais." },
    { id: "pre56", tipo: "versiculo", texto: "Porque um menino nos nasceu... e o seu nome será: Maravilhoso Conselheiro, Deus Forte, Pai da Eternidade, Príncipe da Paz.", referencia: "Isaías 9:6", resumo: "Cristo é o Príncipe da Paz. Esse título descreve quem Ele é em essência. Submeter-se ao Seu reinado interior é receber Sua paz." },
    { id: "pre57", tipo: "salmo", texto: "Em Salém está o seu tabernáculo, e o lugar da sua habitação, em Sião.", referencia: "Salmos 76:2", resumo: "Salém significa 'paz'. Deus escolhe habitar onde há paz. Cultivar paz no coração é preparar lugar para Sua habitação." },
    { id: "pre58", tipo: "reflexao", texto: "Mas a sabedoria que vem do alto é, primeiramente, pura; depois, pacífica, indulgente, tratável.", referencia: "Tiago 3:17", resumo: "A sabedoria divina é pacífica por natureza. Quando recebemos sabedoria de Deus, vem com paz embutida. Pedir uma é receber a outra." },
    { id: "pre59", tipo: "versiculo", texto: "Farei com elas aliança de paz e acabarei com as bestas-feras da terra.", referencia: "Ezequiel 34:25", resumo: "Aliança de paz é promessa profunda. Deus se compromete a tirar as 'bestas' — os terrores — e dar segurança. Essa aliança é nossa em Cristo." },
    { id: "pre60", tipo: "versiculo", texto: "Graça e paz vos sejam multiplicadas no pleno conhecimento de Deus e de Jesus, nosso Senhor.", referencia: "2 Pedro 1:2", resumo: "Paz se multiplica no conhecimento de Cristo. Quanto mais O conhecemos, mais paz recebemos. Isso transforma o estudo da Palavra em terapia da alma." },
    { id: "pre171", tipo: "versiculo", texto: "Deixo-vos a paz, a minha paz vos dou.", referencia: "João 14:27", resumo: "Paz de Cristo é dom próprio. Diferente da paz do mundo." },
    { id: "pre172", tipo: "salmo", texto: "Em paz me deitarei e dormirei.", referencia: "Salmos 4:8", resumo: "Paz até no sono. Deus sustenta descanso completo." },
    { id: "pre173", tipo: "versiculo", texto: "A paz de Deus, que excede todo entendimento.", referencia: "Filipenses 4:7", resumo: "Paz que ultrapassa razão. Presente divino." },
    { id: "pre174", tipo: "salmo", texto: "O Senhor abençoará o seu povo com paz.", referencia: "Salmos 29:11", resumo: "Bênção específica de paz. Deus distribui." },
    { id: "pre175", tipo: "reflexao", texto: "Grande é a paz dos que amam a tua lei.", referencia: "Salmos 119:165", resumo: "Amor à Palavra produz paz. Base sólida." },
    { id: "pre176", tipo: "versiculo", texto: "Ele mesmo é a nossa paz.", referencia: "Efésios 2:14", resumo: "Cristo É paz. Ter Cristo é ter paz." },
    { id: "pre177", tipo: "salmo", texto: "Meu coração e minha carne exultam pelo Deus vivo.", referencia: "Salmos 84:2", resumo: "Exultação em Deus. Paz que vem da comunhão viva." },
    { id: "pre178", tipo: "versiculo", texto: "O Deus da paz vos aperfeiçoe.", referencia: "Hebreus 13:20-21", resumo: "Deus da paz aperfeiçoa. Paz é ferramenta de crescimento." },
    { id: "pre179", tipo: "salmo", texto: "O Senhor está no seu santo templo; cale-se a terra.", referencia: "Habacuque 2:20", resumo: "Silêncio diante de Deus. Paz que vem do silêncio reverente." },
    { id: "pre180", tipo: "versiculo", texto: "Aquietai-vos e sabei que eu sou Deus.", referencia: "Salmos 46:10", resumo: "Silêncio interior. Paz na consciência da soberania." },
    { id: "pre181", tipo: "salmo", texto: "Buscai a paz e segui-a.", referencia: "Salmos 34:14", resumo: "Paz como caminho ativo. Não passiva." },
    { id: "pre182", tipo: "versiculo", texto: "Estai em paz uns com os outros.", referencia: "Marcos 9:50", resumo: "Paz mútua. Comunidade como cenário." },
    { id: "pre183", tipo: "salmo", texto: "O Senhor é bom para os que esperam.", referencia: "Lamentações 3:25", resumo: "Esperar produz paz. Deus recompensa a paciência." },
    { id: "pre184", tipo: "reflexao", texto: "Cristo vos deu a paz por meio de seu sangue.", referencia: "Colossenses 1:20", resumo: "Paz pelo sangue. Preço alto pela paz eterna." },
    { id: "pre185", tipo: "versiculo", texto: "Tu conservarás em perfeita paz aquele cuja mente.", referencia: "Isaías 26:3", resumo: "Paz perfeita. Condicionada à mente firme em Deus." },
    { id: "pre186", tipo: "salmo", texto: "O Senhor é o meu pastor.", referencia: "Salmos 23:1", resumo: "Pastor pessoal. Paz da liderança amorosa." },
    { id: "pre187", tipo: "versiculo", texto: "O reino de Deus é justiça, paz e alegria.", referencia: "Romanos 14:17", resumo: "Paz é parte do reino. Estilo divino." },
    { id: "pre188", tipo: "salmo", texto: "Espera no Senhor.", referencia: "Salmos 37:7", resumo: "Esperar em silêncio. Paz na expectativa." },
    { id: "pre189", tipo: "versiculo", texto: "O Senhor de paz vos dê paz.", referencia: "2 Tessalonicenses 3:16", resumo: "Deus de paz dá paz. Fonte e presente." },
    { id: "pre190", tipo: "salmo", texto: "O Senhor é a minha luz.", referencia: "Salmos 27:1", resumo: "Luz interior. Paz que dissipa trevas." },
    { id: "pre191", tipo: "versiculo", texto: "Deus não é de confusão.", referencia: "1 Coríntios 14:33", resumo: "Deus é de paz. Confusão não vem Dele." },
    { id: "pre192", tipo: "salmo", texto: "Feliz o povo que assim lhe sucede.", referencia: "Salmos 144:15", resumo: "Felicidade pela pertença. Paz da identidade." },
    { id: "pre193", tipo: "versiculo", texto: "Fostes chamados à paz.", referencia: "1 Coríntios 7:15", resumo: "Chamado à paz. Vocação de tranquilidade." },
    { id: "pre194", tipo: "salmo", texto: "O Senhor é fiel.", referencia: "2 Tessalonicenses 3:3", resumo: "Fidelidade divina. Paz na constância." },
    { id: "pre195", tipo: "versiculo", texto: "Vinde a mim, e eu vos aliviarei.", referencia: "Mateus 11:28", resumo: "Alívio prometido. Paz do descarrego." },
    { id: "pre196", tipo: "salmo", texto: "O Senhor é a força.", referencia: "Salmos 27:1", resumo: "Força interior. Paz da capacitação." },
    { id: "pre197", tipo: "versiculo", texto: "O amor cobre multidão de pecados.", referencia: "1 Pedro 4:8", resumo: "Amor abrangente. Paz que perdoa e cobre." },
    { id: "pre198", tipo: "salmo", texto: "O Senhor está perto de todos os que o invocam.", referencia: "Salmos 145:18", resumo: "Proximidade convidada. Paz da presença próxima." },
    { id: "pre199", tipo: "versiculo", texto: "Sede em paz uns com os outros.", referencia: "1 Tessalonicenses 5:13", resumo: "Paz comunitária. Escolha coletiva." },
    { id: "pre200", tipo: "salmo", texto: "O Senhor guarda a tua vida.", referencia: "Salmos 121:7", resumo: "Guarda vital. Paz da proteção." },
    { id: "pre201", tipo: "versiculo", texto: "O manso possuirá a terra.", referencia: "Mateus 5:5", resumo: "Mansidão herda. Paz recebe futuro." },
    { id: "pre202", tipo: "salmo", texto: "O Senhor te sustente.", referencia: "Salmos 20:2", resumo: "Sustento oracional. Paz da resposta esperada." },
    { id: "pre203", tipo: "versiculo", texto: "O Senhor é bom.", referencia: "Naum 1:7", resumo: "Bondade divina. Paz na natureza segura." },
    { id: "pre204", tipo: "salmo", texto: "O Senhor é justo.", referencia: "Salmos 145:17", resumo: "Justiça divina. Paz na certeza da retribuição correta." },
    { id: "pre205", tipo: "versiculo", texto: "O Senhor é misericordioso.", referencia: "Salmos 145:8", resumo: "Misericórdia. Paz no perdão constante." },
    { id: "pre206", tipo: "salmo", texto: "O Senhor pelejará por vós.", referencia: "Êxodo 14:14", resumo: "Silêncio quando Deus luta. Paz da confiança." },
    { id: "pre207", tipo: "versiculo", texto: "Paz seja convosco.", referencia: "João 20:19", resumo: "Saudação de Cristo. Paz declarada." },
    { id: "pre208", tipo: "salmo", texto: "O Senhor te acompanhe.", referencia: "Salmos 91:11", resumo: "Anjos ao lado. Paz da cobertura sobrenatural." },
    { id: "pre209", tipo: "versiculo", texto: "Onde há o Espírito, há liberdade.", referencia: "2 Coríntios 3:17", resumo: "Liberdade do Espírito. Paz da soltura interior." },
    { id: "pre210", tipo: "salmo", texto: "O Senhor é o meu escudo.", referencia: "Salmos 3:3", resumo: "Escudo divino. Paz na defesa constante." },
    { id: "pre211", tipo: "versiculo", texto: "Cristo é a nossa vida.", referencia: "Colossenses 3:4", resumo: "Cristo é vida. Paz da identidade em Cristo." },
    { id: "pre212", tipo: "salmo", texto: "O Senhor guarda os fiéis.", referencia: "Salmos 31:23", resumo: "Guarda dos fiéis. Paz da atenção seletiva." },
    { id: "pre213", tipo: "versiculo", texto: "O amor lança fora o medo.", referencia: "1 João 4:18", resumo: "Amor sem medo. Paz da eliminação do temor." },
    { id: "pre214", tipo: "salmo", texto: "O Senhor te salvará.", referencia: "Salmos 34:6", resumo: "Salvação pessoal. Paz da intervenção." },
    { id: "pre215", tipo: "versiculo", texto: "Deus é fiel.", referencia: "1 Coríntios 10:13", resumo: "Fidelidade divina. Paz na constância." },
    { id: "pre216", tipo: "salmo", texto: "O Senhor guarda a tua alma.", referencia: "Salmos 121:7", resumo: "Guarda íntima. Paz interior." },
    { id: "pre217", tipo: "versiculo", texto: "Cristo em vós.", referencia: "Colossenses 1:27", resumo: "Cristo por dentro. Paz da habitação divina." },
    { id: "pre218", tipo: "salmo", texto: "O Senhor é bom.", referencia: "Salmos 100:5", resumo: "Bondade essencial. Paz da natureza divina." },
    { id: "pre219", tipo: "versiculo", texto: "Bendito seja Deus.", referencia: "2 Coríntios 1:3", resumo: "Bênção. Paz do louvor." },
    { id: "pre220", tipo: "salmo", texto: "O Senhor te livrará.", referencia: "Salmos 91:14", resumo: "Livramento. Paz da promessa." },
    { id: "pre221", tipo: "versiculo", texto: "Aquele que confia no Senhor.", referencia: "Salmos 32:10", resumo: "Confiança. Paz da entrega." },
    { id: "pre222", tipo: "salmo", texto: "Feliz o povo cujo Deus é o Senhor.", referencia: "Salmos 33:12", resumo: "Pertença. Paz da adoção." },
    { id: "pre223", tipo: "versiculo", texto: "Fostes chamados na esperança.", referencia: "Efésios 4:4", resumo: "Vocação na esperança. Paz do chamado." },
    { id: "pre224", tipo: "salmo", texto: "O Senhor te abençoe.", referencia: "Números 6:24", resumo: "Bênção. Paz da cobertura." },
    { id: "pre225", tipo: "versiculo", texto: "Cristo nos amou.", referencia: "Gálatas 2:20", resumo: "Amor de Cristo. Paz do amor recebido." },
    { id: "pre226", tipo: "salmo", texto: "O Senhor guarda a saída.", referencia: "Salmos 121:8", resumo: "Guarda de porta. Paz das transições." },
    { id: "pre227", tipo: "versiculo", texto: "A paz vos deixo.", referencia: "João 14:27", resumo: "Paz deixada. Herança pessoal." },
    { id: "pre228", tipo: "salmo", texto: "O Senhor é a minha rocha.", referencia: "Salmos 18:2", resumo: "Rocha firme. Paz da estabilidade." },
    { id: "pre229", tipo: "versiculo", texto: "Sabemos que todas as coisas cooperam.", referencia: "Romanos 8:28", resumo: "Cooperação divina. Paz do propósito de tudo." },
    { id: "pre230", tipo: "salmo", texto: "O Senhor é a minha porção.", referencia: "Salmos 73:26", resumo: "Porção suficiente. Paz da suficiência." },
    { id: "pre231", tipo: "versiculo", texto: "O Deus da esperança vos encha.", referencia: "Romanos 15:13", resumo: "Deus enche. Paz da fonte divina." },
    { id: "pre232", tipo: "salmo", texto: "O Senhor te sustenta.", referencia: "Salmos 3:5", resumo: "Sustento. Paz da energia divina." },
    { id: "pre233", tipo: "versiculo", texto: "Todo aquele que Nele crê.", referencia: "Romanos 10:11", resumo: "Fé confiante. Paz da certeza." },
    { id: "pre234", tipo: "salmo", texto: "O Senhor está comigo.", referencia: "Salmos 118:6", resumo: "Companhia divina. Paz da presença." },
    { id: "pre235", tipo: "versiculo", texto: "O nosso Senhor é a nossa esperança.", referencia: "1 Timóteo 1:1", resumo: "Cristo é esperança. Paz na fonte." },
    { id: "pre236", tipo: "salmo", texto: "O Senhor guarda a tua entrada.", referencia: "Salmos 121:8", resumo: "Guarda de entrada. Paz das chegadas." },
    { id: "pre237", tipo: "versiculo", texto: "Sabemos que o amor de Deus.", referencia: "1 João 4:16", resumo: "Amor conhecido. Paz da certeza amorosa." },
    { id: "pre238", tipo: "salmo", texto: "Feliz aquele cuja força está em ti.", referencia: "Salmos 84:5", resumo: "Força divina. Paz da fonte." },
    { id: "pre239", tipo: "versiculo", texto: "O Senhor é o meu Salvador.", referencia: "Miqueias 7:7", resumo: "Salvação. Paz da certeza." },
    { id: "pre240", tipo: "salmo", texto: "O Senhor te preservará.", referencia: "Salmos 121:7", resumo: "Preservação. Paz da atenção contínua." },
    { id: "pre241", tipo: "versiculo", texto: "Cristo em vós, esperança da glória.", referencia: "Colossenses 1:27", resumo: "Cristo interior. Paz da esperança." },
    { id: "pre242", tipo: "salmo", texto: "O Senhor conhece o teu caminho.", referencia: "Salmos 1:6", resumo: "Conhecimento divino. Paz da direção conhecida." },
    { id: "pre243", tipo: "versiculo", texto: "Nele fostes selados.", referencia: "Efésios 1:13", resumo: "Selo. Paz da marca divina." },
    { id: "pre244", tipo: "salmo", texto: "O Senhor guarda os simples.", referencia: "Salmos 116:6", resumo: "Guarda dos simples. Paz da atenção especial." },
    { id: "pre245", tipo: "versiculo", texto: "O Deus da paz esteja convosco.", referencia: "Romanos 15:33", resumo: "Bênção pacífica. Paz coletiva." },
    { id: "pre246", tipo: "salmo", texto: "O Senhor é bom.", referencia: "Salmos 34:8", resumo: "Bondade. Paz na natureza divina." },
    { id: "pre247", tipo: "versiculo", texto: "Estamos convosco todos os dias.", referencia: "Mateus 28:20", resumo: "Companhia contínua. Paz da presença diária." },
    { id: "pre248", tipo: "salmo", texto: "O Senhor te sustente.", referencia: "Salmos 55:22", resumo: "Sustento. Paz do apoio." },
    { id: "pre249", tipo: "versiculo", texto: "O que começou boa obra.", referencia: "Filipenses 1:6", resumo: "Obra completa. Paz do acabamento." },
    { id: "pre250", tipo: "salmo", texto: "O Senhor é o meu Deus.", referencia: "Salmos 118:28", resumo: "Pertença. Paz da identidade." },
  ],
  "Preciso de força": [
    { id: "pre61", tipo: "versiculo", texto: "Posso todas as coisas naquele que me fortalece.", referencia: "Filipenses 4:13", resumo: "Paulo escreve da prisão, aprendendo viver contente em qualquer circunstância. O 'tudo posso' não é sucesso garantido em qualquer empreitada — é força sobrenatural para enfrentar o que a vida traz." },
    { id: "pre62", tipo: "salmo", texto: "O Senhor é a minha força e o meu escudo; nele o meu coração confia, e fui socorrido.", referencia: "Salmos 28:7", resumo: "Deus é simultaneamente força (capacidade interior) e escudo (proteção exterior). Cuida do crente por dentro e por fora. Força vem da decisão consciente de descansar nEle." },
    { id: "pre63", tipo: "salmo", texto: "O Senhor é a minha força, e o meu cântico, e se tornou a minha salvação.", referencia: "Êxodo 15:2", resumo: "Cântico de Moisés após o Mar Vermelho. Reconhecer Deus como força nasce de testemunhos de libertação. Cantar Sua salvação renova a força para os próximos desafios." },
    { id: "pre64", tipo: "versiculo", texto: "A minha graça te basta, porque o poder se aperfeiçoa na fraqueza.", referencia: "2 Coríntios 12:9", resumo: "Paulo descobre princípio revolucionário: é na fraqueza humana que o poder divino se manifesta com mais clareza. Sua fraqueza não é problema — é cenário ideal para a graça." },
    { id: "pre65", tipo: "versiculo", texto: "Sê forte e corajoso; não temas, nem te espantes, porque o Senhor, teu Deus, é contigo por onde quer que andares.", referencia: "Josué 1:9", resumo: "Deus encoraja Josué antes de missão gigantesca. A coragem ordenada aqui é fundamentada na presença de Deus. Não somos chamados a ser fortes sozinhos." },
    { id: "pre66", tipo: "versiculo", texto: "O Senhor Deus é a minha fortaleza, e faz os meus pés como os das cervas, e me faz andar altaneiramente.", referencia: "Habacuque 3:19", resumo: "Mesmo prevendo escassez total, Habacuque declara força divina. Pés de cerva sobem terrenos impossíveis. Em terrenos difíceis, Deus dá tração sobrenatural." },
    { id: "pre67", tipo: "salmo", texto: "Deus é o que me reveste de força e aperfeiçoa o meu caminho.", referencia: "Salmos 18:32", resumo: "Deus reveste — força vem de fora para dentro, como roupa. Não é gerada por nós; é recebida. Vestir-se diariamente dessa força é prática espiritual." },
    { id: "pre68", tipo: "versiculo", texto: "Vigiai, estai firmes na fé, portai-vos varonilmente, fortalecei-vos.", referencia: "1 Coríntios 16:13", resumo: "Paulo lista quatro ordens curtas e potentes. Permanecer firme, atento e fortalecido é escolha diária. Não somos vítimas das circunstâncias; podemos resistir." },
    { id: "pre69", tipo: "salmo", texto: "Deus é o nosso refúgio e fortaleza, socorro bem presente na angústia.", referencia: "Salmos 46:1", resumo: "Refúgio e fortaleza são imagens de proteção e resistência. Em meio à tribulação, Deus não está distante — está presente, atuante e disponível." },
    { id: "pre70", tipo: "versiculo", texto: "Não temas, porque eu sou contigo... eu te fortaleço, e te ajudo, e te sustento com a minha destra fiel.", referencia: "Isaías 41:10", resumo: "Três verbos cobrem todas as necessidades: fortalecer, ajudar, sustentar. A mão divina é fiel e não solta o que segura." },
    { id: "pre71", tipo: "versiculo", texto: "Quanto ao mais, sede fortalecidos no Senhor e na força do seu poder.", referencia: "Efésios 6:10", resumo: "Antes de listar a armadura, Paulo manda buscar força em Deus. Equipamento sem força é inútil. Fortalecer-se nEle é a base de toda batalha vencida." },
    { id: "pre72", tipo: "salmo", texto: "Eu te amo, ó Senhor, força minha. O Senhor é a minha rocha, a minha fortaleza e o meu libertador.", referencia: "Salmos 18:1-2", resumo: "Davi acumula imagens de proteção: rocha, fortaleza, libertador. Cada uma fala de força diferente. Deus é múltiplo na forma de nos sustentar." },
    { id: "pre73", tipo: "versiculo", texto: "Dá força ao cansado e multiplica as forças ao que não tem nenhum vigor.", referencia: "Isaías 40:29", resumo: "Promessa específica para os exaustos. Quando você acha que acabou, Deus multiplica do zero. Reconhecer a exaustão é o primeiro passo para receber força." },
    { id: "pre74", tipo: "salmo", texto: "No dia em que eu clamei, me acudiste e alentaste a força da minha alma.", referencia: "Salmos 138:3", resumo: "Resposta de Deus à oração inclui revigorar a alma. Clamar não é fraqueza — é canal direto para receber alento." },
    { id: "pre75", tipo: "salmo", texto: "Buscai o Senhor e a sua força; buscai perpetuamente a sua presença.", referencia: "1 Crônicas 16:11", resumo: "Buscar a Deus e Sua força é instrução permanente, não pontual. A constância é o segredo. Quem busca sempre, encontra sempre." },
    { id: "pre76", tipo: "salmo", texto: "Sairei em poder do Senhor Deus; só dele farei menção da tua justiça.", referencia: "Salmos 71:16", resumo: "O salmista decide agir 'em poder do Senhor', não no próprio. Distinguir as duas fontes muda completamente a experiência da força." },
    { id: "pre77", tipo: "versiculo", texto: "Como os teus dias, assim seja a tua força.", referencia: "Deuteronômio 33:25", resumo: "Promessa para cada dia: força proporcional ao desafio. Deus mede e supre conforme a necessidade. Não falta nem sobra — sempre o suficiente." },
    { id: "pre78", tipo: "salmo", texto: "Bem-aventurado o homem cuja força está em ti... atravessando o vale, fazem dele um manancial.", referencia: "Salmos 84:5,7", resumo: "Quem tira força em Deus transforma vales em mananciais. A força que vem do alto não apenas atravessa — fertiliza por onde passa." },
    { id: "pre79", tipo: "versiculo", texto: "Corroborados com todo o poder, segundo a força da sua glória... com alegria.", referencia: "Colossenses 1:11", resumo: "Paulo ora por força para perseverar com alegria. Não basta resistir — resistir com alegria é o sinal da força verdadeiramente divina." },
    { id: "pre80", tipo: "salmo", texto: "A minha carne e o meu coração desfalecem; mas Deus é a fortaleza do meu coração e a minha porção para sempre.", referencia: "Salmos 73:26", resumo: "Mesmo quando o corpo e os sentimentos falham, Deus permanece fortaleza interior. Isso liberta de depender de saúde física para se sentir forte." },
    { id: "pre81", tipo: "versiculo", texto: "Para que, segundo a riqueza da sua glória, vos conceda que sejais robustecidos com poder, mediante o seu Espírito, no homem interior.", referencia: "Efésios 3:16", resumo: "Oração de Paulo: fortalecimento interior pelo Espírito. A força mais importante é a do 'homem interior', não a aparência exterior." },
    { id: "pre82", tipo: "salmo", texto: "Achei a Davi, meu servo; com o meu santo óleo o ungi. A minha mão será sempre com ele; o meu braço o fortalecerá.", referencia: "Salmos 89:21", resumo: "Deus se compromete pessoalmente a fortalecer quem chama. Mão de Deus sobre nós, braço dEle nos sustentando — proteção integral." },
    { id: "pre83", tipo: "versiculo", texto: "Se tiverdes fé como um grão de mostarda, direis a este monte: Passa daqui para lá, e ele passará.", referencia: "Mateus 17:20", resumo: "Fé pequena mas verdadeira tem poder enorme. Não precisamos de muito — precisamos de fé real. Esse princípio liberta da pressão de 'fé suficiente'." },
    { id: "pre84", tipo: "salmo", texto: "Buscai o Senhor e a sua força; buscai perpetuamente a sua presença.", referencia: "Salmos 105:4", resumo: "Repetição do princípio: força e presença andam juntas. Onde buscamos uma, encontramos a outra. Comunhão é fonte de vigor." },
    { id: "pre85", tipo: "versiculo", texto: "Disse-lhe Jesus: Se podes! Tudo é possível ao que crê.", referencia: "Marcos 9:23", resumo: "Jesus desafia a fé. Tudo é possível ao que crê — não porque a fé seja mágica, mas porque conecta com o Deus para quem nada é impossível." },
    { id: "pre86", tipo: "salmo", texto: "Bendito seja o Senhor, minha rocha, que adestra as minhas mãos para o combate e os meus dedos para a guerra.", referencia: "Salmos 144:1", resumo: "Deus treina para as batalhas que enfrentamos. Cada desafio anterior foi treinamento para o próximo. Não há sofrimento sem propósito formativo." },
    { id: "pre87", tipo: "reflexao", texto: "O sábio é forte, e o homem de conhecimento, cheio de poder.", referencia: "Provérbios 24:5", resumo: "Conhecimento da Palavra produz força real. Quem investe em sabedoria divina constrói reservas para os dias difíceis." },
    { id: "pre88", tipo: "salmo", texto: "A minha alma se consome de tristeza; fortalece-me segundo a tua palavra.", referencia: "Salmos 119:28", resumo: "O salmista pede força ancorada na Palavra. Quando a alma está consumida, a Bíblia é instrumento de recuperação." },
    { id: "pre89", tipo: "versiculo", texto: "Em todas estas coisas, somos mais que vencedores, por meio daquele que nos amou.", referencia: "Romanos 8:37", resumo: "Não apenas vencedores — mais que vencedores. Por meio de Cristo, atravessamos tudo com vitória que vai além de simplesmente sobreviver." },
    { id: "pre90", tipo: "salmo", texto: "Tremendo és, ó Deus, desde os teus santuários; é o Deus de Israel quem dá força e poder ao povo. Bendito seja Deus!", referencia: "Salmos 68:35", resumo: "Deus dá força ao povo. Esse é Seu compromisso, parte de Sua identidade. Receber força dEle é confiar em quem Ele é." },
    { id: "pre251", tipo: "versiculo", texto: "Ele dá força ao cansado.", referencia: "Isaías 40:29", resumo: "Força para o cansado. Deus supre onde falta." },
    { id: "pre252", tipo: "salmo", texto: "O Senhor é a força da minha vida.", referencia: "Salmos 27:1", resumo: "Força vital. Deus é fonte." },
    { id: "pre253", tipo: "versiculo", texto: "A minha graça te basta, porque o poder se aperfeiçoa na fraqueza.", referencia: "2 Coríntios 12:9", resumo: "Fraqueza é palco do poder Dele. Paradoxo divino." },
    { id: "pre254", tipo: "salmo", texto: "Deus é o meu forte refúgio.", referencia: "Salmos 71:7", resumo: "Refúgio forte. Base para o fraco." },
    { id: "pre255", tipo: "reflexao", texto: "Sede fortes e corajosos.", referencia: "Josué 1:9", resumo: "Ordem de coragem. Fortaleza escolhida." },
    { id: "pre256", tipo: "versiculo", texto: "Fortalecei-vos no Senhor e na força do seu poder.", referencia: "Efésios 6:10", resumo: "Força no Senhor. Fonte identificada." },
    { id: "pre257", tipo: "salmo", texto: "O Senhor é a minha fortaleza.", referencia: "Salmos 18:2", resumo: "Fortaleza pessoal. Proteção ativa." },
    { id: "pre258", tipo: "versiculo", texto: "O Senhor dará forças ao seu povo.", referencia: "Salmos 29:11", resumo: "Força ao povo. Coletiva." },
    { id: "pre259", tipo: "salmo", texto: "O justo florescerá como a palmeira.", referencia: "Salmos 92:12", resumo: "Florescer é sinal de vida. Força que dura." },
    { id: "pre260", tipo: "versiculo", texto: "Os que esperam no Senhor renovam as forças.", referencia: "Isaías 40:31", resumo: "Esperar renova. Força na quietude." },
    { id: "pre261", tipo: "salmo", texto: "O Senhor é o meu escudo.", referencia: "Salmos 3:3", resumo: "Escudo divino. Força defensiva." },
    { id: "pre262", tipo: "versiculo", texto: "Sede fortes e corajosos, não temais.", referencia: "Deuteronômio 31:6", resumo: "Coragem porque Deus vai junto. Força relacional." },
    { id: "pre263", tipo: "salmo", texto: "O Senhor é a força do seu ungido.", referencia: "Salmos 28:8", resumo: "Força específica. Deus fortalece os Seus." },
    { id: "pre264", tipo: "reflexao", texto: "Não pelo poder, mas pelo meu Espírito.", referencia: "Zacarias 4:6", resumo: "Força espiritual. Não muscular." },
    { id: "pre265", tipo: "versiculo", texto: "O Senhor é o meu ajudador.", referencia: "Hebreus 13:6", resumo: "Ajuda identificada. Força na parceria." },
    { id: "pre266", tipo: "salmo", texto: "Feliz o homem cuja força está em ti.", referencia: "Salmos 84:5", resumo: "Força pessoal em Deus. Fonte inesgotável." },
    { id: "pre267", tipo: "versiculo", texto: "Estai firmes na fé, portai-vos varonilmente, sede fortes.", referencia: "1 Coríntios 16:13", resumo: "Sequência de ordens. Força escolhida." },
    { id: "pre268", tipo: "salmo", texto: "O Senhor sustenta o justo.", referencia: "Salmos 37:17", resumo: "Sustento contínuo. Força invisível." },
    { id: "pre269", tipo: "versiculo", texto: "Aquele que está em vós é maior.", referencia: "1 João 4:4", resumo: "Maior interior. Força que vence." },
    { id: "pre270", tipo: "salmo", texto: "O Senhor é rocha.", referencia: "Salmos 18:2", resumo: "Rocha firme. Base para força." },
    { id: "pre271", tipo: "versiculo", texto: "Andai por meio do Espírito.", referencia: "Gálatas 5:16", resumo: "Andar espiritual. Força no caminho." },
    { id: "pre272", tipo: "salmo", texto: "O Senhor te sustente.", referencia: "Salmos 20:2", resumo: "Sustento oracional. Força pedida." },
    { id: "pre273", tipo: "versiculo", texto: "Bem-aventurados os que têm fome de justiça.", referencia: "Mateus 5:6", resumo: "Fome que sacia. Força na busca." },
    { id: "pre274", tipo: "salmo", texto: "O Senhor é a força.", referencia: "Salmos 46:1", resumo: "Força reconhecida. Base para vida." },
    { id: "pre275", tipo: "versiculo", texto: "Fortalecei-vos na graça.", referencia: "2 Timóteo 2:1", resumo: "Força na graça. Fonte específica." },
    { id: "pre276", tipo: "salmo", texto: "O Senhor é o meu Deus.", referencia: "Salmos 18:2", resumo: "Pertença. Força da identidade." },
    { id: "pre277", tipo: "versiculo", texto: "O Senhor pelejará por vós.", referencia: "Êxodo 14:14", resumo: "Deus luta. Força na aliança." },
    { id: "pre278", tipo: "salmo", texto: "O Senhor é grande.", referencia: "Salmos 145:3", resumo: "Grandeza. Força na fonte magnífica." },
    { id: "pre279", tipo: "versiculo", texto: "Tudo posso naquele que me fortalece.", referencia: "Filipenses 4:13", resumo: "Tudo em Cristo. Força completa." },
    { id: "pre280", tipo: "salmo", texto: "O Senhor é bom.", referencia: "Salmos 34:8", resumo: "Bondade. Força na natureza confiável." },
    { id: "pre281", tipo: "versiculo", texto: "Não vos canseis de fazer o bem.", referencia: "Gálatas 6:9", resumo: "Perseverança. Força para o bem." },
    { id: "pre282", tipo: "salmo", texto: "O Senhor está comigo.", referencia: "Salmos 118:6", resumo: "Companhia. Força relacional." },
    { id: "pre283", tipo: "versiculo", texto: "Deus é fiel.", referencia: "1 Coríntios 10:13", resumo: "Fidelidade. Força na constância." },
    { id: "pre284", tipo: "salmo", texto: "O Senhor guarda a saída.", referencia: "Salmos 121:8", resumo: "Guarda. Força de porta em porta." },
    { id: "pre285", tipo: "versiculo", texto: "O amor lança fora o medo.", referencia: "1 João 4:18", resumo: "Amor perfeito. Força contra medo." },
    { id: "pre286", tipo: "salmo", texto: "O Senhor é a minha luz.", referencia: "Salmos 27:1", resumo: "Luz. Força na iluminação." },
    { id: "pre287", tipo: "versiculo", texto: "Cristo em vós, esperança da glória.", referencia: "Colossenses 1:27", resumo: "Cristo interior. Força habitante." },
    { id: "pre288", tipo: "salmo", texto: "Feliz o povo cujo Deus é o Senhor.", referencia: "Salmos 33:12", resumo: "Pertença. Força da adoção." },
    { id: "pre289", tipo: "versiculo", texto: "O que começou boa obra há de completá-la.", referencia: "Filipenses 1:6", resumo: "Completude. Força até o fim." },
    { id: "pre290", tipo: "salmo", texto: "O Senhor te livrará.", referencia: "Salmos 91:14", resumo: "Livramento. Força da promessa." },
    { id: "pre291", tipo: "versiculo", texto: "Nele fostes selados.", referencia: "Efésios 1:13", resumo: "Selo. Força na marca." },
    { id: "pre292", tipo: "salmo", texto: "O Senhor te preservará.", referencia: "Salmos 121:7", resumo: "Preservação. Força de proteção." },
    { id: "pre293", tipo: "versiculo", texto: "Sabemos que todas as coisas cooperam.", referencia: "Romanos 8:28", resumo: "Cooperação. Força do propósito." },
    { id: "pre294", tipo: "salmo", texto: "O Senhor te sustenta.", referencia: "Salmos 3:5", resumo: "Sustento. Força invisível." },
    { id: "pre295", tipo: "versiculo", texto: "O nosso Senhor é a nossa esperança.", referencia: "1 Timóteo 1:1", resumo: "Esperança pessoal. Força fonte." },
    { id: "pre296", tipo: "salmo", texto: "O Senhor guarda os fiéis.", referencia: "Salmos 31:23", resumo: "Guarda dos fiéis. Força seletiva." },
    { id: "pre297", tipo: "versiculo", texto: "Bendito seja Deus.", referencia: "Efésios 1:3", resumo: "Bênção. Força no louvor." },
    { id: "pre298", tipo: "salmo", texto: "O Senhor é a minha porção.", referencia: "Salmos 73:26", resumo: "Porção. Força na suficiência." },
    { id: "pre299", tipo: "versiculo", texto: "Deus da esperança vos encha.", referencia: "Romanos 15:13", resumo: "Enchimento. Força cheia." },
    { id: "pre300", tipo: "salmo", texto: "Feliz aquele cuja força está em ti.", referencia: "Salmos 84:5", resumo: "Força em Deus. Bem-aventurança." },
    { id: "pre301", tipo: "versiculo", texto: "Cristo é nossa vida.", referencia: "Colossenses 3:4", resumo: "Vida em Cristo. Força vital." },
    { id: "pre302", tipo: "salmo", texto: "O Senhor é fiel.", referencia: "Salmos 145:13", resumo: "Fidelidade. Força constante." },
    { id: "pre303", tipo: "versiculo", texto: "O Senhor guarda os simples.", referencia: "Salmos 116:6", resumo: "Guarda especial. Força para os frágeis." },
    { id: "pre304", tipo: "versiculo", texto: "Todo aquele que Nele crê.", referencia: "Romanos 10:11", resumo: "Fé sem confusão. Força da certeza." },
    { id: "pre305", tipo: "salmo", texto: "O Senhor é o meu Salvador.", referencia: "Miqueias 7:7", resumo: "Salvação. Força da intervenção." },
    { id: "pre306", tipo: "versiculo", texto: "Sabemos que amamos porque ele primeiro.", referencia: "1 João 4:19", resumo: "Amor original. Força da resposta." },
    { id: "pre307", tipo: "salmo", texto: "O Senhor te sustente.", referencia: "Salmos 55:22", resumo: "Sustento. Força ao entregue." },
    { id: "pre308", tipo: "versiculo", texto: "Onde há o Espírito, há liberdade.", referencia: "2 Coríntios 3:17", resumo: "Espírito e liberdade. Força libertada." },
    { id: "pre309", tipo: "salmo", texto: "O Senhor guarda a tua alma.", referencia: "Salmos 121:7", resumo: "Guarda íntima. Força interior." },
    { id: "pre310", tipo: "versiculo", texto: "O Deus da paz vos aperfeiçoe.", referencia: "Hebreus 13:20-21", resumo: "Aperfeiçoamento. Força na maturidade." },
    { id: "pre311", tipo: "salmo", texto: "O Senhor é a minha rocha.", referencia: "Salmos 18:2", resumo: "Rocha. Força estável." },
    { id: "pre312", tipo: "versiculo", texto: "Cristo em nós.", referencia: "Colossenses 1:27", resumo: "Habitação. Força interior." },
    { id: "pre313", tipo: "salmo", texto: "O Senhor é bom.", referencia: "Salmos 100:5", resumo: "Bondade. Força na natureza." },
    { id: "pre314", tipo: "versiculo", texto: "O Senhor pelejará.", referencia: "Êxodo 14:14", resumo: "Guerra divina. Força aliada." },
    { id: "pre315", tipo: "salmo", texto: "O Senhor te ajudará.", referencia: "Salmos 46:5", resumo: "Ajuda. Força no socorro." },
    { id: "pre316", tipo: "versiculo", texto: "Fostes chamados à liberdade.", referencia: "Gálatas 5:13", resumo: "Liberdade. Força soltar-se." },
    { id: "pre317", tipo: "salmo", texto: "O Senhor te abençoe.", referencia: "Números 6:24", resumo: "Bênção. Força coberta." },
    { id: "pre318", tipo: "versiculo", texto: "Deus é fiel.", referencia: "1 Tessalonicenses 5:24", resumo: "Fidelidade. Força constante." },
    { id: "pre319", tipo: "salmo", texto: "O Senhor está no meio.", referencia: "Salmos 46:5", resumo: "Presença central. Força ao redor." },
    { id: "pre320", tipo: "versiculo", texto: "Deus não nos deu espírito de covardia, mas de poder.", referencia: "2 Timóteo 1:7", resumo: "Poder herdado. Força padrão." },
    { id: "pre321", tipo: "salmo", texto: "O Senhor te guardará.", referencia: "Salmos 121:7", resumo: "Guarda. Força cobertura." },
    { id: "pre322", tipo: "versiculo", texto: "Cristo é nossa paz.", referencia: "Efésios 2:14", resumo: "Cristo paz. Força pacífica." },
    { id: "pre323", tipo: "salmo", texto: "O Senhor te sustenta a mão.", referencia: "Salmos 63:8", resumo: "Mão sustentada. Força tangível." },
    { id: "pre324", tipo: "versiculo", texto: "Todo aquele que crê.", referencia: "João 3:16", resumo: "Fé simples. Força na simplicidade." },
    { id: "pre325", tipo: "salmo", texto: "O Senhor guarda a vida.", referencia: "Salmos 121:7", resumo: "Guarda vital. Força de vida." },
    { id: "pre326", tipo: "versiculo", texto: "Cristo é o poder de Deus.", referencia: "1 Coríntios 1:24", resumo: "Cristo é poder. Força pessoal." },
    { id: "pre327", tipo: "salmo", texto: "O Senhor é justo.", referencia: "Salmos 145:17", resumo: "Justiça. Força da retidão." },
    { id: "pre328", tipo: "versiculo", texto: "O Senhor é o meu ajudador.", referencia: "Hebreus 13:6", resumo: "Ajuda. Força na parceria." },
    { id: "pre329", tipo: "salmo", texto: "O Senhor é a força da minha vida.", referencia: "Salmos 27:1", resumo: "Força vital. Fonte identificada." },
    { id: "pre330", tipo: "versiculo", texto: "Estamos convosco todos os dias.", referencia: "Mateus 28:20", resumo: "Companhia. Força diária." },
  ],
  "Motivação": [
    { id: "mot1", tipo: "reflexao", texto: "Comece onde você está. Use o que você tem. Faça o que você pode.", referencia: "Arthur Ashe", resumo: "Não espere o cenário perfeito. O movimento, mesmo pequeno, já é o início do caminho. A clareza vem com a ação, não antes dela." },
    { id: "mot2", tipo: "reflexao", texto: "O futuro pertence àqueles que acreditam na beleza dos seus sonhos.", referencia: "Eleanor Roosevelt", resumo: "Sonhar grande não é fuga — é coragem. Quem acredita no próprio sonho constrói pontes que os céticos nem enxergam." },
    { id: "mot3", tipo: "reflexao", texto: "Não é a montanha que conquistamos, mas a nós mesmos.", referencia: "Edmund Hillary", resumo: "Cada desafio externo é, no fundo, um espelho do interior. O que você supera fora de você forma quem você é por dentro." },
    { id: "mot4", tipo: "reflexao", texto: "A persistência realiza o impossível.", referencia: "Provérbio chinês", resumo: "Talento abre portas, persistência mantém você dentro. Quem volta uma vez a mais do que cai sempre chega." },
    { id: "mot5", tipo: "reflexao", texto: "Você é mais forte do que pensa, mais corajoso do que acredita e mais capaz do que imagina.", referencia: "Motivação", resumo: "A força real só se revela quando é exigida. Não duvide do seu tamanho antes de testá-lo no momento certo." },
    { id: "mot6", tipo: "reflexao", texto: "A jornada de mil milhas começa com um único passo.", referencia: "Lao-Tsé", resumo: "Não foque na distância — foque no próximo passo. Um por vez, todos os dias, e o caminho se desenha sozinho." },
    { id: "mot7", tipo: "reflexao", texto: "Não pare quando estiver cansado. Pare quando tiver terminado.", referencia: "Motivação", resumo: "O cansaço é sinal de progresso, não de fim. O fim chega quando o objetivo é alcançado, não quando o corpo reclama." },
    { id: "mot8", tipo: "reflexao", texto: "Acredite que você pode, e você já estará no meio do caminho.", referencia: "Theodore Roosevelt", resumo: "Crença não realiza sozinha, mas sem ela nada começa. Acreditar é o primeiro ato concreto rumo à realização." },
    { id: "mot9", tipo: "reflexao", texto: "Sua única limitação é você mesmo.", referencia: "Motivação", resumo: "As maiores paredes da vida são as que construímos por dentro. Derrubá-las é o primeiro projeto de qualquer conquista." },
    { id: "mot10", tipo: "reflexao", texto: "A diferença entre o possível e o impossível está na determinação de cada um.", referencia: "Tommy Lasorda", resumo: "Possibilidade não é dada — é arrancada. A determinação transforma o 'não dá' em 'eu vou'." },
    { id: "mot11", tipo: "reflexao", texto: "Tudo o que você sempre quis está do outro lado do medo.", referencia: "George Addair", resumo: "O medo guarda a porta dos seus melhores capítulos. Atravesse a porta — quase nunca é tão grande do outro lado." },
    { id: "mot12", tipo: "reflexao", texto: "Não conte os dias, faça os dias contarem.", referencia: "Muhammad Ali", resumo: "Tempo não se acumula — se gasta. Faça cada hora valer algo que você possa lembrar com orgulho amanhã." },
    { id: "mot13", tipo: "reflexao", texto: "O sucesso é a soma de pequenos esforços repetidos dia após dia.", referencia: "Robert Collier", resumo: "Ninguém vence em um único dia. Vence quem aparece todos os dias, mesmo quando ninguém vê." },
    { id: "mot14", tipo: "reflexao", texto: "Não tenha medo de desistir do bom para perseguir o ótimo.", referencia: "John D. Rockefeller", resumo: "Aceitar o bom às vezes é o maior obstáculo ao ótimo. Largue o suficiente quando o extraordinário é possível." },
    { id: "mot15", tipo: "reflexao", texto: "Cada dia é uma nova chance de mudar sua vida.", referencia: "Motivação", resumo: "Independente do que ontem trouxe, hoje começa em branco. Você não precisa esperar segunda, janeiro ou aniversário — basta agora." },
    { id: "mot16", tipo: "reflexao", texto: "Disciplina é a ponte entre objetivos e realizações.", referencia: "Jim Rohn", resumo: "Motivação começa o trabalho, disciplina o termina. Cultive hábitos que sustentam quando a inspiração vai embora." },
    { id: "mot17", tipo: "reflexao", texto: "Não pare. Cada passo te aproxima de onde você precisa estar.", referencia: "Motivação", resumo: "Mesmo o passo pequeno reduz a distância. Continuar é mais decisivo que correr." },
    { id: "mot18", tipo: "reflexao", texto: "Você não falha até parar de tentar.", referencia: "Albert Einstein", resumo: "A queda só vira fracasso quando você decide ficar caído. Levantar-se uma vez a mais já reescreve a história." },
    { id: "mot19", tipo: "reflexao", texto: "Grandes coisas nunca vêm de zonas de conforto.", referencia: "Motivação", resumo: "O conforto é gostoso, mas estéril. O que faz crescer mora um passo além do que você já conhece." },
    { id: "mot20", tipo: "reflexao", texto: "Sonhe grande e ouse falhar.", referencia: "Norman Vaughan", resumo: "Falhar tentando algo grande ensina mais do que vencer em algo pequeno. A ousadia é o solo de qualquer feito notável." },
    { id: "mot21", tipo: "reflexao", texto: "O segredo para seguir em frente é começar.", referencia: "Mark Twain", resumo: "Não existe momento perfeito. Existe momento começado. Comece imperfeito — ajuste no caminho." },
    { id: "mot22", tipo: "reflexao", texto: "Sua vida não melhora por acaso, ela melhora por mudança.", referencia: "Jim Rohn", resumo: "Esperar que melhore sozinho é desperdiçar tempo. Mude algo hoje — pequeno, mas concreto." },
    { id: "mot23", tipo: "reflexao", texto: "A melhor maneira de prever o futuro é criá-lo.", referencia: "Peter Drucker", resumo: "Você não precisa adivinhar o que vem — você pode construir. Cada escolha de hoje é um tijolo do amanhã." },
    { id: "mot24", tipo: "reflexao", texto: "Não importa o quão devagar você vá, desde que você não pare.", referencia: "Confúcio", resumo: "Velocidade é menos importante que direção e constância. Devagar e sempre vence o rápido que desiste." },
    { id: "mot25", tipo: "reflexao", texto: "Coragem não é a ausência de medo, mas a decisão de seguir apesar dele.", referencia: "Nelson Mandela", resumo: "Sentir medo é humano. Avançar com ele do lado é coragem. Você não precisa esperar o medo passar para agir." },
    { id: "mot26", tipo: "reflexao", texto: "Você é o autor da sua própria história.", referencia: "Motivação", resumo: "Outros podem opinar, mas a caneta está na sua mão. Escreva capítulos que valham a pena reler." },
    { id: "mot27", tipo: "reflexao", texto: "Tudo parece impossível até que seja feito.", referencia: "Nelson Mandela", resumo: "O impossível é uma categoria temporária. Alguém sempre é o primeiro a provar o contrário — pode ser você." },
    { id: "mot28", tipo: "reflexao", texto: "Pequenos progressos diários levam a grandes resultados.", referencia: "Satya Nani", resumo: "Não menospreze o 1% de hoje. Multiplicado por 365, ele muda tudo. Constância é a fórmula secreta." },
    { id: "mot29", tipo: "reflexao", texto: "A força não vem da capacidade física, mas da vontade indomável.", referencia: "Mahatma Gandhi", resumo: "Músculos cansam, vontade decidida não. A força que sustenta nasce dentro, não fora." },
    { id: "mot30", tipo: "reflexao", texto: "Faça hoje o que os outros não querem, viva amanhã como os outros não podem.", referencia: "Jerry Rice", resumo: "Resultado extraordinário exige esforço fora do padrão. O preço é pago antes — o prêmio chega depois." },
    { id: "mot31", tipo: "reflexao", texto: "Você não precisa ser perfeito, só precisa começar.", referencia: "Motivação", resumo: "Perfeccionismo paralisa, ação liberta. Comece imperfeito, melhore enquanto faz." },
    { id: "mot32", tipo: "reflexao", texto: "O único limite para o seu sucesso é a sua imaginação.", referencia: "Motivação", resumo: "Antes da realidade existir, ela é imaginada. Amplie o que você imagina e o possível se amplia junto." },
    { id: "mot33", tipo: "reflexao", texto: "Quem nunca errou, nunca tentou nada de novo.", referencia: "Albert Einstein", resumo: "Errar é prova de movimento. O erro é dado, não tragédia — aprenda e siga." },
    { id: "mot34", tipo: "reflexao", texto: "Acredite em si mesmo e tudo será possível.", referencia: "Motivação", resumo: "Autoconfiança é o motor escondido por trás de toda realização. Comece nutrindo quem você é antes de cobrar o que faz." },
    { id: "mot35", tipo: "reflexao", texto: "A vida é 10% o que acontece com você e 90% como você reage.", referencia: "Charles R. Swindoll", resumo: "Você raramente escolhe os fatos, mas sempre escolhe a resposta. A liberdade mora aí." },
    { id: "mot36", tipo: "reflexao", texto: "Não desista. O começo é sempre o mais difícil.", referencia: "Motivação", resumo: "O início drena energia porque tudo é novo. Resista esses primeiros dias — depois o caminho fica mais leve." },
    { id: "mot37", tipo: "reflexao", texto: "A motivação te tira da cama. O hábito te leva até o fim.", referencia: "Motivação", resumo: "Não dependa de sentir vontade — construa um sistema. Hábitos são motivação congelada em forma de ação." },
    { id: "mot38", tipo: "reflexao", texto: "Não espere por oportunidade. Crie-a.", referencia: "George Bernard Shaw", resumo: "Esperar é caro. Quem cria oportunidade tem dez vezes mais portas para escolher." },
    { id: "mot39", tipo: "reflexao", texto: "O que você faz hoje pode melhorar todos os seus amanhãs.", referencia: "Ralph Marston", resumo: "Cada ação de hoje é um depósito no banco do futuro. Pequenos depósitos, juros compostos." },
    { id: "mot40", tipo: "reflexao", texto: "Não compare o seu capítulo 1 com o capítulo 20 dos outros.", referencia: "Motivação", resumo: "Você está apenas no início. Comparar fases diferentes da jornada é injusto consigo mesmo. Foque no seu próximo capítulo." },
    { id: "mot41", tipo: "reflexao", texto: "Foco. Disciplina. Consistência. Esses três vencem o talento sozinho.", referencia: "Motivação", resumo: "Talento abre janelas, mas é a disciplina constante que constrói catedrais. Aposte nos três que dependem só de você." },
    { id: "mot42", tipo: "reflexao", texto: "Você só precisa de coragem para começar e fé para continuar.", referencia: "Motivação", resumo: "Coragem inicia, fé sustenta. Entre esses dois ingredientes, qualquer projeto chega ao fim." },
    { id: "mot43", tipo: "reflexao", texto: "Hoje é o dia perfeito para começar de novo.", referencia: "Motivação", resumo: "Não importa há quantos dias você caiu — o reinício está disponível agora. Não desperdice mais um dia esperando." },
    { id: "mot44", tipo: "reflexao", texto: "Trabalhe duro em silêncio. Deixe seu sucesso fazer o barulho.", referencia: "Frank Ocean", resumo: "Resultado fala mais alto que promessa. Construa quietude no esforço e deixe o barulho para a conquista." },
    { id: "mot45", tipo: "reflexao", texto: "Se você não construir o seu sonho, alguém vai te contratar para construir o dele.", referencia: "Tony Gaskins", resumo: "Tempo e energia são finitos. Use os seus primeiro no que você sonha — depois sobra para os outros." },
    { id: "mot46", tipo: "reflexao", texto: "Não tenha pressa, mas não pare.", referencia: "Motivação", resumo: "Pressa estraga a qualidade; parar mata o progresso. Caminhar firme é o ponto de equilíbrio." },
    { id: "mot47", tipo: "reflexao", texto: "Cada manhã é uma nova página em branco. Escreva algo bonito.", referencia: "Motivação", resumo: "Você não controla tudo, mas controla o tom com que abre o dia. Escolha começar bonito — o resto se ajeita." },
    { id: "mot48", tipo: "reflexao", texto: "Os obstáculos são aquelas coisas assustadoras que você vê quando tira os olhos do seu objetivo.", referencia: "Henry Ford", resumo: "Foco encolhe obstáculos. Quanto mais você olha para o destino, menores eles parecem." },
    { id: "mot49", tipo: "reflexao", texto: "Acredite em você quando ninguém mais acreditar.", referencia: "Motivação", resumo: "Antes que o mundo aposte em você, você precisa apostar primeiro. Sua fé própria é a única indispensável." },
    { id: "mot50", tipo: "reflexao", texto: "Sucesso é cair sete vezes e levantar oito.", referencia: "Provérbio japonês", resumo: "Vencer é, no fim, uma matemática simples: levantar sempre mais uma vez do que caiu. Conte os levantares — não as quedas." },
    { id: "mot51", tipo: "reflexao", texto: "Não tenha medo de recomeçar. Desta vez você não começa do zero, começa da experiência.", referencia: "Motivação", resumo: "Recomeçar não é apagar — é continuar com mais sabedoria. Tudo que você aprendeu vai junto." },
    { id: "mot52", tipo: "reflexao", texto: "A coragem é o primeiro passo. Tudo o mais é apenas tenacidade.", referencia: "Amelia Earhart", resumo: "Decidir é o ato mais raro. Depois disso, basta não soltar. A tenacidade é menos heroica do que parece — é só não desistir." },
    { id: "mot53", tipo: "reflexao", texto: "Você cresce no momento em que escolhe ir além do conforto.", referencia: "Motivação", resumo: "Crescimento é desconfortável por definição. Aceite o desconforto como sinal de que está acontecendo algo importante." },
    { id: "mot54", tipo: "reflexao", texto: "Não conte para as pessoas seus planos. Mostre seus resultados.", referencia: "Motivação", resumo: "Energia gasta convencendo é energia que poderia construir. Trabalhe no silêncio e deixe a evidência falar." },
    { id: "mot55", tipo: "reflexao", texto: "A maneira de começar é parar de falar e começar a fazer.", referencia: "Walt Disney", resumo: "Quanto mais tempo no planejamento, menos tempo no resultado. Em algum ponto, troque palavras por ações." },
    { id: "mot56", tipo: "reflexao", texto: "Tudo o que você precisa já está dentro de você. Comece agora.", referencia: "Motivação", resumo: "Você não precisa de mais cursos, mais idade ou mais sinais. O essencial você já tem. Use." },
    { id: "mot57", tipo: "reflexao", texto: "A pressão transforma carvão em diamante. Não tema o aperto.", referencia: "Motivação", resumo: "Os momentos mais difíceis são, muitas vezes, os mais formativos. O que aperta também molda." },
    { id: "mot58", tipo: "reflexao", texto: "Quem quer vencer encontra um caminho. Quem não quer encontra uma desculpa.", referencia: "Jim Rohn", resumo: "A diferença entre vencer e desistir muitas vezes não é talento — é a recusa de aceitar desculpas." },
    { id: "mot59", tipo: "reflexao", texto: "Não desista nunca. Nunca, nunca, nunca.", referencia: "Winston Churchill", resumo: "Em meio à guerra mais dura, Churchill resumiu a vitória em três palavras. Desistir é a única forma garantida de perder." },
    { id: "mot60", tipo: "reflexao", texto: "Levante-se. Recomece. Você é capaz.", referencia: "Motivação", resumo: "Não importa quantas vezes a vida te derrubou — a próxima cena depende de você se erguer. Você foi feito para mais." },
    { id: "mot61", tipo: "reflexao", texto: "Não tenha medo de ser iniciante. Todo mestre já foi um.", referencia: "Motivação", resumo: "Toda excelência começa desajeitada. Permita-se ser ruim no começo — é o pedágio do domínio." },
    { id: "mot62", tipo: "reflexao", texto: "Faça com medo, mas faça.", referencia: "Motivação", resumo: "Esperar o medo passar é esperar para sempre. Aja com ele do lado — a coragem se constrói no movimento." },
    { id: "mot63", tipo: "reflexao", texto: "Seu maior concorrente é quem você foi ontem.", referencia: "Motivação", resumo: "Comparar-se com os outros é distração. A única medida útil é o seu progresso desde o último ciclo." },
    { id: "mot64", tipo: "reflexao", texto: "A vida recompensa quem age, não quem planeja para sempre.", referencia: "Motivação", resumo: "Plano sem execução é fantasia. Em algum ponto, troque o caderno pela rua." },
    { id: "mot65", tipo: "reflexao", texto: "Você não precisa ver toda a escada. Apenas suba o primeiro degrau.", referencia: "Martin Luther King Jr.", resumo: "A clareza completa raramente vem antes de começar. Confie no próximo passo — o resto se revela." },
    { id: "mot66", tipo: "reflexao", texto: "Energia segue foco. Onde você olha, sua vida cresce.", referencia: "Motivação", resumo: "Aquilo em que você presta atenção, se expande. Escolha o foco com cuidado — ele desenha o futuro." },
    { id: "mot67", tipo: "reflexao", texto: "O ‘não’ que você teme já é o resultado de não tentar.", referencia: "Motivação", resumo: "Quando você não pede, a resposta já é não. Tentar só pode melhorar a estatística." },
    { id: "mot68", tipo: "reflexao", texto: "Pequenos hábitos, repetidos, viram destino.", referencia: "Motivação", resumo: "O que você faz todos os dias importa mais do que o que você faz de vez em quando. Hábito é destino em câmera lenta." },
    { id: "mot69", tipo: "reflexao", texto: "Não troque o que você mais quer pelo que você quer agora.", referencia: "Zig Ziglar", resumo: "O impulso curto sabota o objetivo longo. Lembre-se do destino antes de ceder ao desvio." },
    { id: "mot70", tipo: "reflexao", texto: "Sua zona de conforto é uma prisão bonita.", referencia: "Motivação", resumo: "O conforto seduz, mas estagna. Saia antes que ele te convença de que ali é o lugar." },
    { id: "mot71", tipo: "reflexao", texto: "Não é o tempo que muda as pessoas. São as decisões.", referencia: "Motivação", resumo: "Esperar o tempo agir é desperdício. Quem decide muda agora — o tempo só registra." },
    { id: "mot72", tipo: "reflexao", texto: "Quem foca no problema, vê obstáculos. Quem foca na solução, vê caminhos.", referencia: "Motivação", resumo: "Sua pergunta determina sua resposta. Mude o foco — mude o que aparece." },
    { id: "mot73", tipo: "reflexao", texto: "Seja a pessoa que você precisava quando era mais novo.", referencia: "Ayesha Siddiqi", resumo: "Tornar-se essa pessoa cura você duas vezes — no presente e retroativamente. É serviço e libertação ao mesmo tempo." },
    { id: "mot74", tipo: "reflexao", texto: "Não tenha pressa de chegar. Tenha pressa de começar.", referencia: "Motivação", resumo: "O começo é o único momento totalmente sob seu controle. Adie a ansiedade do destino — apresse o primeiro passo." },
    { id: "mot75", tipo: "reflexao", texto: "Seu potencial é maior que sua história até aqui.", referencia: "Motivação", resumo: "O passado é dado, o futuro é desenho. Não permita que o que já aconteceu defina o que ainda pode acontecer." },
    { id: "mot76", tipo: "reflexao", texto: "Faça uma coisa todo dia que te assuste um pouco.", referencia: "Eleanor Roosevelt", resumo: "Crescer dói. Doses diárias de coragem expandem a sua capacidade aos poucos, sem trauma." },
    { id: "mot77", tipo: "reflexao", texto: "A disciplina é escolher entre o que você quer agora e o que você quer mais.", referencia: "Augusta F. Kantra", resumo: "Toda escolha grande passa por essa pergunta. Saber a resposta antes do impulso é metade da vitória." },
    { id: "mot78", tipo: "reflexao", texto: "Não compare seu progresso com o de ninguém. Sua corrida é só sua.", referencia: "Motivação", resumo: "Pistas diferentes, larguras diferentes, ventos diferentes. Compare-se apenas com quem você era ontem." },
    { id: "mot79", tipo: "reflexao", texto: "Cada ‘não’ te aproxima do próximo ‘sim’.", referencia: "Motivação", resumo: "Negativas são estatística — quanto mais você pede, mais ‘sim’ aparece. Não pare na primeira porta fechada." },
    { id: "mot80", tipo: "reflexao", texto: "Você não precisa estar pronto. Precisa estar disposto.", referencia: "Motivação", resumo: "‘Pronto’ é um estado que quase nunca chega. ‘Disposto’ é uma decisão disponível agora." },
    { id: "mot81", tipo: "reflexao", texto: "Não desista nos dias difíceis. É justamente neles que se decide tudo.", referencia: "Motivação", resumo: "Dia bom todo mundo aguenta. O que separa quem chega de quem para é o comportamento nos dias ruins." },
    { id: "mot82", tipo: "reflexao", texto: "Aprenda a amar o processo. O resultado é só a sobra.", referencia: "Motivação", resumo: "Quem só ama o pódio sofre o caminho inteiro. Quem ama o processo já está sendo recompensado." },
    { id: "mot83", tipo: "reflexao", texto: "Você se torna aquilo em que pensa o dia inteiro.", referencia: "Ralph Waldo Emerson", resumo: "Pensamento é semente. Cuide do que planta na cabeça — sua vida vai colher exatamente isso." },
    { id: "mot84", tipo: "reflexao", texto: "Não terceirize seu valor para a opinião dos outros.", referencia: "Motivação", resumo: "Quem te aplaude hoje pode te criticar amanhã. Ancore seu valor em algo que não muda com o vento." },
    { id: "mot85", tipo: "reflexao", texto: "O preço da grandeza é a responsabilidade.", referencia: "Winston Churchill", resumo: "Querer mais exige carregar mais. Aceitar a conta é o que separa quem sonha de quem realiza." },
    { id: "mot86", tipo: "reflexao", texto: "Faça hoje algo de que seu eu de dez anos atrás se orgulharia.", referencia: "Motivação", resumo: "Sua versão antiga sonhava com esta vida. Honre esse menino ou menina com uma ação concreta agora." },
    { id: "mot87", tipo: "reflexao", texto: "Você não precisa de mais tempo. Precisa de prioridade.", referencia: "Motivação", resumo: "Todos têm 24 horas. A diferença é onde cada um as gasta. Reordene — não acumule." },
    { id: "mot88", tipo: "reflexao", texto: "O que parece sacrifício hoje é liberdade amanhã.", referencia: "Motivação", resumo: "Disciplina parece cara no presente e barata no futuro. Pague agora — colha leveza depois." },
    { id: "mot89", tipo: "reflexao", texto: "Plante hoje a árvore sob a qual você gostaria de descansar amanhã.", referencia: "Provérbio", resumo: "Toda colheita exige antecipação. O melhor momento para plantar foi há 20 anos. O segundo melhor é hoje." },
    { id: "mot90", tipo: "reflexao", texto: "Não se desculpe por sonhar grande.", referencia: "Motivação", resumo: "Sonho grande incomoda quem desistiu do próprio. Não encolha — siga e deixe sua vida ser o argumento." },
    { id: "mot91", tipo: "reflexao", texto: "Quem ama o que faz, nunca trabalha um dia sequer.", referencia: "Confúcio", resumo: "Vocação transforma esforço em entrega. Procure o que pesa menos mesmo sendo difícil — ali está sua veia." },
    { id: "mot92", tipo: "reflexao", texto: "A vida começa onde sua coragem termina o medo.", referencia: "Motivação", resumo: "Os melhores capítulos moram um centímetro além do que assusta. Avance esse centímetro." },
    { id: "mot93", tipo: "reflexao", texto: "Não pare na primeira tentativa. Quase ninguém acerta de primeira.", referencia: "Motivação", resumo: "Domínio é repetição inteligente. A primeira tentativa quase nunca conta — ela calibra." },
    { id: "mot94", tipo: "reflexao", texto: "Mude o que pode ser mudado. Aceite o que não pode. Saiba a diferença.", referencia: "Reinhold Niebuhr", resumo: "Energia bem distribuída é o segredo da paz produtiva. Brigar com o imutável só esgota." },
    { id: "mot95", tipo: "reflexao", texto: "Persista. O que parece longe hoje, amanhã será o ponto de partida.", referencia: "Motivação", resumo: "Distâncias encolhem quando você continua andando. A persistência reorganiza o mapa." },
    { id: "mot96", tipo: "reflexao", texto: "O sucesso não é final, o fracasso não é fatal. O que conta é a coragem de continuar.", referencia: "Winston Churchill", resumo: "Nem o topo é permanente, nem o fundo é definitivo. A coragem é o único elemento constante." },
    { id: "mot97", tipo: "reflexao", texto: "Você não foi feito para caber. Foi feito para crescer.", referencia: "Motivação", resumo: "Forçar-se a caber em espaços pequenos sufoca. Cresça — e os ambientes certos vão aparecer." },
    { id: "mot98", tipo: "reflexao", texto: "A consistência derrota o talento que não aparece.", referencia: "Motivação", resumo: "Talento que falta no dia ruim não vence. Quem aparece todo dia, mesmo médio, supera o gênio inconstante." },
    { id: "mot99", tipo: "reflexao", texto: "Sua mente é seu maior aliado ou seu pior inimigo. Você decide.", referencia: "Motivação", resumo: "A voz interna pode te empurrar ou te paralisar. Treine-a como se treina um músculo." },
    { id: "mot100", tipo: "reflexao", texto: "Não compare seus bastidores com o palco dos outros.", referencia: "Motivação", resumo: "Você vê o resultado deles e a luta sua. É comparação injusta. Compare palco com palco — ou nada com nada." },
    { id: "mot101", tipo: "reflexao", texto: "O que você não desafia, você não muda.", referencia: "Motivação", resumo: "Aceitar passivamente é manter. Mudar exige confronto — com situações, hábitos ou crenças." },
    { id: "mot102", tipo: "reflexao", texto: "A jornada de longa distância é vencida em passos curtos repetidos.", referencia: "Motivação", resumo: "Ninguém atravessa um continente em um pulo. Mas atravessa com passos curtos e constantes." },
    { id: "mot103", tipo: "reflexao", texto: "Não tenha medo de recomeçar quantas vezes for preciso.", referencia: "Motivação", resumo: "Recomeçar não é fracasso — é evidência de quem não desiste. Quem recomeça já está vencendo." },
    { id: "mot104", tipo: "reflexao", texto: "Faça o trabalho que ninguém viu. O resultado todos vão ver.", referencia: "Motivação", resumo: "A excelência se constrói no escuro. Quando a luz chega, ela só revela o que já estava pronto." },
    { id: "mot105", tipo: "reflexao", texto: "Você está mais perto do que pensa. Não pare agora.", referencia: "Motivação", resumo: "A vontade de desistir geralmente aparece pouco antes do avanço. Aguente mais um pouco." },
    { id: "mot106", tipo: "reflexao", texto: "Cada falha é dado, não veredito.", referencia: "Motivação", resumo: "Falhar te informa, não te define. Use o dado para ajustar e siga." },
    { id: "mot107", tipo: "reflexao", texto: "Não corra atrás do reconhecimento. Corra atrás de fazer bem feito.", referencia: "Motivação", resumo: "Reconhecimento é consequência, não objetivo. Quem persegue o trabalho bem feito recebe os dois." },
    { id: "mot108", tipo: "reflexao", texto: "Quem espera condição perfeita, nunca começa.", referencia: "Motivação", resumo: "Condições perfeitas são lenda. Comece com o que tem — o resto se ajeita andando." },
    { id: "mot109", tipo: "reflexao", texto: "A vida não é sobre encontrar a si mesmo. É sobre criar a si mesmo.", referencia: "George Bernard Shaw", resumo: "Você não é uma pedra a ser descoberta — é escultura em andamento. Cada escolha esculpe." },
    { id: "mot110", tipo: "reflexao", texto: "Comece pequeno. Comece feio. Comece com medo. Mas comece.", referencia: "Motivação", resumo: "O começo nunca será cinematográfico. O importante é que aconteça — o brilho vem depois." },
  ],
};

// Sistema de Cache Local Requisitado
interface Cache {
  lastMessages: string[];
  lastType: TipoMensagem | null;
}

// O cache deve ser resetado ao fechar/abrir o app (instância em memória)
const cache: Cache = {
  lastMessages: [],
  lastType: null,
};

export function getRandomIdForCategoria(categoria: Categoria): string {
  const todas = MENSAGENS[categoria];

  // 1. Remover mensagens exibidas nas últimas interações (cache local)
  let filtradas = todas.filter(m => !cache.lastMessages.includes(m.id));

  if (filtradas.length === 0) {
    cache.lastMessages = [];
    filtradas = todas;
  }

  // 2. Garantir que não apareça o mesmo tipo duas vezes seguidas
  let finalistas = filtradas.filter(m => m.tipo !== cache.lastType);

  if (finalistas.length === 0) {
    finalistas = filtradas;
  }

  // 3. Selecionar aleatoriamente
  const selecionada = finalistas[Math.floor(Math.random() * finalistas.length)];

  // Atualizar cache
  cache.lastMessages = [...cache.lastMessages, selecionada.id].slice(-25);
  cache.lastType = selecionada.tipo;

  return selecionada.id;
}

export function getMensagemById(categoria: Categoria, id: string): Mensagem {
  const todas = MENSAGENS[categoria];
  return todas.find(m => m.id === id) || todas[0];
}

export function getProximaMensagem(categoria: Categoria): Mensagem {
  const id = getRandomIdForCategoria(categoria);
  return getMensagemById(categoria, id);
}

export function getRandomMensagemGlobal(): { categoria: Categoria; id: string } {
  const categoria = CATEGORIAS[Math.floor(Math.random() * CATEGORIAS.length)];
  const id = getRandomIdForCategoria(categoria);
  return { categoria, id };
}
